{
  "name": "DamDam Laundry Payroll System",
  "description": "A comprehensive payroll and attendance management system for DamDam Laundry with geofencing capabilities and weekly salary calculations.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export enum UserRole {
  OWNER = 'OWNER',
  EMPLOYEE = 'EMPLOYEE'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  gapok: number; // Monthly basic salary
  uangMakan: number; // Monthly meal allowance
}

export interface AttendanceRecord {
  id: string;
  userId: string;
  date: string; // YYYY-MM-DD
  clockIn: string | null;
  clockOut: string | null;
  latitude: number;
  longitude: number;
  status: 'PRESENT' | 'LEAVE' | 'ABSENT';
}

export interface LeaveRequest {
  id: string;
  userId: string;
  date: string;
  reason: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
}

export interface OutletConfig {
  latitude: number;
  longitude: number;
  radius: number; // In meters
}

export interface PayrollReport {
  userId: string;
  userName: string;
  weekStartDate: string;
  weekEndDate: string;
  totalPresent: number;
  totalLeave: number;
  excessLeaveCount: number;
  grossSalary: number;
  deductions: number;
  netSalary: number;
}

import { User, UserRole, OutletConfig } from './types';

export const INITIAL_OUTLET_CONFIG: OutletConfig = {
  latitude: -6.200000, // Example Jakarta coordinates
  longitude: 106.816666,
  radius: 100, // 100 meters
};

export const MOCK_USERS: User[] = [
  { id: '1', name: 'Owner DamDam', role: UserRole.OWNER, gapok: 0, uangMakan: 0 },
  { id: '2', name: 'Budi Laundry', role: UserRole.EMPLOYEE, gapok: 3000000, uangMakan: 500000 },
  { id: '3', name: 'Siti Clean', role: UserRole.EMPLOYEE, gapok: 3200000, uangMakan: 600000 },
];

export const DAYS_IN_MONTH = 30; // Static for payroll calc as per requirement
export const FREE_LEAVE_QUOTA = 3;

export const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number): number => {
  const R = 6371e3; // Earth radius in meters
  const φ1 = (lat1 * Math.PI) / 180;
  const φ2 = (lat2 * Math.PI) / 180;
  const Δφ = ((lat2 - lat1) * Math.PI) / 180;
  const Δλ = ((lon2 - lon1) * Math.PI) / 180;

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return R * c; // Distance in meters
};

export const getCurrentPosition = (): Promise<GeolocationPosition> => {
  return new Promise((resolve, reject) => {
    if (!navigator.geolocation) {
      reject(new Error("Geolocation not supported"));
    }
    navigator.geolocation.getCurrentPosition(resolve, reject, {
      enableHighAccuracy: true,
      timeout: 10000,
      maximumAge: 0
    });
  });
};

import { User, AttendanceRecord, PayrollReport } from '../types';
import { DAYS_IN_MONTH, FREE_LEAVE_QUOTA } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[],
  allRecordsThisMonth: AttendanceRecord[], // Needed to check 3-day quota
  weekStart: Date,
  weekEnd: Date
): PayrollReport => {
  const dailyRate = (user.gapok + user.uangMakan) / DAYS_IN_MONTH;

  // Filter records for this specific week
  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;
  const leaveCount = weekRecords.filter(r => r.status === 'LEAVE').length;

  // Monthly stats to determine if we exceed 3 free leaves
  const monthlyLeaves = allRecordsThisMonth.filter(r => r.status === 'LEAVE').length;

  // Logic: Each leave above FREE_LEAVE_QUOTA (3) is deducted.
  // We need to figure out how many of the leaves IN THIS WEEK are "excess".
  // Simplified: If cumulative month leaves > 3, then current leaves might be penalized.
  let excessLeaveCount = 0;
  let runningLeaveCount = 0;

  // Sort all month records to track when the quota breaks
  const sortedMonthRecords = [...allRecordsThisMonth].sort((a, b) => a.date.localeCompare(b.date));

  sortedMonthRecords.forEach(r => {
    if (r.status === 'LEAVE') {
      runningLeaveCount++;
      const rDate = new Date(r.date);
      if (runningLeaveCount > FREE_LEAVE_QUOTA && rDate >= weekStart && rDate <= weekEnd) {
        excessLeaveCount++;
      }
    }
  });

  // Monday to Sunday is 7 days.
  // Gross pay for the week is 7 days worth of daily rate.
  // But strictly, we subtract for missed days or excess leaves.
  // The requirement says: "Gaji dibagi jumlah hari dalam sebulan... gajian tiap minggu... masuk terus senin-minggu... jatah libur 3x tanpa potong... jika lebih 3x potong gaji harian".

  const weeklyBase = dailyRate * 7;
  const deduction = excessLeaveCount * dailyRate;

  // If they just didn't show up (ABSENT status) and didn't apply for leave, we deduct too.
  const absentCount = 7 - (presentCount + leaveCount); 
  const absenceDeduction = absentCount * dailyRate;

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalLeave: leaveCount,
    excessLeaveCount,
    grossSalary: weeklyBase,
    deductions: deduction + absenceDeduction,
    netSalary: Math.max(0, weeklyBase - (deduction + absenceDeduction))
  };
};

