import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [distance, setDistance] = useState<number | null>(null);
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  const checkLocation = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      setDistance(dist);
      if (dist > outletConfig.radius) {
        setErrorLoc(`Anda berada di luar radius (${Math.round(dist)}m). Radius maksimal: ${outletConfig.radius}m`);
      }
    } catch (err) {
      setErrorLoc("Gagal mendapatkan lokasi. Pastikan izin GPS aktif.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const handleClockIn = async () => {
    setLoadingLoc(true);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Gagal: Jarak ${Math.round(dist)}m melebihi batas.`);
      }
    } catch (err) {
      setErrorLoc("Gagal akses lokasi.");
    } finally {
      setLoadingLoc(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      <div className="space-y-6">
        {/* Attendance Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <h2 className="text-xl font-bold mb-4 flex items-center">
            <span className="w-8 h-8 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mr-2">📍</span>
            Presensi Hari Ini
          </h2>

          <div className="bg-slate-50 rounded-xl p-4 mb-6">
            <div className="flex justify-between items-center mb-2">
              <span className="text-slate-500">Tanggal:</span>
              <span className="font-semibold">{new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-slate-500">Status:</span>
              <span className={`px-2 py-1 rounded text-xs font-bold uppercase ${todayRecord?.clockIn ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                {todayRecord?.clockIn ? 'Sudah Absen' : 'Belum Absen'}
              </span>
            </div>
          </div>

          <div className="space-y-4">
            {!todayRecord?.clockIn && (
              <>
                <button
                  onClick={checkLocation}
                  disabled={loadingLoc}
                  className="w-full py-3 bg-slate-200 hover:bg-slate-300 rounded-xl font-semibold transition-colors disabled:opacity-50"
                >
                  {loadingLoc ? 'Mengecek Lokasi...' : 'Cek Lokasi Saya'}
                </button>
                {distance !== null && !errorLoc && (
                  <p className="text-sm text-green-600 font-medium text-center">
                    Lokasi cocok! Jarak: {Math.round(distance)}m dari outlet.
                  </p>
                )}
                {errorLoc && (
                  <p className="text-sm text-red-500 font-medium text-center bg-red-50 p-2 rounded-lg">
                    {errorLoc}
                  </p>
                )}
                <button
                  onClick={handleClockIn}
                  disabled={loadingLoc || (distance !== null && distance > outletConfig.radius)}
                  className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-lg shadow-md transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  CLOCK IN
                </button>
              </>
            )}

            {todayRecord?.clockIn && !todayRecord?.clockOut && (
              <button
                onClick={onClockOut}
                className="w-full py-4 bg-orange-500 hover:bg-orange-600 text-white rounded-xl font-bold text-lg shadow-md transition-all"
              >
                CLOCK OUT
              </button>
            )}

            {todayRecord?.clockOut && (
              <div className="text-center p-4 bg-green-50 rounded-xl border border-green-200">
                <p className="text-green-700 font-bold">Kerja Selesai!</p>
                <p className="text-sm text-green-600">Jam Masuk: {todayRecord.clockIn}</p>
                <p className="text-sm text-green-600">Jam Keluar: {todayRecord.clockOut}</p>
              </div>
            )}
          </div>
        </div>

        {/* Leave Request Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <h2 className="text-xl font-bold mb-4 flex items-center">
            <span className="w-8 h-8 bg-purple-100 text-purple-600 rounded-full flex items-center justify-center mr-2">📄</span>
            Ajukan Izin
          </h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tanggal Izin</label>
              <input
                type="date"
                value={leaveDate}
                onChange={(e) => setLeaveDate(e.target.value)}
                min={today}
                className="w-full p-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Alasan</label>
              <textarea
                value={leaveReason}
                onChange={(e) => setLeaveReason(e.target.value)}
                rows={3}
                placeholder="Kenapa anda izin?"
                className="w-full p-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
              />
            </div>
            <button
              onClick={() => {
                if(leaveDate && leaveReason) {
                  onSubmitLeave(leaveDate, leaveReason);
                  setLeaveDate('');
                  setLeaveReason('');
                }
              }}
              className="w-full py-3 bg-purple-600 hover:bg-purple-700 text-white rounded-xl font-semibold transition-colors"
            >
              Kirim Pengajuan
            </button>
          </div>
        </div>
      </div>

      {/* History Side */}
      <div className="space-y-6">
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <h2 className="text-xl font-bold mb-4">Riwayat Izin & Absensi</h2>
          <div className="space-y-3 overflow-y-auto max-h-[600px] pr-2">
            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Status Izin</h3>
            {leaveRequests.filter(l => l.userId === user.id).length === 0 && (
              <p className="text-slate-400 text-sm italic">Belum ada riwayat izin.</p>
            )}
            {leaveRequests.filter(l => l.userId === user.id).map(l => (
              <div key={l.id} className="p-3 bg-slate-50 rounded-lg flex justify-between items-center">
                <div>
                  <p className="font-medium">{new Date(l.date).toLocaleDateString('id-ID')}</p>
                  <p className="text-xs text-slate-500">{l.reason}</p>
                </div>
                <span className={`text-xs font-bold px-2 py-1 rounded ${
                  l.status === 'APPROVED' ? 'bg-green-100 text-green-700' : 
                  l.status === 'REJECTED' ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                }`}>
                  {l.status}
                </span>
              </div>
            ))}

            <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider mt-6">Log Absen</h3>
            {attendance.filter(a => a.userId === user.id).map(a => (
              <div key={a.id} className="p-3 border-b flex justify-between items-center text-sm">
                <div>
                  <p className="font-semibold">{new Date(a.date).toLocaleDateString('id-ID')}</p>
                  <p className="text-xs text-slate-500">In: {a.clockIn || '--'} | Out: {a.clockOut || '--'}</p>
                </div>
                <span className={`text-xs px-2 py-0.5 rounded font-bold ${a.status === 'PRESENT' ? 'text-green-600' : 'text-purple-600'}`}>
                  {a.status}
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeDashboard;

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, PayrollReport } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave
}) => {
  const [activeTab, setActiveTab] = useState<'attendance' | 'payroll' | 'settings'>('attendance');
  const [tempLat, setTempLat] = useState(outletConfig.latitude.toString());
  const [tempLng, setTempLng] = useState(outletConfig.longitude.toString());
  const [tempRad, setTempRad] = useState(outletConfig.radius.toString());

  // Payroll Calculation Helper
  const getPayrollForUser = (user: User) => {
    // Determine this week (Simplified: last 7 days)
    const end = new Date();
    const start = new Date();
    start.setDate(end.getDate() - 7);

    // Monthly data for leave quota
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);

    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end);
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100">
      <div className="flex border-b">
        {(['attendance', 'payroll', 'settings'] as const).map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 py-4 font-bold text-sm uppercase tracking-widest transition-all ${
              activeTab === tab 
                ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/50' 
                : 'text-slate-400 hover:text-slate-600'
            }`}
          >
            {tab === 'attendance' ? 'Absensi & Izin' : tab === 'payroll' ? 'Gaji Mingguan' : 'Konfigurasi'}
          </button>
        ))}
      </div>

      <div className="p-8">
        {activeTab === 'attendance' && (
          <div className="space-y-10">
            {/* Pending Leave Requests */}
            <section>
              <h3 className="text-xl font-bold text-slate-800 mb-4 flex items-center">
                <span className="w-2 h-8 bg-purple-500 rounded mr-3"></span>
                Persetujuan Izin
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && (
                  <p className="col-span-full text-center text-slate-400 py-8 border-2 border-dashed rounded-2xl">
                    Tidak ada pengajuan izin tertunda.
                  </p>
                )}
                {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                  const emp = employees.find(e => e.id === l.userId);
                  return (
                    <div key={l.id} className="bg-white border rounded-2xl p-4 shadow-sm hover:shadow-md transition-shadow">
                      <div className="flex justify-between items-start mb-2">
                        <div>
                          <p className="font-bold text-slate-900">{emp?.name}</p>
                          <p className="text-xs text-slate-500">{new Date(l.date).toLocaleDateString('id-ID')}</p>
                        </div>
                        <span className="bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded text-[10px] font-bold">PENDING</span>
                      </div>
                      <p className="text-sm text-slate-600 mb-4 bg-slate-50 p-2 rounded italic">"{l.reason}"</p>
                      <div className="grid grid-cols-2 gap-2">
                        <button 
                          onClick={() => onApproveLeave(l.id, 'APPROVED')}
                          className="py-2 bg-green-500 hover:bg-green-600 text-white rounded-lg text-xs font-bold transition-colors"
                        >
                          SETUJU
                        </button>
                        <button 
                          onClick={() => onApproveLeave(l.id, 'REJECTED')}
                          className="py-2 bg-red-500 hover:bg-red-600 text-white rounded-lg text-xs font-bold transition-colors"
                        >
                          TOLAK
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>

            {/* Attendance Logs */}
            <section>
              <h3 className="text-xl font-bold text-slate-800 mb-4 flex items-center">
                <span className="w-2 h-8 bg-indigo-500 rounded mr-3"></span>
                Log Kehadiran Karyawan
              </h3>
              <div className="overflow-x-auto rounded-xl border">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
                    <tr>
                      <th className="px-6 py-4">Karyawan</th>
                      <th className="px-6 py-4">Tanggal</th>
                      <th className="px-6 py-4">Jam In</th>
                      <th className="px-6 py-4">Jam Out</th>
                      <th className="px-6 py-4">Status</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y text-sm">
                    {attendance.map(a => (
                      <tr key={a.id} className="hover:bg-slate-50">
                        <td className="px-6 py-4 font-medium">{employees.find(e => e.id === a.userId)?.name}</td>
                        <td className="px-6 py-4">{a.date}</td>
                        <td className="px-6 py-4 text-slate-500">{a.clockIn || '-'}</td>
                        <td className="px-6 py-4 text-slate-500">{a.clockOut || '-'}</td>
                        <td className="px-6 py-4">
                          <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                            a.status === 'PRESENT' ? 'bg-green-100 text-green-700' : 'bg-purple-100 text-purple-700'
                          }`}>
                            {a.status}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </section>
          </div>
        )}

        {activeTab === 'payroll' && (
          <div className="space-y-6">
            <div className="bg-indigo-600 rounded-2xl p-6 text-white mb-8">
              <h3 className="text-xl font-bold mb-2">Ikhtisar Gaji Mingguan</h3>
              <p className="text-indigo-100 text-sm">Perhitungan otomatis berdasarkan kehadiran dan kuota cuti (3x/bulan).</p>
            </div>

            <div className="grid grid-cols-1 gap-4">
              {employees.filter(e => e.role === 'EMPLOYEE').map(emp => {
                const report = getPayrollForUser(emp);
                return (
                  <div key={emp.id} className="bg-white border rounded-2xl p-6 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div className="flex-1">
                      <h4 className="text-lg font-bold text-slate-900">{emp.name}</h4>
                      <div className="flex gap-4 mt-1 text-xs text-slate-500">
