import React, { useState, useEffect } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';

const App: React.FC = () => {
  // Auth state
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Data state
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);

  // Persistence simulation
  useEffect(() => {
    const savedAttendance = localStorage.getItem('attendance');
    const savedLeave = localStorage.getItem('leave');
    const savedConfig = localStorage.getItem('config');

    if (savedAttendance) setAttendance(JSON.parse(savedAttendance));
    if (savedLeave) setLeaveRequests(JSON.parse(savedLeave));
    if (savedConfig) setOutletConfig(JSON.parse(savedConfig));
  }, []);

  useEffect(() => {
    localStorage.setItem('attendance', JSON.stringify(attendance));
    localStorage.setItem('leave', JSON.stringify(leaveRequests));
    localStorage.setItem('config', JSON.stringify(outletConfig));
  }, [attendance, leaveRequests, outletConfig]);

  // Handlers
  const handleLogin = (userId: string) => {
    const user = MOCK_USERS.find(u => u.id === userId);
    if (user) setCurrentUser(user);
  };

  const handleLogout = () => setCurrentUser(null);

  const handleClockIn = (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }),
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT'
    };
    setAttendance(prev => [...prev, newRecord]);
  };

  const handleClockOut = () => {
    if (!currentUser) return;
    const today = new Date().toISOString().split('T')[0];
    const now = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === today) ? { ...a, clockOut: now } : a
    ));
  };

  const handleSubmitLeave = (date: string, reason: string) => {
    if (!currentUser) return;
    const newLeave: LeaveRequest = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING'
    };
    setLeaveRequests(prev => [...prev, newLeave]);
  };

  const handleApproveLeave = (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));

    // If approved, create attendance record with status LEAVE
    if (status === 'APPROVED') {
      const leave = leaveRequests.find(l => l.id === leaveId);
      if (leave) {
        const leaveRecord: AttendanceRecord = {
          id: Math.random().toString(36).substr(2, 9),
          userId: leave.userId,
          date: leave.date,
          clockIn: null,
          clockOut: null,
          latitude: 0,
          longitude: 0,
          status: 'LEAVE'
        };
        setAttendance(prev => [...prev, leaveRecord]);
      }
    }
  };

  const handleUpdateConfig = (config: OutletConfig) => {
    setOutletConfig(config);
    alert("Konfigurasi lokasi berhasil diperbarui!");
  };

  // Login Screen
  if (!currentUser) {
    return (
      <div className="min-h-screen bg-indigo-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-8 border border-indigo-100">
          <div className="text-center mb-8">
            <div className="w-20 h-20 bg-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg transform -rotate-3">
              <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z"></path>
              </svg>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-slate-400 font-medium">Payroll & Attendance System</p>
          </div>

          <div className="space-y-4">
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest text-center mb-2">Pilih Akun Masuk</p>
            {MOCK_USERS.map(u => (
              <button
                key={u.id}
                onClick={() => handleLogin(u.id)}
                className="w-full flex items-center justify-between p-4 bg-slate-50 hover:bg-indigo-50 border border-slate-200 hover:border-indigo-300 rounded-2xl transition-all group"
              >
                <div className="flex items-center space-x-3 text-left">
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${u.role === UserRole.OWNER ? 'bg-indigo-100 text-indigo-600' : 'bg-green-100 text-green-600'}`}>
                    {u.name.charAt(0)}
                  </div>
                  <div>
                    <p className="font-bold text-slate-900">{u.name}</p>
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-tighter">{u.role}</p>
                  </div>
                </div>
                <span className="opacity-0 group-hover:opacity-100 transform translate-x-2 group-hover:translate-x-0 transition-all text-indigo-600">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                </span>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser}
          outletConfig={outletConfig}
          attendance={attendance}
          leaveRequests={leaveRequests}
          onClockIn={handleClockIn}
          onClockOut={handleClockOut}
          onSubmitLeave={handleSubmitLeave}
        />
      ) : (
        <OwnerDashboard 
          employees={MOCK_USERS}
          attendance={attendance}
          leaveRequests={leaveRequests}
          outletConfig={outletConfig}
          onUpdateConfig={handleUpdateConfig}
          onApproveLeave={handleApproveLeave}
        />
      )}
    </Layout>
  );
};

export default App;

