import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');
  const [filterDate, setFilterDate] = useState(new Date().toISOString().split('T')[0]);

  // Employee Modal State
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ name: '', username: '', gapok: 0, uangMakan: 0 });

  // Settings State
  const [tempConfig, setTempConfig] = useState(outletConfig);

  const exportAttendanceToCSV = () => {
    const headers = ['Nama', 'Tanggal', 'Jam Masuk', 'Jam Keluar', 'Status'];
    const rows = attendance
      .filter(a => a.date === filterDate)
      .map(a => [
        employees.find(e => e.id === a.userId)?.name || 'Unknown',
        a.date,
        a.clockIn || '-',
        a.clockOut || '-',
        a.status
      ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `absensi_${filterDate}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getPayrollForUser = (user: User) => {
    const end = new Date();
    const start = new Date();
    start.setDate(end.getDate() - 7);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end);
  };

  const filteredAttendance = attendance.filter(a => a.date === filterDate);

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100'
      }`}
    >
      <span className="text-xl">{icon}</span>
      <span className="font-semibold text-sm">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-6">
      {/* Sidebar */}
      <aside className="w-full md:w-64 space-y-2">
        <SidebarItem icon="📊" label="Dashboard" id="dashboard" />
        <SidebarItem icon="👥" label="Data Karyawan" id="employees" />
        <SidebarItem icon="📅" label="Log Absensi" id="attendance" />
        <SidebarItem icon="💰" label="Gaji Mingguan" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 bg-white rounded-3xl border border-slate-200 shadow-sm p-6 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-8">
            <h2 className="text-2xl font-black text-slate-800">Dashboard Owner</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-2xl">
                <p className="text-indigo-600 text-sm font-bold uppercase">Total Karyawan</p>
                <p className="text-4xl font-black text-indigo-900">{employees.filter(e => e.role === UserRole.EMPLOYEE).length}</p>
              </div>
              <div className="bg-green-50 border border-green-100 p-6 rounded-2xl">
                <p className="text-green-600 text-sm font-bold uppercase">Hadir Hari Ini</p>
                <p className="text-4xl font-black text-green-900">
                  {attendance.filter(a => a.date === new Date().toISOString().split('T')[0] && a.status === 'PRESENT').length}
                </p>
              </div>
              <div className="bg-purple-50 border border-purple-100 p-6 rounded-2xl">
                <p className="text-purple-600 text-sm font-bold uppercase">Izin Pending</p>
                <p className="text-4xl font-black text-purple-900">{leaveRequests.filter(l => l.status === 'PENDING').length}</p>
              </div>
            </div>

            <section>
              <h3 className="text-lg font-bold mb-4">Persetujuan Izin</h3>
              <div className="space-y-3">
                {leaveRequests.filter(l => l.status === 'PENDING').map(l => (
                  <div key={l.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl border border-slate-200">
                    <div>
                      <p className="font-bold text-slate-900">{employees.find(e => e.id === l.userId)?.name}</p>
