                    </div>
                    <div className="flex space-x-2">
                      <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="bg-green-500 text-white px-4 py-1.5 rounded-lg text-xs font-bold">Setuju</button>
                      <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="bg-red-500 text-white px-4 py-1.5 rounded-lg text-xs font-bold">Tolak</button>
                    </div>
                  </div>
                ))}
                {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && <p className="text-slate-400 italic text-sm">Tidak ada izin pending.</p>}
              </div>
            </section>
          </div>
        )}

        {activeMenu === 'employees' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-800">Manajemen Karyawan</h2>
              <button 
                onClick={() => { setEditingEmp(null); setEmpForm({ name: '', username: '', gapok: 0, uangMakan: 0 }); setShowEmpModal(true); }}
                className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold shadow-md hover:bg-indigo-700 transition-all"
              >
                + Tambah Karyawan
              </button>
            </div>

            <div className="overflow-x-auto border rounded-2xl">
              <table className="w-full text-left border-collapse">
