                  <tr>
                    <th className="px-6 py-4">Nama</th>
                    <th className="px-6 py-4">Username</th>
                    <th className="px-6 py-4">Gapok</th>
                    <th className="px-6 py-4">Uang Makan</th>
                    <th className="px-6 py-4 text-right">Aksi</th>
                  </tr>
                </thead>
                <tbody className="divide-y text-sm">
                  {employees.filter(e => e.role === UserRole.EMPLOYEE).map(e => (
                    <tr key={e.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-6 py-4 font-bold text-slate-700">{e.name}</td>
                      <td className="px-6 py-4 text-slate-500">@{e.username}</td>
                      <td className="px-6 py-4">Rp {e.gapok.toLocaleString('id-ID')}</td>
                      <td className="px-6 py-4">Rp {e.uangMakan.toLocaleString('id-ID')}</td>
