                    <tr key={a.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-6 py-4 font-bold text-slate-700">{employees.find(e => e.id === a.userId)?.name}</td>
                      <td className="px-6 py-4 text-slate-500">{a.clockIn || '--'}</td>
                      <td className="px-6 py-4 text-slate-500">{a.clockOut || '--'}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-[10px] font-black uppercase ${
                          a.status === 'PRESENT' ? 'bg-green-100 text-green-700' : 'bg-purple-100 text-purple-700'
                        }`}>
                          {a.status}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeMenu === 'payroll' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-black text-slate-800">Gaji Mingguan</h2>
            <div className="grid grid-cols-1 gap-4">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => {
                const report = getPayrollForUser(emp);
                return (
                  <div key={emp.id} className="p-6 border rounded-2xl flex flex-col md:flex-row md:items-center justify-between gap-6 hover:border-indigo-200 transition-colors">
                    <div>
                      <h4 className="text-lg font-black text-slate-900">{emp.name}</h4>
                      <p className="text-xs text-slate-500">Status Kehadiran: <span className="text-indigo-600 font-bold">{report.totalPresent} Hari</span></p>
                    </div>
                    <div className="flex items-center gap-8">
                      <div className="text-right">
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Potongan (Absen/Izin)</p>
                        <p className="font-bold text-red-500">- Rp {report.deductions.toLocaleString('id-ID')}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">Gaji Bersih</p>
                        <p className="text-xl font-black text-indigo-700">Rp {report.netSalary.toLocaleString('id-ID')}</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeMenu === 'settings' && (
          <div className="max-w-xl space-y-6">
            <h2 className="text-2xl font-black text-slate-800">Pengaturan Outlet</h2>
            <div className="space-y-4 bg-slate-50 p-6 rounded-2xl border">
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Latitude</label>
                <input 
                  type="number" value={tempConfig.latitude} 
                  onChange={e => setTempConfig({...tempConfig, latitude: parseFloat(e.target.value)})}
                  className="w-full p-3 border rounded-xl"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Longitude</label>
                <input 
                  type="number" value={tempConfig.longitude} 
                  onChange={e => setTempConfig({...tempConfig, longitude: parseFloat(e.target.value)})}
                  className="w-full p-3 border rounded-xl"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 mb-1 uppercase">Radius (Meter)</label>
                <input 
                  type="number" value={tempConfig.radius} 
                  onChange={e => setTempConfig({...tempConfig, radius: parseInt(e.target.value)})}
                  className="w-full p-3 border rounded-xl"
                />
              </div>
              <button 
                onClick={() => onUpdateConfig(tempConfig)}
                className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-black transition-all"
              >
                Update Konfigurasi
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Employee Modal */}
      {showEmpModal && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-w-lg p-8 shadow-2xl">
            <h3 className="text-xl font-black mb-6">{editingEmp ? 'Edit Karyawan' : 'Tambah Karyawan Baru'}</h3>
            <div className="space-y-4">
              <input 
                placeholder="Nama Lengkap" 
                value={empForm.name} 
                onChange={e => setEmpForm({...empForm, name: e.target.value})}
                className="w-full p-4 border rounded-2xl"
              />
              <input 
                placeholder="Username (tanpa spasi)" 
                value={empForm.username} 
                onChange={e => setEmpForm({...empForm, username: e.target.value.toLowerCase().replace(/\s/g, '')})}
                className="w-full p-4 border rounded-2xl"
              />
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-bold text-slate-400">Gaji Pokok</label>
                  <input 
                    type="number" value={empForm.gapok} 
                    onChange={e => setEmpForm({...empForm, gapok: parseInt(e.target.value)})}
                    className="w-full p-4 border rounded-2xl"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400">Uang Makan</label>
                  <input 
                    type="number" value={empForm.uangMakan} 
                    onChange={e => setEmpForm({...empForm, uangMakan: parseInt(e.target.value)})}
                    className="w-full p-4 border rounded-2xl"
                  />
                </div>
              </div>
              <div className="flex space-x-3 pt-4">
                <button 
                  onClick={() => setShowEmpModal(false)}
                  className="flex-1 bg-slate-100 py-3 rounded-xl font-bold text-slate-600"
                >
                  Batal
                </button>
                <button 
                  onClick={() => {
                    if (editingEmp) onEditEmployee({ ...editingEmp, ...empForm } as User);
                    else onAddEmployee(empForm);
                    setShowEmpModal(false);
                  }}
                  className="flex-1 bg-indigo-600 py-3 rounded-xl font-bold text-white"
                >
                  Simpan
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

