import React, { useState, useEffect } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';

const App: React.FC = () => {
  // Global States
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);

  // Login Form States
  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Initial Data Load
  useEffect(() => {
    const savedUsers = localStorage.getItem('damdam_users');
    const savedAttendance = localStorage.getItem('damdam_attendance');
    const savedLeave = localStorage.getItem('damdam_leave');
    const savedConfig = localStorage.getItem('damdam_config');

    setUsers(savedUsers ? JSON.parse(savedUsers) : MOCK_USERS);
    if (savedAttendance) setAttendance(JSON.parse(savedAttendance));
    if (savedLeave) setLeaveRequests(JSON.parse(savedLeave));
    if (savedConfig) setOutletConfig(JSON.parse(savedConfig));
  }, []);

  // Sync to LocalStorage
  useEffect(() => {
    if (users.length > 0) localStorage.setItem('damdam_users', JSON.stringify(users));
    localStorage.setItem('damdam_attendance', JSON.stringify(attendance));
    localStorage.setItem('damdam_leave', JSON.stringify(leaveRequests));
    localStorage.setItem('damdam_config', JSON.stringify(outletConfig));
  }, [users, attendance, leaveRequests, outletConfig]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    const user = users.find(u => u.username === loginUsername && u.password === loginPassword);
    if (user) {
      setCurrentUser(user);
      setLoginUsername('');
      setLoginPassword('');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => setCurrentUser(null);

  // Owner Actions
  const handleAddEmployee = (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'New Employee',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: '123', // Default password
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      isActive: true
    };
    setUsers(prev => [...prev, newUser]);
  };

  const handleEditEmployee = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
  };

  const handleDeleteEmployee = (userId: string) => {
    if (confirm('Hapus karyawan ini? Data absensi akan tetap ada.')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
    }
  };

  // Employee Actions
  const handleClockIn = (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' }),
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT'
    };
    setAttendance(prev => [...prev, newRecord]);
  };

  const handleClockOut = () => {
    if (!currentUser) return;
    const today = new Date().toISOString().split('T')[0];
    const now = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });
    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === today) ? { ...a, clockOut: now } : a
    ));
  };

  const handleSubmitLeave = (date: string, reason: string) => {
    if (!currentUser) return;
    const newLeave: LeaveRequest = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING'
    };
    setLeaveRequests(prev => [...prev, newLeave]);
  };

  const handleApproveLeave = (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    if (status === 'APPROVED') {
      const leave = leaveRequests.find(l => l.id === leaveId);
      if (leave) {
        const leaveRecord: AttendanceRecord = {
          id: Math.random().toString(36).substr(2, 9),
          userId: leave.userId,
          date: leave.date,
          clockIn: null,
          clockOut: null,
          latitude: 0,
          longitude: 0,
          status: 'LEAVE'
        };
        setAttendance(prev => [...prev, leaveRecord]);
      }
    }
  };

  // Auth Screen
  if (!currentUser) {
    return (
      <div className="min-h-screen bg-indigo-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-3xl shadow-2xl p-10 border border-indigo-100">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg">
              <span className="text-3xl">🧺</span>
            </div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-slate-400 font-medium">Payroll & Management</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Username</label>
              <input 
                type="text" 
                value={loginUsername}
                onChange={e => setLoginUsername(e.target.value)}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                placeholder="Masukkan username"
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Password</label>
              <input 
                type="password" 
                value={loginPassword}
                onChange={e => setLoginPassword(e.target.value)}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                placeholder="Masukkan password"
                required
              />
            </div>
            {loginError && <p className="text-red-500 text-xs font-bold text-center">{loginError}</p>}
            <button 
              type="submit"
              className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold shadow-lg hover:bg-indigo-700 transition-all transform hover:-translate-y-1"
            >
              Log In
            </button>
          </form>

          <div className="mt-8 pt-6 border-t text-center">
            <p className="text-[10px] text-slate-400 font-bold uppercase mb-2 italic">Akun Demo (User/Pass):</p>
            <p className="text-[10px] text-slate-500">Owner: owner / 123</p>
            <p className="text-[10px] text-slate-500">Employee: budi / 123</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser}
          outletConfig={outletConfig}
          attendance={attendance}
          leaveRequests={leaveRequests}
          onClockIn={handleClockIn}
          onClockOut={handleClockOut}
          onSubmitLeave={handleSubmitLeave}
        />
      ) : (
        <OwnerDashboard 
          employees={users}
          attendance={attendance}
          leaveRequests={leaveRequests}
          outletConfig={outletConfig}
          onUpdateConfig={setOutletConfig}
          onApproveLeave={handleApproveLeave}
          onAddEmployee={handleAddEmployee}
          onEditEmployee={handleEditEmployee}
          onDeleteEmployee={handleDeleteEmployee}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [distance, setDistance] = useState<number | null>(null);
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      setDistance(dist);
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Gagal: Anda berada ${Math.round(dist)}m dari outlet. Maksimal ${outletConfig.radius}m.`);
      }
    } catch (err) {
      setErrorLoc("Izin lokasi ditolak atau GPS mati.");
    } finally {
      setLoadingLoc(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-start">
      {/* Action Section */}
      <div className="lg:col-span-4 space-y-6">
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm text-center">
          <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4 text-3xl">
            📍
          </div>
          <h2 className="text-xl font-black text-slate-800 mb-2">Presensi Laundry</h2>
          <p className="text-slate-500 text-sm mb-6 font-medium">
            {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' })}
          </p>

          {!todayRecord?.clockIn ? (
            <button
              onClick={handleClockInAction}
              disabled={loadingLoc}
              className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-100 transition-all disabled:opacity-50"
            >
              {loadingLoc ? 'Mengecek Lokasi...' : 'ABSEN MASUK'}
            </button>
          ) : !todayRecord.clockOut ? (
            <button
              onClick={onClockOut}
              className="w-full py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-orange-100 transition-all"
            >
              ABSEN KELUAR
            </button>
          ) : (
            <div className="p-4 bg-green-50 text-green-700 rounded-2xl font-bold border border-green-100">
              Selesai Kerja Hari Ini! ✅
            </div>
          )}

          {errorLoc && <p className="mt-4 text-xs font-bold text-red-500 bg-red-50 p-3 rounded-xl">{errorLoc}</p>}
        </div>

        <div className="bg-indigo-700 p-8 rounded-3xl text-white shadow-lg">
          <h3 className="font-black text-lg mb-4">Pengajuan Izin</h3>
          <div className="space-y-3">
            <input 
              type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)}
              className="w-full p-3 bg-white/10 border border-white/20 rounded-xl outline-none placeholder:text-white/50"
              min={today}
            />
            <textarea 
              placeholder="Alasan izin..." value={leaveReason} onChange={e => setLeaveReason(e.target.value)}
              className="w-full p-3 bg-white/10 border border-white/20 rounded-xl outline-none min-h-[80px]"
            />
            <button 
              onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason); setLeaveDate(''); setLeaveReason(''); } }}
              className="w-full bg-white text-indigo-700 py-3 rounded-xl font-black hover:bg-slate-100"
            >
              Kirim Pengajuan
            </button>
          </div>
        </div>
      </div>

      {/* History Section */}
      <div className="lg:col-span-8 space-y-6">
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm min-h-[500px]">
          <h2 className="text-xl font-black text-slate-800 mb-6 flex items-center">
            <span className="mr-3">🕒</span> Riwayat Kehadiran Anda
          </h2>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="text-[10px] font-black uppercase text-slate-400 tracking-widest border-b">
                <tr>
                  <th className="pb-4">Tanggal</th>
                  <th className="pb-4">Jam Masuk</th>
                  <th className="pb-4">Jam Keluar</th>
                  <th className="pb-4">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {attendance.filter(a => a.userId === user.id).length === 0 && (
                  <tr><td colSpan={4} className="py-10 text-center text-slate-400 italic">Belum ada riwayat absensi.</td></tr>
                )}
                {attendance.filter(a => a.userId === user.id).map(a => (
                  <tr key={a.id} className="text-sm">
                    <td className="py-4 font-bold text-slate-700">{a.date}</td>
                    <td className="py-4 text-slate-500 font-medium">{a.clockIn || '--'}</td>
                    <td className="py-4 text-slate-500 font-medium">{a.clockOut || '--'}</td>
                    <td className="py-4">
                      <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${a.status === 'PRESENT' ? 'text-green-600' : 'text-purple-600'}`}>{a.status}</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeDashboard;

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');
  const [filterDate, setFilterDate] = useState(new Date().toISOString().split('T')[0]);

  // Employee Modal State
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ name: '', username: '', password: '', gapok: 0, uangMakan: 0 });

  // Settings State
  const [tempConfig, setTempConfig] = useState(outletConfig);

  const getRemainingLeave = (userId: string) => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    const usedLeave = attendance.filter(a => 
      a.userId === userId && 
      a.status === 'LEAVE' && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - usedLeave);
  };

  const exportAttendanceToCSV = () => {
    const headers = ['Nama', 'Tanggal', 'Jam Masuk', 'Jam Keluar', 'Status'];
    const rows = attendance
      .filter(a => a.date === filterDate)
      .map(a => [
        employees.find(e => e.id === a.userId)?.name || 'Unknown',
        a.date,
        a.clockIn || '-',
        a.clockOut || '-',
        a.status
      ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `absensi_${filterDate}.csv`);
    link.click();
  };

  const getPayrollForUser = (user: User) => {
    const end = new Date();
    const start = new Date();
    start.setDate(end.getDate() - 7);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end);
  };

  const filteredAttendance = attendance.filter(a => a.date === filterDate);

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
