export default OwnerDashboard;

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [distance, setDistance] = useState<number | null>(null);
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  const getRemainingLeave = () => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    const usedLeave = attendance.filter(a => 
      a.userId === user.id && 
      a.status === 'LEAVE' && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - usedLeave);
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      setDistance(dist);
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Gagal: Anda berada ${Math.round(dist)}m dari outlet. Maksimal ${outletConfig.radius}m.`);
      }
    } catch (err) {
      setErrorLoc("Izin lokasi ditolak atau GPS mati.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const sisaLibur = getRemainingLeave();

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
      {/* Action Section */}
      <div className="lg:col-span-4 space-y-6">
        <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm text-center">
          <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 text-3xl shadow-sm rotate-3 hover:rotate-0 transition-transform">
            📍
          </div>
          <h2 className="text-2xl font-black text-slate-800 mb-2">Presensi Laundry</h2>
          <p className="text-slate-400 text-sm mb-8 font-medium">
            {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
          </p>

          <div className="mb-8 space-y-2">
            {!todayRecord?.clockIn ? (
              <button
                onClick={handleClockInAction}
                disabled={loadingLoc}
                className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-lg shadow-xl shadow-indigo-100 transition-all disabled:opacity-50 active:scale-95"
              >
                {loadingLoc ? 'Mengecek Lokasi...' : 'ABSEN MASUK'}
              </button>
            ) : !todayRecord.clockOut ? (
              <button
                onClick={onClockOut}
                className="w-full py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-2xl font-black text-lg shadow-xl shadow-orange-100 transition-all active:scale-95"
              >
                ABSEN KELUAR
              </button>
            ) : (
              <div className="p-6 bg-green-50 text-green-700 rounded-3xl font-black border border-green-100 shadow-inner">
                Selesai Kerja Hari Ini! ✅
                <p className="text-[10px] uppercase mt-1 opacity-60">Kembali besok pagi</p>
              </div>
            )}
          </div>

          <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center justify-between">
             <div className="text-left">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sisa Jatah Libur</p>
                <p className="text-lg font-black text-indigo-600">{sisaLibur}x / {FREE_LEAVE_QUOTA}x</p>
             </div>
             <span className="text-2xl">🌴</span>
          </div>

          {errorLoc && <p className="mt-4 text-xs font-bold text-red-500 bg-red-50 p-4 rounded-2xl border border-red-100">{errorLoc}</p>}
        </div>

        <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm">
          <h3 className="font-black text-xl text-slate-800 mb-6 flex items-center">
             <span className="mr-2 text-purple-600">📄</span> Pengajuan Izin
          </h3>
          <div className="space-y-4">
            <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-widest pl-1">Tanggal Izin</label>
                <input 
                type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)}
                className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500 transition-all font-bold text-slate-700"
                min={today}
                />
            </div>
            <div>
                <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-widest pl-1">Alasan</label>
                <textarea 
                placeholder="Kenapa kamu tidak masuk?" value={leaveReason} onChange={e => setLeaveReason(e.target.value)}
                className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-purple-500 transition-all min-h-[120px] font-medium"
                />
            </div>
            <button 
              onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason); setLeaveDate(''); setLeaveReason(''); } }}
