export default OwnerDashboard;

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [distance, setDistance] = useState<number | null>(null);
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  const getRemainingLeave = () => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    const usedLeave = attendance.filter(a => 
      a.userId === user.id && 
      a.status === 'LEAVE' && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - usedLeave);
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      setDistance(dist);
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Gagal: Lokasi Anda ${Math.round(dist)}m dari titik pusat. Batas maksimal ${outletConfig.radius}m.`);
      }
    } catch (err) {
      setErrorLoc("Akses lokasi ditolak. Harap aktifkan GPS Anda.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const sisaLibur = getRemainingLeave();

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
      {/* Kolom Aksi - Tema Putih */}
      <div className="lg:col-span-5 space-y-8">
        <div className="bg-white p-12 rounded-[48px] border border-slate-100 shadow-sm text-center">
          <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 text-4xl shadow-sm rotate-6 hover:rotate-0 transition-all duration-500">
            🧺
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Halo, {user.name.split(' ')[0]}!</h2>
          <p className="text-slate-400 text-sm mb-10 font-bold uppercase tracking-widest">
            {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' })}
          </p>

          <div className="mb-10">
            {!todayRecord?.clockIn && todayRecord?.status !== 'LEAVE' ? (
              <button
                onClick={handleClockInAction}
                disabled={loadingLoc}
                className="w-full py-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-3xl font-black text-xl shadow-2xl shadow-indigo-100 transition-all transform active:scale-95 disabled:opacity-50"
              >
                {loadingLoc ? 'MENGECEK LOKASI...' : 'ABSEN MASUK SEKARANG'}
              </button>
            ) : todayRecord?.status === 'LEAVE' ? (
              <div className="p-8 bg-purple-50 text-purple-700 rounded-[32px] font-black border border-purple-100 shadow-inner">
                 <p className="text-lg">HARI INI ANDA IZIN (OFF)</p>
                 <p className="text-[10px] uppercase mt-1 opacity-60 italic">Nikmati waktu istirahat Anda</p>
              </div>
            ) : !todayRecord?.clockOut ? (
              <button
                onClick={onClockOut}
                className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-3xl font-black text-xl shadow-2xl shadow-orange-100 transition-all active:scale-95"
              >
                ABSEN KELUAR (PULANG)
              </button>
            ) : (
              <div className="p-8 bg-green-50 text-green-700 rounded-[32px] font-black border border-green-100 shadow-inner">
                TUGAS HARI INI SELESAI! ✅
                <p className="text-[10px] uppercase mt-1 opacity-60">Kembali lagi besok pagi</p>
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
              <div className="p-5 bg-white rounded-3xl border border-slate-100 flex flex-col items-center">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Sisa Jatah Libur</p>
                <p className="text-2xl font-black text-indigo-600">{sisaLibur}x</p>
              </div>
              <div className="p-5 bg-white rounded-3xl border border-slate-100 flex flex-col items-center">
                <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Status Lokasi</p>
                <p className="text-2xl font-black text-slate-900">{distance ? 'OK' : '--'}</p>
              </div>
          </div>

          {errorLoc && <p className="mt-6 text-xs font-bold text-red-500 bg-red-50 p-4 rounded-2xl border border-red-100">{errorLoc}</p>}
        </div>

        {/* Form Izin - Putih Terang */}
        <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm">
          <h3 className="font-black text-2xl text-slate-900 mb-8 flex items-center">
             <span className="w-2 h-6 bg-purple-500 rounded-full mr-3"></span>
             Ajukan Izin
          </h3>
          <div className="space-y-5">
            <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Kapan Anda Berencana Libur?</label>
                <input 
                type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)}
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-2 focus:ring-purple-500 font-black text-slate-700 transition-all"
                min={today}
                />
            </div>
            <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Apa Alasan Anda?</label>
                <textarea 
                placeholder="Berikan alasan yang jelas..." value={leaveReason} onChange={e => setLeaveReason(e.target.value)}
                className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-2 focus:ring-purple-500 min-h-[140px] font-medium text-slate-700"
                />
            </div>
            <button 
              onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason); setLeaveDate(''); setLeaveReason(''); } }}
              className="w-full bg-purple-600 text-white py-5 rounded-3xl font-black hover:bg-purple-700 shadow-xl shadow-purple-50 transition-all active:scale-95"
            >
              KIRIM PENGAJUAN IZIN
            </button>
          </div>
        </div>
      </div>

      {/* Kolom Riwayat Kehadiran */}
      <div className="lg:col-span-7 space-y-8">
        <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm min-h-[700px]">
          <h2 className="text-2xl font-black text-slate-900 mb-10 flex items-center">
            <span className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center mr-4 text-xl">🗓️</span> 
            Riwayat Aktivitas Bulanan
          </h2>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="text-[10px] font-black uppercase text-slate-400 tracking-widest border-b border-slate-50">
                <tr>
                  <th className="pb-8 pl-4">Hari/Tanggal</th>
                  <th className="pb-8">Masuk</th>
                  <th className="pb-8">Keluar</th>
                  <th className="pb-8 pr-4">Keterangan</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {attendance.filter(a => a.userId === user.id).length === 0 && (
                  <tr><td colSpan={4} className="py-24 text-center text-slate-400 font-bold italic bg-slate-50/20 rounded-[40px]">Belum ada data kehadiran untuk bulan ini.</td></tr>
                )}
                {attendance.filter(a => a.userId === user.id).sort((a,b) => b.date.localeCompare(a.date)).map(a => (
                  <tr key={a.id} className="group hover:bg-slate-50/50 transition-all">
                    <td className="py-6 pl-4 font-black text-slate-800">{a.date}</td>
                    <td className="py-6 text-slate-500 font-black">{a.clockIn || '--:--'}</td>
                    <td className="py-6 text-slate-500 font-black">{a.clockOut || '--:--'}</td>
                    <td className="py-6 pr-4">
                      <span className={`px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-wider ${
                        a.status === 'PRESENT' ? 'bg-green-100 text-green-700' : 'bg-purple-100 text-purple-700'
                      }`}>
                        {a.status === 'LEAVE' ? 'OFF (IZIN)' : 'HADIR'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeDashboard;

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');
  const [filterDate, setFilterDate] = useState(new Date().toISOString().split('T')[0]);

  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ name: '', username: '', password: '', gapok: 0, uangMakan: 0 });

  const [tempConfig, setTempConfig] = useState(outletConfig);

  const getRemainingLeave = (userId: string) => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    const approvedLeaves = leaveRequests.filter(l => 
      l.userId === userId && 
      l.status === 'APPROVED' && 
      new Date(l.date).getMonth() === currentMonth &&
      new Date(l.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - approvedLeaves);
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();

    doc.setFontSize(20);
    doc.text("Laporan Kehadiran DamDam Laundry", 14, 22);
    doc.setFontSize(11);
    doc.setTextColor(100);
    doc.text(`Tanggal Laporan: ${filterDate}`, 14, 30);

    const mergedData = getMergedAttendance();
    const tableData = mergedData.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.type === 'ATTENDANCE' ? (item.clockIn || '-') : '-',
      item.type === 'ATTENDANCE' ? (item.clockOut || '-') : '-',
      item.statusText
    ]);

    (doc as any).autoTable({
      startY: 40,
      head: [['Nama Karyawan', 'Jam Masuk', 'Jam Keluar', 'Status']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] }, // Indigo-600
    });

    doc.save(`absensi_damdam_${filterDate}.pdf`);
  };

  const getMergedAttendance = () => {
    const dailyAtt = attendance.filter(a => a.date === filterDate);
    const dailyLeaves = leaveRequests.filter(l => l.date === filterDate);

    const combined: any[] = [];

    // Add normal attendance
    dailyAtt.forEach(a => {
      combined.push({
        ...a,
        type: 'ATTENDANCE',
        statusText: a.status === 'PRESENT' ? 'HADIR' : 'ABSEN'
      });
    });

    // Add leaves that don't have attendance records yet
    dailyLeaves.forEach(l => {
      const alreadyIn = combined.find(c => c.userId === l.userId);
      if (!alreadyIn) {
        let statusText = 'IZIN (PENDING)';
        if (l.status === 'APPROVED') statusText = 'IZIN (DISETUJUI)';
        if (l.status === 'REJECTED') statusText = 'IZIN (DITOLAK)';

        combined.push({
          userId: l.userId,
          type: 'LEAVE',
          statusText: statusText
        });
      }
    });

    return combined;
  };

  const getPayrollForUser = (user: User) => {
    const end = new Date();
    const start = new Date();
    start.setDate(end.getDate() - 7);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end);
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`w-full flex items-center space-x-3 px-4 py-4 rounded-2xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'
      }`}
    >
      <span className="text-xl">{icon}</span>
      <span className="font-bold text-sm tracking-tight">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-8">
      <aside className="w-full md:w-64 space-y-2">
        <SidebarItem icon="📊" label="Dashboard" id="dashboard" />
        <SidebarItem icon="👥" label="Karyawan" id="employees" />
        <SidebarItem icon="📅" label="Absensi" id="attendance" />
        <SidebarItem icon="💰" label="Payroll" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      <div className="flex-1 bg-white rounded-[40px] border border-slate-100 shadow-sm p-10 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Ikhtisar Bisnis</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="bg-white border border-slate-100 p-8 rounded-3xl shadow-sm">
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-2">Total Staf</p>
                <p className="text-4xl font-black text-slate-900">{employees.filter(e => e.role === UserRole.EMPLOYEE).length}</p>
              </div>
              <div className="bg-white border border-slate-100 p-8 rounded-3xl shadow-sm">
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-2">Hadir (Hari Ini)</p>
                <p className="text-4xl font-black text-indigo-600">
                  {attendance.filter(a => a.date === new Date().toISOString().split('T')[0] && a.status === 'PRESENT').length}
                </p>
              </div>
              <div className="bg-white border border-slate-100 p-8 rounded-3xl shadow-sm">
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-2">Izin Pending</p>
                <p className="text-4xl font-black text-purple-600">{leaveRequests.filter(l => l.status === 'PENDING').length}</p>
              </div>
            </div>

            <section>
              <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center">
                <span className="w-2 h-6 bg-purple-500 rounded-full mr-3"></span>
                Persetujuan Izin
              </h3>
              <div className="space-y-4">
                {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                    const sisaLibur = getRemainingLeave(l.userId);
                    return (
                      <div key={l.id} className="flex flex-col md:flex-row md:items-center justify-between p-6 bg-white rounded-3xl border border-slate-100 shadow-sm gap-6">
                        <div className="flex-1">
                          <div className="flex items-center space-x-3 mb-1">
                            <p className="font-black text-slate-900 text-lg">{employees.find(e => e.id === l.userId)?.name}</p>
                            <span className={`text-[10px] px-3 py-1 rounded-full font-black ${sisaLibur > 0 ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                                Sisa Jatah: {sisaLibur}x
                            </span>
                          </div>
                          <p className="text-sm text-slate-500 font-medium"><span className="text-indigo-600 font-bold">{l.date}</span> — "{l.reason}"</p>
                        </div>
                        <div className="flex space-x-3">
                          <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="flex-1 md:flex-none bg-green-500 text-white px-8 py-3 rounded-2xl text-xs font-black hover:bg-green-600 shadow-lg shadow-green-50 transition-all">SETUJUI</button>
                          <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="flex-1 md:flex-none bg-white text-red-500 border border-red-100 px-8 py-3 rounded-2xl text-xs font-black hover:bg-red-50 transition-all">TOLAK</button>
                        </div>
                      </div>
                    );
                })}
                {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && (
                  <div className="text-center py-16 bg-white border-2 border-dashed border-slate-100 rounded-[40px]">
                    <p className="text-slate-400 font-bold">Tidak ada pengajuan izin saat ini.</p>
                  </div>
                )}
              </div>
            </section>
          </div>
        )}

        {activeMenu === 'employees' && (
          <div className="space-y-8">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Manajemen Staf</h2>
              <button 
                onClick={() => { setEditingEmp(null); setEmpForm({ name: '', username: '', password: '', gapok: 0, uangMakan: 0 }); setShowEmpModal(true); }}
                className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all"
              >
                + Tambah Staf
              </button>
            </div>

            <div className="overflow-x-auto border border-slate-50 rounded-[32px] shadow-sm">
              <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50 border-b border-slate-100 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nama & Info</th>
                    <th className="px-8 py-6">Sisa Libur</th>
                    <th className="px-8 py-6">Gapok / Bln</th>
                    <th className="px-8 py-6">Uang Makan / Bln</th>
                    <th className="px-8 py-6 text-right">Aksi</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm">
                  {employees.filter(e => e.role === UserRole.EMPLOYEE).map(e => (
                    <tr key={e.id} className="hover:bg-slate-50/30 transition-colors group">
                      <td className="px-8 py-6">
                        <p className="font-black text-slate-800">{e.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">@{e.username}</p>
                      </td>
                      <td className="px-8 py-6 font-black text-indigo-600">{getRemainingLeave(e.id)} / {FREE_LEAVE_QUOTA}x</td>
                      <td className="px-8 py-6 text-slate-600 font-bold italic">Rp {e.gapok.toLocaleString('id-ID')}</td>
                      <td className="px-8 py-6 text-slate-600 font-bold italic">Rp {e.uangMakan.toLocaleString('id-ID')}</td>
                      <td className="px-8 py-6 text-right space-x-4">
                        <button onClick={() => { setEditingEmp(e); setEmpForm(e); setShowEmpModal(true); }} className="text-indigo-600 font-black text-xs hover:bg-indigo-50 px-3 py-1 rounded-lg">Edit</button>
                        <button onClick={() => onDeleteEmployee(e.id)} className="text-red-500 font-black text-xs hover:bg-red-50 px-3 py-1 rounded-lg">Hapus</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeMenu === 'attendance' && (
          <div className="space-y-8">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Log Kehadiran</h2>
              <div className="flex items-center space-x-4">
                <input 
                  type="date" 
                  value={filterDate}
                  onChange={(e) => setFilterDate(e.target.value)}
                  className="p-4 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-slate-700 shadow-sm"
                />
                <button 
                  onClick={exportAttendanceToPDF}
                  className="bg-white border border-red-200 text-red-600 px-6 py-4 rounded-2xl font-black shadow-sm hover:bg-red-50 flex items-center transition-all"
                >
                  <span className="mr-2">📄</span> PDF EXPORT
                </button>
              </div>
            </div>

            <div className="overflow-x-auto border border-slate-50 rounded-[32px] shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-100 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Staf</th>
                    <th className="px-8 py-6">Jam Masuk</th>
                    <th className="px-8 py-6">Jam Keluar</th>
                    <th className="px-8 py-6">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm">
                  {getMergedAttendance().length === 0 && (
                    <tr><td colSpan={4} className="px-8 py-20 text-center text-slate-400 font-bold italic">Tidak ada aktivitas pada tanggal ini.</td></tr>
                  )}
                  {getMergedAttendance().map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/30 transition-colors">
                      <td className="px-8 py-6 font-black text-slate-800">{employees.find(e => e.id === item.userId)?.name}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.clockIn || '--'}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.clockOut || '--'}</td>
                      <td className="px-8 py-6">
                        <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                          item.statusText === 'HADIR' ? 'bg-green-100 text-green-700' : 
                          item.statusText.includes('IZIN') ? 'bg-purple-100 text-purple-700' : 'bg-red-100 text-red-700'
                        }`}>
                          {item.statusText}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <p className="text-[10px] text-slate-400 font-bold italic text-center">** Status izin muncul sejak diajukan hingga disetujui/ditolak owner.</p>
          </div>
        )}

        {activeMenu === 'payroll' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Laporan Payroll</h2>
            <div className="p-6 bg-indigo-50 border border-indigo-100 rounded-3xl text-indigo-700 text-sm font-medium">
                Sistem menghitung gaji harian <strong>(Gaji+Makan / {DAYS_IN_MONTH})</strong>. Izin di luar jatah 3x/bulan akan memotong gaji harian secara otomatis.
            </div>
            <div className="grid grid-cols-1 gap-6">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => {
                const report = getPayrollForUser(emp);
                const dailyRate = (emp.gapok + emp.uangMakan) / DAYS_IN_MONTH;
                return (
                  <div key={emp.id} className="p-8 bg-white border border-slate-100 rounded-[32px] flex flex-col md:flex-row md:items-center justify-between gap-8 hover:shadow-xl hover:shadow-slate-100 transition-all border-l-4 border-l-indigo-600">
                    <div>
                      <h4 className="text-xl font-black text-slate-900 mb-2">{emp.name}</h4>
                      <div className="flex flex-wrap gap-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                         <span className="bg-slate-50 px-3 py-1 rounded-full">Hadir: <span className="text-indigo-600">{report.totalPresent}</span></span>
                         <span className="bg-slate-50 px-3 py-1 rounded-full">Izin: <span className="text-purple-600">{report.totalLeave}</span></span>
                         <span className="bg-red-50 px-3 py-1 rounded-full text-red-500">Potongan Izin: {report.excessLeaveCount}</span>
                      </div>
                    </div>
                    <div className="flex items-center gap-10">
                      <div className="text-right">
                        <p className="text-[10px] text-slate-400 font-black uppercase mb-1">Rate Harian</p>
                        <p className="font-bold text-slate-700">Rp {Math.round(dailyRate).toLocaleString('id-ID')}</p>
                      </div>
                      <div className="text-right border-l-2 pl-10 border-slate-50">
                        <p className="text-[10px] text-indigo-400 font-black uppercase mb-1">Take Home Pay</p>
                        <p className="text-3xl font-black text-indigo-700">Rp {report.netSalary.toLocaleString('id-ID')}</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeMenu === 'settings' && (
          <div className="max-w-2xl space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Titik Lokasi Laundry</h2>
            <div className="space-y-8 bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Latitude</label>
                    <input 
                    type="number" value={tempConfig.latitude} 
                    onChange={e => setTempConfig({...tempConfig, latitude: parseFloat(e.target.value)})}
                    className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-800"
                    />
                  </div>
                  <div className="space-y-2">
