                 <input placeholder="E.g. Siti Aminah" value={empForm.name} onChange={e => setEmpForm({...empForm, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold"/>
              </div>
              <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Username</label>
                    <input placeholder="username" value={empForm.username} onChange={e => setEmpForm({...empForm, username: e.target.value.toLowerCase().replace(/\s/g, '')})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold"/>
                  </div>
                  <div className="space-y-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Password</label>
                    <input type="text" placeholder="Min. 6 Karakter" value={empForm.password} onChange={e => setEmpForm({...empForm, password: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold"/>
                  </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Gaji Pokok / Bulan</label>
                  <input type="number" value={empForm.gapok} onChange={e => setEmpForm({...empForm, gapok: parseInt(e.target.value)})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-indigo-600"/>
                </div>
                <div className="space-y-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Uang Makan / Bulan</label>
                  <input type="number" value={empForm.uangMakan} onChange={e => setEmpForm({...empForm, uangMakan: parseInt(e.target.value)})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-green-600"/>
                </div>
              </div>
              <div className="flex space-x-4 pt-8">
                <button onClick={() => setShowEmpModal(false)} className="flex-1 bg-white border border-slate-200 py-4 rounded-2xl font-black text-slate-400 hover:bg-slate-50 transition-all">BATAL</button>
                <button onClick={() => { if (editingEmp) onEditEmployee({ ...editingEmp, ...empForm } as User); else onAddEmployee(empForm); setShowEmpModal(false); }} className="flex-1 bg-indigo-600 py-4 rounded-2xl font-black text-white hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all">SIMPAN DATA</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OwnerDashboard;

export enum UserRole {
  OWNER = 'OWNER',
  EMPLOYEE = 'EMPLOYEE'
}

export interface User {
  id: string;
  name: string;
  username: string;
  password?: string;
  role: UserRole;
  gapok: number; // Monthly basic salary
  uangMakan: number; // Monthly meal allowance
  isActive: boolean;
}

export interface AttendanceRecord {
  id: string;
  userId: string;
  date: string; // YYYY-MM-DD
  clockIn: string | null;
  clockOut: string | null;
  latitude: number;
  longitude: number;
  status: 'PRESENT' | 'LEAVE' | 'ABSENT';
}

export interface LeaveRequest {
  id: string;
  userId: string;
  date: string;
  reason: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
}

export interface OutletConfig {
  latitude: number;
  longitude: number;
  radius: number; // In meters
}

export interface PayrollReport {
  userId: string;
  userName: string;
  weekStartDate: string;
  weekEndDate: string;
  totalPresent: number;
  totalNotPresent: number; // Combined Leave + Absent
  excessDaysCount: number; // Days that actually trigger deduction
  dailyRate: number;
  grossSalary: number;
  deductions: number;
  bonus: number;
  manualDeduction: number;
  netSalary: number;
}

import { User, AttendanceRecord, PayrollReport } from '../types';
import { DAYS_IN_MONTH, FREE_LEAVE_QUOTA } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[],
  allRecordsThisMonth: AttendanceRecord[],
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  // Gaji harian = (Gapok + Uang Makan) / 30. Jika uang makan 0, maka otomatis Gapok/30.
  const dailyRate = (user.gapok + user.uangMakan) / DAYS_IN_MONTH;

  // Filter data untuk minggu ini
  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;

  // Karyawan masuk terus Senin-Minggu (7 hari). 
  // Hari tidak hadir adalah 7 dikurangi hari hadir.
  const totalNotPresentThisWeek = 7 - presentCount;

  // Hitung akumulasi hari tidak hadir (Izin + Alfa) dalam bulan ini untuk menentukan kuota 3x
  let excessDaysThisWeek = 0;
  let monthlyNotPresentCounter = 0;

  // Kita perlu mensimulasikan kalender bulan ini untuk tahu kapan kuota habis
  const monthStart = new Date(weekEnd.getFullYear(), weekEnd.getMonth(), 1);
  const daysInMonth = new Date(weekEnd.getFullYear(), weekEnd.getMonth() + 1, 0).getDate();

  for (let i = 1; i <= daysInMonth; i++) {
    const currentDateStr = `${weekEnd.getFullYear()}-${String(weekEnd.getMonth() + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
    const currentDate = new Date(currentDateStr);

    // Cari apakah ada record hadir di tanggal ini
    const record = allRecordsThisMonth.find(r => r.date === currentDateStr);
    const isPresent = record && record.status === 'PRESENT';

    // Jika tidak hadir dan tanggal i <= tanggal akhir minggu ini
    if (!isPresent) {
      monthlyNotPresentCounter++;

      // Jika sudah melewati batas 3 hari, dan tanggal ini masuk dalam rentang minggu payroll
      if (monthlyNotPresentCounter > FREE_LEAVE_QUOTA) {
        if (currentDate >= weekStart && currentDate <= weekEnd) {
          excessDaysThisWeek++;
        }
      }
    }

    // Berhenti jika sudah melewati akhir minggu payroll
    if (currentDate > weekEnd) break;
  }

  const weeklyGross = dailyRate * 7;
  const attendanceDeduction = excessDaysThisWeek * dailyRate;
  const totalDeductions = attendanceDeduction + manualDeduction;

  const netSalary = Math.max(0, weeklyGross + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalNotPresent: totalNotPresentThisWeek,
    excessDaysCount: excessDaysThisWeek,
    dailyRate: dailyRate,
    grossSalary: weeklyGross,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary
  };
};

import React, { useState, useMemo, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollReport } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');

  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);

  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');

  const [adjustments, setAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ name: '', username: '', password: '', gapok: 0, uangMakan: 0 });

  const [tempConfig, setTempConfig] = useState(outletConfig);

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);

    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  const getRemainingLeave = (userId: string) => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    const approvedNotPresent = attendance.filter(a => 
      a.userId === userId && 
      a.status !== 'PRESENT' && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - approvedNotPresent);
  };

  const handleAdjustmentChange = (userId: string, field: 'bonus' | 'deduction', value: string) => {
    const numValue = parseInt(value) || 0;
    setAdjustments(prev => ({
      ...prev,
      [userId]: {
        ...(prev[userId] || { bonus: 0, deduction: 0 }),
        [field]: numValue
      }
    }));
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Laporan Kehadiran DamDam Laundry", 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periode: ${attStartDate} s/d ${attEndDate}`, 14, 28);
    const mergedData = getMergedAttendance();
    const tableData = mergedData.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.date || '-',
      item.type === 'ATTENDANCE' ? (item.clockIn || '-') : '-',
      item.type === 'ATTENDANCE' ? (item.clockOut || '-') : '-',
      item.statusText
    ]);
    (doc as any).autoTable({
      startY: 35,
      head: [['Nama Karyawan', 'Tanggal', 'Jam Masuk', 'Jam Keluar', 'Status']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`absensi_damdam_${attStartDate}_to_${attEndDate}.pdf`);
  };

  const exportPayrollToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Rekap Laporan Payroll - DamDam Laundry", 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periode: ${payStartDate} s/d ${payEndDate}`, 14, 28);

    const payrollData = employees
      .filter(e => e.role === UserRole.EMPLOYEE)
      .map(emp => {
        const report = getPayrollForUser(emp);
        return [
          emp.name,
          `Rp ${report.grossSalary.toLocaleString('id-ID')}`,
          `Rp ${report.bonus.toLocaleString('id-ID')}`,
          `Rp ${report.deductions.toLocaleString('id-ID')}`,
          `Rp ${report.netSalary.toLocaleString('id-ID')}`
        ];
      });

    (doc as any).autoTable({
      startY: 35,
      head: [['Nama Karyawan', 'Gaji Kotor (7 Hari)', 'Bonus', 'Total Potongan', 'Gaji Bersih']],
      body: payrollData,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`rekap_payroll_damdam_${payEndDate}.pdf`);
  };

  const exportIndividualSlipPDF = (emp: User) => {
    const { jsPDF } = (window as any).jspdf;
    const report = getPayrollForUser(emp);
    const doc = new jsPDF();

    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(12);
    doc.setTextColor(100);
    doc.text("SLIP GAJI MINGGUAN", 105, 28, { align: 'center' });
    doc.setDrawColor(230);
    doc.line(14, 35, 196, 35);

    doc.setFontSize(10);
    doc.setTextColor(50);
    doc.setFont(undefined, 'bold');
    doc.text("DETAIL KARYAWAN", 14, 45);
    doc.setFont(undefined, 'normal');
    doc.text(`Nama: ${emp.name}`, 14, 52);
    doc.text(`Periode: ${payStartDate} s/d ${payEndDate}`, 14, 58);
    doc.text(`Rate Harian (Gapok+Makan / 30): Rp ${Math.round(report.dailyRate).toLocaleString('id-ID')}`, 14, 64);

    const attendanceDeduction = report.excessDaysCount * report.dailyRate;

    (doc as any).autoTable({
      startY: 75,
      head: [['DESKRIPSI PENDAPATAN', 'JUMLAH']],
      body: [
        ['Gaji Mingguan (Full 7 Hari)', `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus', `Rp ${report.bonus.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    (doc as any).autoTable({
      startY: (doc as any).lastAutoTable.finalY + 10,
      head: [['DESKRIPSI POTONGAN', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Potongan Absen / Izin Berlebih', `${report.excessDaysCount} Hari (>3x)`, `Rp ${attendanceDeduction.toLocaleString('id-ID')}`],
        ['Potongan Lainnya', '-', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [239, 68, 68] },
      columnStyles: { 2: { halign: 'right' } }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.setFont(undefined, 'bold');
    doc.setTextColor(0);
    doc.text("TOTAL GAJI DITERIMA", 14, finalY);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rp ${report.netSalary.toLocaleString('id-ID')}`, 196, finalY, { align: 'right' });

    doc.setFontSize(8);
    doc.setTextColor(150);
    doc.text("* Jatah libur 3x/bulan tanpa potong gaji. Pelanggaran dipotong rate harian.", 14, finalY + 15);

    doc.save(`slip_${emp.name.toLowerCase().replace(/\s+/g, '_')}_${payEndDate}.pdf`);
  };

  const getMergedAttendance = () => {
    const start = new Date(attStartDate);
    const end = new Date(attEndDate);
    const dailyAtt = attendance.filter(a => {
      const d = new Date(a.date);
      return d >= start && d <= end;
    });
    const dailyLeaves = leaveRequests.filter(l => {
      const d = new Date(l.date);
      return d >= start && d <= end;
    });
    const combined: any[] = [];
    dailyAtt.forEach(a => {
      combined.push({ ...a, type: 'ATTENDANCE', statusText: a.status === 'PRESENT' ? 'HADIR' : 'ABSEN' });
    });
    dailyLeaves.forEach(l => {
      const alreadyIn = combined.find(c => c.userId === l.userId && c.date === l.date);
      if (!alreadyIn) {
        let statusText = 'IZIN (PENDING)';
        if (l.status === 'APPROVED') statusText = 'IZIN (DISETUJUI)';
        if (l.status === 'REJECTED') statusText = 'IZIN (DITOLAK)';
        combined.push({ userId: l.userId, date: l.date, type: 'LEAVE', statusText: statusText });
      }
    });
    return combined.sort((a, b) => b.date.localeCompare(a.date));
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate);
    const end = new Date(payEndDate);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const adj = adjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
