import React, { useState, useEffect } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  useEffect(() => {
    const savedUsers = localStorage.getItem('damdam_users');
    const savedAttendance = localStorage.getItem('damdam_attendance');
    const savedLeave = localStorage.getItem('damdam_leave');
    const savedConfig = localStorage.getItem('damdam_config');

    setUsers(savedUsers ? JSON.parse(savedUsers) : MOCK_USERS);
    if (savedAttendance) setAttendance(JSON.parse(savedAttendance));
    if (savedLeave) setLeaveRequests(JSON.parse(savedLeave));
    if (savedConfig) setOutletConfig(JSON.parse(savedConfig));
  }, []);

  useEffect(() => {
    if (users.length > 0) localStorage.setItem('damdam_users', JSON.stringify(users));
    localStorage.setItem('damdam_attendance', JSON.stringify(attendance));
    localStorage.setItem('damdam_leave', JSON.stringify(leaveRequests));
    localStorage.setItem('damdam_config', JSON.stringify(outletConfig));
  }, [users, attendance, leaveRequests, outletConfig]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    const user = users.find(u => u.username === loginUsername && u.password === loginPassword);
    if (user) {
      setCurrentUser(user);
      setLoginUsername('');
      setLoginPassword('');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => setCurrentUser(null);

  const handleAddEmployee = (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      isActive: true
    };
    setUsers(prev => [...prev, newUser]);
  };

  const handleEditEmployee = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
  };

  const handleDeleteEmployee = (userId: string) => {
    if (confirm('Hapus karyawan ini? Data absensi akan tetap ada.')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
    }
  };

  const handleClockIn = (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const currentTimeStr = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    // Check if late
    const [nowH, nowM] = currentTimeStr.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: currentTimeStr,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };
    setAttendance(prev => [...prev, newRecord]);
  };

  const handleClockOut = () => {
    if (!currentUser) return;
    const today = new Date().toISOString().split('T')[0];
    const now = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === today) ? { ...a, clockOut: now } : a
    ));
  };

  const handleSubmitLeave = (date: string, reason: string) => {
    if (!currentUser) return;
    const newLeave: LeaveRequest = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING'
    };
    setLeaveRequests(prev => [...prev, newLeave]);
  };

  const handleApproveLeave = (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    if (status === 'APPROVED') {
      const leave = leaveRequests.find(l => l.id === leaveId);
      if (leave) {
        setAttendance(prev => {
          const filtered = prev.filter(a => !(a.userId === leave.userId && a.date === leave.date));
          const leaveRecord: AttendanceRecord = {
            id: Math.random().toString(36).substr(2, 9),
            userId: leave.userId,
            date: leave.date,
            clockIn: null,
            clockOut: null,
            latitude: 0,
            longitude: 0,
            status: 'LEAVE'
          };
          return [...filtered, leaveRecord];
        });
      }
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl rotate-3">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-slate-400 font-bold uppercase tracking-tighter text-[10px] mt-1">Management System</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Username</label>
              <input 
                type="text" 
                value={loginUsername}
                onChange={e => setLoginUsername(e.target.value)}
                className="w-full p-4 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-700 transition-all" 
                placeholder="masukkan username"
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Password</label>
              <input 
                type="password" 
                value={loginPassword}
                onChange={e => setLoginPassword(e.target.value)}
                className="w-full p-4 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-700 transition-all" 
                placeholder="••••••••"
                required
              />
            </div>
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center bg-red-50 py-2 rounded-lg">{loginError}</p>}
            <button 
              type="submit"
              className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all transform hover:-translate-y-1 active:translate-y-0"
            >
              MASUK KE SISTEM
            </button>
          </form>

          <div className="mt-12 pt-8 border-t border-slate-50 text-center">
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-3 italic">Demo Akun:</p>
            <div className="inline-block text-left text-[10px] bg-slate-50 p-4 rounded-2xl font-bold text-slate-500">
               <p>Owner: owner / 123</p>
               <p>Karyawan: budi / 123</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser}
          outletConfig={outletConfig}
          attendance={attendance}
          leaveRequests={leaveRequests}
          onClockIn={handleClockIn}
          onClockOut={handleClockOut}
          onSubmitLeave={handleSubmitLeave}
        />
      ) : (
        <OwnerDashboard 
          employees={users}
          attendance={attendance}
          leaveRequests={leaveRequests}
          outletConfig={outletConfig}
          onUpdateConfig={setOutletConfig}
          onApproveLeave={handleApproveLeave}
          onAddEmployee={handleAddEmployee}
          onEditEmployee={handleEditEmployee}
          onDeleteEmployee={handleDeleteEmployee}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [distance, setDistance] = useState<number | null>(null);
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  const getStats = () => {
    const userAttendance = attendance.filter(a => a.userId === user.id);
    const userLeaves = leaveRequests.filter(l => l.userId === user.id && l.status === 'APPROVED');

    const late = userAttendance.filter(a => a.status === 'PRESENT' && a.isLate).length;
    const onTime = userAttendance.filter(a => a.status === 'PRESENT' && !a.isLate).length;

    return {
      late,
      onTime,
      leave: userLeaves.length,
      remainingLeave: Math.max(0, FREE_LEAVE_QUOTA - userLeaves.length)
    };
  };

  const getMergedHistory = () => {
    const userAttendance = attendance.filter(a => a.userId === user.id);
    const userLeaves = leaveRequests.filter(l => l.userId === user.id);

    const history: any[] = [];
    userAttendance.forEach(a => {
      let statusText = a.status === 'PRESENT' ? (a.isLate ? 'TERLAMBAT' : 'TEPAT WAKTU') : 'ABSEN';
      history.push({
        date: a.date,
        clockIn: a.clockIn,
        clockOut: a.clockOut,
        statusText: statusText,
        isLate: a.isLate,
        rawDate: new Date(a.date)
      });
    });

    userLeaves.forEach(l => {
      const existing = history.find(h => h.date === l.date);
      if (!existing) {
        let statusText = 'IZIN (PENDING)';
        if (l.status === 'APPROVED') statusText = 'IZIN (DISETUJUI)';
        if (l.status === 'REJECTED') statusText = 'IZIN (DITOLAK)';

        history.push({
          date: l.date,
          clockIn: '--:--',
          clockOut: '--:--',
          statusText: statusText,
          rawDate: new Date(l.date)
        });
      }
    });

    return history.sort((a, b) => b.rawDate.getTime() - a.rawDate.getTime());
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      setDistance(dist);
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Gagal: Lokasi Anda ${Math.round(dist)}m dari titik pusat. Batas maksimal ${outletConfig.radius}m.`);
      }
    } catch (err) {
      setErrorLoc("Akses lokasi ditolak. Harap aktifkan GPS Anda.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const stats = getStats();
  const mergedHistory = getMergedHistory();

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
      <div className="lg:col-span-5 space-y-8">
        <div className="bg-white p-12 rounded-[48px] border border-slate-100 shadow-sm text-center">
          <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 text-4xl shadow-sm rotate-6 hover:rotate-0 transition-all duration-500">
            🧺
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Halo, {user.name.split(' ')[0]}!</h2>
          <p className="text-slate-400 text-sm mb-10 font-bold uppercase tracking-widest">
            {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' })}
          </p>

          <div className="mb-10">
            {!todayRecord?.clockIn && todayRecord?.status !== 'LEAVE' ? (
              <button
                onClick={handleClockInAction}
                disabled={loadingLoc}
                className="w-full py-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-3xl font-black text-xl shadow-2xl shadow-indigo-100 transition-all transform active:scale-95 disabled:opacity-50"
              >
                {loadingLoc ? 'MENGECEK LOKASI...' : 'ABSEN MASUK SEKARANG'}
              </button>
            ) : todayRecord?.status === 'LEAVE' ? (
              <div className="p-8 bg-purple-50 text-purple-700 rounded-[32px] font-black border border-purple-100 shadow-inner">
                 <p className="text-lg">HARI INI ANDA IZIN (OFF)</p>
              </div>
            ) : !todayRecord?.clockOut ? (
              <button
                onClick={onClockOut}
                className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-3xl font-black text-xl shadow-2xl shadow-orange-100 transition-all active:scale-95"
              >
                ABSEN KELUAR (PULANG)
              </button>
            ) : (
              <div className="p-8 bg-green-50 text-green-700 rounded-[32px] font-black border border-green-100 shadow-inner">
                TUGAS HARI INI SELESAI! ✅
              </div>
            )}
          </div>

          <div className="grid grid-cols-3 gap-3">
              <div className="p-4 bg-green-50 rounded-2xl border border-green-100 flex flex-col items-center">
                <p className="text-[8px] font-black text-green-600 uppercase mb-1">Tepat Waktu</p>
                <p className="text-xl font-black text-green-700">{stats.onTime}</p>
              </div>
              <div className="p-4 bg-yellow-50 rounded-2xl border border-yellow-100 flex flex-col items-center">
                <p className="text-[8px] font-black text-yellow-600 uppercase mb-1">Terlambat</p>
                <p className="text-xl font-black text-yellow-700">{stats.late}</p>
              </div>
              <div className="p-4 bg-purple-50 rounded-2xl border border-purple-100 flex flex-col items-center">
                <p className="text-[8px] font-black text-purple-600 uppercase mb-1">Izin</p>
                <p className="text-xl font-black text-purple-700">{stats.leave}</p>
              </div>
          </div>

          {errorLoc && <p className="mt-6 text-xs font-bold text-red-500 bg-red-50 p-4 rounded-2xl border border-red-100">{errorLoc}</p>}
        </div>

        <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm">
          <h3 className="font-black text-2xl text-slate-900 mb-8 flex items-center">
             <span className="w-2 h-6 bg-purple-500 rounded-full mr-3"></span>
             Ajukan Izin
          </h3>
          <div className="space-y-5">
            <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Kapan Anda Berencana Libur?</label>
                <input 
                  type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)}
                  className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-2 focus:ring-purple-500 font-black text-slate-700 transition-all appearance-none"
                  min={today}
                />
            </div>
            <div className="space-y-2">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Apa Alasan Anda?</label>
                <textarea 
                  placeholder="Berikan alasan yang jelas..." value={leaveReason} onChange={e => setLeaveReason(e.target.value)}
                  className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-2 focus:ring-purple-500 min-h-[140px] font-medium text-slate-700"
                />
            </div>
            <button 
              onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason); setLeaveDate(''); setLeaveReason(''); } }}
              className="w-full bg-purple-600 text-white py-5 rounded-3xl font-black hover:bg-purple-700 shadow-xl shadow-purple-50 transition-all active:scale-95"
            >
              KIRIM PENGAJUAN IZIN
            </button>
          </div>
        </div>
      </div>

      <div className="lg:col-span-7 space-y-8">
        <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm min-h-[700px]">
          <h2 className="text-2xl font-black text-slate-900 mb-10 flex items-center">
            <span className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center mr-4 text-xl">🗓️</span> 
            Riwayat Aktivitas Bulanan
          </h2>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="text-[10px] font-black uppercase text-slate-400 tracking-widest border-b border-slate-50">
                <tr>
                  <th className="pb-8 pl-4">Hari/Tanggal</th>
                  <th className="pb-8">Masuk</th>
                  <th className="pb-8">Keluar</th>
                  <th className="pb-8 pr-4">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {mergedHistory.length === 0 && (
                  <tr><td colSpan={4} className="py-24 text-center text-slate-400 font-bold italic bg-slate-50/20 rounded-[40px]">Belum ada data aktivitas untuk bulan ini.</td></tr>
                )}
                {mergedHistory.map((item, idx) => (
                  <tr key={idx} className="group hover:bg-slate-50/50 transition-all">
                    <td className="py-6 pl-4 font-black text-slate-800">{item.date}</td>
                    <td className="py-6 text-slate-500 font-black">{item.clockIn || '--:--'}</td>
                    <td className="py-6 text-slate-500 font-black">{item.clockOut || '--:--'}</td>
                    <td className="py-6 pr-4">
                      <span className={`px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-wider ${
                        item.statusText === 'TEPAT WAKTU' ? 'bg-green-100 text-green-700' : 
                        item.statusText === 'TERLAMBAT' ? 'bg-yellow-100 text-yellow-700' :
                        item.statusText.includes('IZIN') ? 'bg-purple-100 text-purple-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {item.statusText}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeDashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollReport } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');

  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);

  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');

  const [adjustments, setAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ name: '', username: '', password: '', gapok: 0, uangMakan: 0 });

  const [tempConfig, setTempConfig] = useState(outletConfig);

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);

    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  const getRemainingLeave = (userId: string) => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    const approvedNotPresent = attendance.filter(a => 
      a.userId === userId && 
      a.status !== 'PRESENT' && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - approvedNotPresent);
  };

  const handleAdjustmentChange = (userId: string, field: 'bonus' | 'deduction', value: string) => {
    const numValue = parseInt(value) || 0;
    setAdjustments(prev => ({
      ...prev,
      [userId]: {
        ...(prev[userId] || { bonus: 0, deduction: 0 }),
        [field]: numValue
      }
    }));
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Laporan Kehadiran DamDam Laundry", 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periode: ${attStartDate} s/d ${attEndDate}`, 14, 28);

    const mergedData = getMergedAttendance();
    const tableData = mergedData.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.date || '-',
      item.type === 'ATTENDANCE' ? (item.clockIn || '-') : '-',
      item.type === 'ATTENDANCE' ? (item.clockOut || '-') : '-',
      item.statusText
    ]);

    (doc as any).autoTable({
      startY: 35,
      head: [['Nama Karyawan', 'Tanggal', 'Jam Masuk', 'Jam Keluar', 'Status']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`absensi_damdam_${attStartDate}_to_${attEndDate}.pdf`);
  };

  const exportPayrollToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Rekap Laporan Payroll - DamDam Laundry", 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periode: ${payStartDate} s/d ${payEndDate}`, 14, 28);

    const payrollData = employees
      .filter(e => e.role === UserRole.EMPLOYEE)
      .map(emp => {
        const report = getPayrollForUser(emp);
        return [
          emp.name,
          `Rp ${report.grossSalary.toLocaleString('id-ID')}`,
          `Rp ${report.bonus.toLocaleString('id-ID')}`,
          `Rp ${report.deductions.toLocaleString('id-ID')}`,
          `Rp ${report.netSalary.toLocaleString('id-ID')}`
        ];
      });

    (doc as any).autoTable({
      startY: 35,
      head: [['Nama Karyawan', 'Gaji Kotor (7 Hari)', 'Bonus', 'Total Potongan', 'Gaji Bersih']],
      body: payrollData,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`rekap_payroll_damdam_${payEndDate}.pdf`);
  };

  const exportIndividualSlipPDF = (emp: User) => {
    const { jsPDF } = (window as any).jspdf;
    const report = getPayrollForUser(emp);
    const doc = new jsPDF();

    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(12);
    doc.setTextColor(100);
    doc.text("SLIP GAJI MINGGUAN", 105, 28, { align: 'center' });
    doc.setDrawColor(230);
    doc.line(14, 35, 196, 35);

    doc.setFontSize(10);
    doc.setTextColor(50);
    doc.setFont(undefined, 'bold');
    doc.text("DETAIL KARYAWAN", 14, 45);
    doc.setFont(undefined, 'normal');
    doc.text(`Nama: ${emp.name}`, 14, 52);
    doc.text(`Periode: ${payStartDate} s/d ${payEndDate}`, 14, 58);
    doc.text(`Rate Harian (Gapok+Makan / 30): Rp ${Math.round(report.dailyRate).toLocaleString('id-ID')}`, 14, 64);

    const attendanceDeduction = report.excessDaysCount * report.dailyRate;

    (doc as any).autoTable({
      startY: 75,
      head: [['DESKRIPSI PENDAPATAN', 'JUMLAH']],
      body: [
        ['Gaji Mingguan (Full 7 Hari)', `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus', `Rp ${report.bonus.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      columnStyles: { 1: { halign: 'right' } }
    });

    (doc as any).autoTable({
      startY: (doc as any).lastAutoTable.finalY + 10,
      head: [['DESKRIPSI POTONGAN', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Potongan Absen / Izin Berlebih', `${report.excessDaysCount} Hari (>3x)`, `Rp ${attendanceDeduction.toLocaleString('id-ID')}`],
        ['Potongan Lainnya', '-', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [239, 68, 68] },
      columnStyles: { 2: { halign: 'right' } }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.setFont(undefined, 'bold');
    doc.setTextColor(0);
    doc.text("TOTAL GAJI DITERIMA", 14, finalY);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rp ${report.netSalary.toLocaleString('id-ID')}`, 196, finalY, { align: 'right' });

    doc.setFontSize(8);
    doc.setTextColor(150);
    doc.text("* Jatah libur 3x/bulan tanpa potong gaji. Pelanggaran dipotong rate harian.", 14, finalY + 15);

    doc.save(`slip_${emp.name.toLowerCase().replace(/\s+/g, '_')}_${payEndDate}.pdf`);
  };

  const getMergedAttendance = () => {
    const start = new Date(attStartDate);
    const end = new Date(attEndDate);
    const dailyAtt = attendance.filter(a => {
      const d = new Date(a.date);
      return d >= start && d <= end;
    });
    const dailyLeaves = leaveRequests.filter(l => {
      const d = new Date(l.date);
      return d >= start && d <= end;
    });
    const combined: any[] = [];
    dailyAtt.forEach(a => {
      let statusText = a.status === 'PRESENT' ? (a.isLate ? 'TERLAMBAT' : 'HADIR') : 'ABSEN';
      combined.push({ ...a, type: 'ATTENDANCE', statusText: statusText });
    });
    dailyLeaves.forEach(l => {
      const alreadyIn = combined.find(c => c.userId === l.userId && c.date === l.date);
      if (!alreadyIn) {
        let statusText = 'IZIN (PENDING)';
        if (l.status === 'APPROVED') statusText = 'IZIN (DISETUJUI)';
        if (l.status === 'REJECTED') statusText = 'IZIN (DITOLAK)';
        combined.push({ userId: l.userId, date: l.date, type: 'LEAVE', statusText: statusText });
      }
    });
    return combined.sort((a, b) => b.date.localeCompare(a.date));
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate);
    const end = new Date(payEndDate);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const adj = adjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`w-full flex items-center space-x-3 px-4 py-4 rounded-2xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'
      }`}
    >
      <span className="text-xl">{icon}</span>
      <span className="font-bold text-sm tracking-tight">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-8">
      <aside className="w-full md:w-64 space-y-2">
        <SidebarItem icon="📊" label="Dashboard" id="dashboard" />
        <SidebarItem icon="👥" label="Karyawan" id="employees" />
        <SidebarItem icon="📅" label="Absensi" id="attendance" />
        <SidebarItem icon="💰" label="Payroll" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      <div className="flex-1 bg-white rounded-[40px] border border-slate-100 shadow-sm p-10 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Ikhtisar Bisnis</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="bg-white border border-slate-100 p-8 rounded-3xl shadow-sm">
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-2">Total Staf</p>
                <p className="text-4xl font-black text-slate-900">{employees.filter(e => e.role === UserRole.EMPLOYEE).length}</p>
              </div>
              <div className="bg-white border border-slate-100 p-8 rounded-3xl shadow-sm">
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-2">Hadir (Hari Ini)</p>
                <p className="text-4xl font-black text-indigo-600">
                  {attendance.filter(a => a.date === new Date().toISOString().split('T')[0] && a.status === 'PRESENT').length}
                </p>
              </div>
              <div className="bg-white border border-slate-100 p-8 rounded-3xl shadow-sm">
                <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mb-2">Izin Pending</p>
                <p className="text-4xl font-black text-purple-600">{leaveRequests.filter(l => l.status === 'PENDING').length}</p>
              </div>
            </div>

            <section>
              <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center">
                <span className="w-2 h-6 bg-purple-500 rounded-full mr-3"></span>
                Persetujuan Izin
              </h3>
              <div className="space-y-4">
                {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                    const sisaLibur = getRemainingLeave(l.userId);
                    return (
                      <div key={l.id} className="flex flex-col md:flex-row md:items-center justify-between p-6 bg-white rounded-3xl border border-slate-100 shadow-sm gap-6">
                        <div className="flex-1">
                          <div className="flex items-center space-x-3 mb-1">
                            <p className="font-black text-slate-900 text-lg">{employees.find(e => e.id === l.userId)?.name}</p>
                            <span className={`text-[10px] px-3 py-1 rounded-full font-black ${sisaLibur > 0 ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                                Sisa Jatah: {sisaLibur}x
                            </span>
                          </div>
                          <p className="text-sm text-slate-500 font-medium"><span className="text-indigo-600 font-bold">{l.date}</span> — "{l.reason}"</p>
                        </div>
                        <div className="flex space-x-3">
                          <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="flex-1 md:flex-none bg-green-500 text-white px-8 py-3 rounded-2xl text-xs font-black hover:bg-green-600 shadow-lg shadow-green-50 transition-all">SETUJUI</button>
                          <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="flex-1 md:flex-none bg-white text-red-500 border border-red-100 px-8 py-3 rounded-2xl text-xs font-black hover:bg-red-50 transition-all">TOLAK</button>
                        </div>
                      </div>
                    );
                })}
              </div>
            </section>
          </div>
        )}

        {activeMenu === 'attendance' && (
          <div className="space-y-8">
            <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6 bg-slate-50 p-8 rounded-[32px] border border-slate-100">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 flex-1">
                <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Dari Tanggal</label><input type="date" value={attStartDate} onChange={(e) => setAttStartDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-slate-700 shadow-sm" /></div>
                <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Sampai Tanggal</label><input type="date" value={attEndDate} onChange={(e) => setAttEndDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-slate-700 shadow-sm" /></div>
              </div>
              <button onClick={exportAttendanceToPDF} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center h-[58px]"><span className="mr-2 text-lg">📄</span> EXPORT PDF</button>
            </div>
            <div className="overflow-x-auto border border-slate-50 rounded-[32px] shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-slate-50 border-b border-slate-100 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr><th className="px-8 py-6">Staf</th><th className="px-8 py-6">Tanggal</th><th className="px-8 py-6">Jam Masuk</th><th className="px-8 py-6">Jam Keluar</th><th className="px-8 py-6">Status</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm">
                  {getMergedAttendance().map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/30 transition-colors">
                      <td className="px-8 py-6 font-black text-slate-800">{employees.find(e => e.id === item.userId)?.name}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.date}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.clockIn || '--'}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.clockOut || '--'}</td>
                      <td className="px-8 py-6">
                        <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                          item.statusText === 'HADIR' ? 'bg-green-100 text-green-700' : 
                          item.statusText === 'TERLAMBAT' ? 'bg-yellow-100 text-yellow-700' :
                          item.statusText.includes('IZIN') ? 'bg-purple-100 text-purple-700' : 'bg-red-100 text-red-700'
                        }`}>{item.statusText}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeMenu === 'payroll' && (
          <div className="space-y-8">
            <div className="flex flex-col lg:flex-row lg:items-end justify-between gap-6 bg-slate-50 p-8 rounded-[40px] border border-slate-100">
               <div className="flex-1">
                  <h2 className="text-2xl font-black text-slate-900 tracking-tight mb-4">Atur Periode Gaji</h2>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Awal Periode</label><input type="date" value={payStartDate} onChange={(e) => setPayStartDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-slate-700 shadow-sm" /></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Akhir Periode (Payday)</label><input type="date" value={payEndDate} onChange={(e) => setPayEndDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-slate-700 shadow-sm" /></div>
                  </div>
               </div>
               <button onClick={exportPayrollToPDF} className="bg-red-600 text-white px-10 py-4 rounded-2xl font-black shadow-xl shadow-red-100 hover:bg-red-700 transition-all flex items-center h-[58px]"><span className="mr-2 text-lg">📂</span> REKAP PDF</button>
            </div>

            <div className="space-y-6">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => {
                const report = getPayrollForUser(emp);
                const adj = adjustments[emp.id] || { bonus: 0, deduction: 0 };
                return (
                  <div key={emp.id} className="p-8 bg-white border border-slate-100 rounded-[32px] hover:shadow-xl transition-all border-l-4 border-l-indigo-600 flex flex-col gap-8">
                    <div className="flex flex-col md:flex-row justify-between gap-6">
                      <div className="flex-1">
                        <div className="flex items-center justify-between mb-2">
                          <h4 className="text-xl font-black text-slate-900">{emp.name}</h4>
                          <button onClick={() => exportIndividualSlipPDF(emp)} className="text-indigo-600 text-[10px] font-black uppercase tracking-widest hover:bg-indigo-50 px-4 py-2 rounded-xl transition-all border border-indigo-100">📄 Cetak Slip Gaji</button>
                        </div>
                        <div className="flex flex-wrap gap-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                           <span className="bg-slate-50 px-3 py-1 rounded-full">Hadir: <span className="text-indigo-600">{report.totalPresent} Hari</span></span>
                           <span className={`px-3 py-1 rounded-full ${report.excessDaysCount > 0 ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>Pelanggaran Kuota: {report.excessDaysCount} Hari</span>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-[10px] text-slate-400 font-black uppercase mb-1">Take Home Pay</p>
                        <p className="text-3xl font-black text-indigo-700">Rp {report.netSalary.toLocaleString('id-ID')}</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeMenu === 'settings' && (
          <div className="max-w-2xl space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Konfigurasi Operasional</h2>
            <div className="space-y-8 bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Jam Masuk</label>
                  <input type="time" value={tempConfig.clockInTime} onChange={e => setTempConfig({...tempConfig, clockInTime: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-800" />
                </div>
                <div className="space-y-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Jam Pulang</label>
                  <input type="time" value={tempConfig.clockOutTime} onChange={e => setTempConfig({...tempConfig, clockOutTime: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-800" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Latitude</label><input type="number" value={tempConfig.latitude} onChange={e => setTempConfig({...tempConfig, latitude: parseFloat(e.target.value)})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-800"/></div>
                  <div className="space-y-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Longitude</label><input type="number" value={tempConfig.longitude} onChange={e => setTempConfig({...tempConfig, longitude: parseFloat(e.target.value)})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-800"/></div>
              </div>
              <div className="space-y-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Radius Keamanan (Meter)</label><input type="number" value={tempConfig.radius} onChange={e => setTempConfig({...tempConfig, radius: parseInt(e.target.value)})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-slate-800"/></div>
              <button onClick={() => onUpdateConfig(tempConfig)} className="w-full bg-slate-900 text-white py-5 rounded-3xl font-black hover:bg-black transition-all shadow-xl shadow-slate-100 active:scale-95">SIMPAN PENGATURAN</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default OwnerDashboard;

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');

  // States for CRUD
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ name: '', username: '', password: '', gapok: 0, uangMakan: 0 });

  // States for Filters & Payroll
  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');
  const [adjustments, setAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [tempConfig, setTempConfig] = useState(outletConfig);

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);

    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  const handleAdjustmentChange = (userId: string, field: 'bonus' | 'deduction', value: string) => {
    const numValue = parseInt(value) || 0;
    setAdjustments(prev => ({
      ...prev,
      [userId]: {
        ...(prev[userId] || { bonus: 0, deduction: 0 }),
        [field]: numValue
      }
    }));
  };

  const getRemainingLeave = (userId: string) => {
    const currentMonth = new Date().getMonth();
    const currentYear = new Date().getFullYear();
    const notPresentCount = attendance.filter(a => 
      a.userId === userId && 
      a.status !== 'PRESENT' && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - notPresentCount);
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate);
    const end = new Date(payEndDate);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const adj = adjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  const exportIndividualSlipPDF = (emp: User) => {
    const { jsPDF } = (window as any).jspdf;
    const report = getPayrollForUser(emp);
    const doc = new jsPDF();

    // Header
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(12);
    doc.setTextColor(100);
    doc.text("SLIP GAJI MINGGUAN", 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);

    // Info
    doc.setFontSize(10);
    doc.setTextColor(50);
    doc.text(`Nama: ${emp.name}`, 14, 45);
    doc.text(`Periode: ${payStartDate} s/d ${payEndDate}`, 14, 51);
    doc.text(`Rate Harian: Rp ${Math.round(report.dailyRate).toLocaleString('id-ID')}`, 14, 57);

    const attDeduction = report.excessDaysCount * report.dailyRate;

    (doc as any).autoTable({
      startY: 65,
      head: [['DESKRIPSI', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Gaji Kotor (7 Hari)', 'Gapok+Makan', `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus', 'Tambahan Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        ['Potongan Absen', `${report.excessDaysCount} Hari (>3x)`, `Rp ${attDeduction.toLocaleString('id-ID')}`],
        ['Potongan Lainnya', 'Manual', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.setFont(undefined, 'bold');
    doc.text("TOTAL TAKE HOME PAY", 14, finalY);
    doc.text(`Rp ${report.netSalary.toLocaleString('id-ID')}`, 196, finalY, { align: 'right' });

    doc.save(`slip_${emp.name.toLowerCase().replace(/\s/g, '_')}.pdf`);
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`w-full flex items-center space-x-3 px-4 py-4 rounded-2xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'
      }`}
    >
      <span className="text-xl">{icon}</span>
      <span className="font-bold text-sm tracking-tight">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-8">
      <aside className="w-full md:w-64 space-y-2">
