  password?: string;
  role: UserRole;
  gapok: number; // Monthly basic salary
  uangMakan: number; // Monthly meal allowance
  isActive: boolean;
}

export interface AttendanceRecord {
  id: string;
  userId: string;
  date: string; // YYYY-MM-DD
  clockIn: string | null;
  clockOut: string | null;
  latitude: number;
  longitude: number;
  status: 'PRESENT' | 'LEAVE' | 'ABSENT';
  isLate?: boolean;
}

export interface LeaveRequest {
  id: string;
  userId: string;
  date: string;
  reason: string;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
}

export interface OutletConfig {
  latitude: number;
  longitude: number;
  radius: number; // In meters
  clockInTime: string; // HH:mm format
  clockOutTime: string; // HH:mm format
}

export interface PayrollReport {
  userId: string;
  userName: string;
  weekStartDate: string;
  weekEndDate: string;
  totalPresent: number;
  totalNotPresent: number; 
  excessDaysCount: number; 
  dailyRate: number;
  grossSalary: number;
  deductions: number;
  bonus: number;
  manualDeduction: number;
  netSalary: number;
}

import { User, AttendanceRecord, PayrollReport } from '../types';
import { DAYS_IN_MONTH, FREE_LEAVE_QUOTA } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[],
  allRecordsThisMonth: AttendanceRecord[],
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  // Gaji harian = (Gapok + Uang Makan) / 30.
  const dailyRate = (user.gapok + user.uangMakan) / DAYS_IN_MONTH;

  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;
  const totalNotPresentThisWeek = 7 - presentCount;

  // Cek akumulasi tidak hadir bulan ini untuk menghitung potongan jatah libur
  let excessDaysThisWeek = 0;
  let monthlyNotPresentCounter = 0;

  const year = weekEnd.getFullYear();
  const month = weekEnd.getMonth();
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  for (let i = 1; i <= daysInMonth; i++) {
    const currentDateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
    const currentDate = new Date(currentDateStr);

    // Cari apakah karyawan HADIR pada tanggal ini
    const record = allRecordsThisMonth.find(r => r.date === currentDateStr);
    const isPresent = record && record.status === 'PRESENT';

    if (!isPresent) {
      monthlyNotPresentCounter++;

      // Jika sudah melewati batas 3 hari, dan tanggal ini masuk dalam rentang minggu payroll
      if (monthlyNotPresentCounter > FREE_LEAVE_QUOTA) {
        if (currentDate >= weekStart && currentDate <= weekEnd) {
          excessDaysThisWeek++;
        }
      }
    }

    if (currentDate > weekEnd) break;
  }

  const weeklyGross = dailyRate * 7;
  const attendanceDeduction = excessDaysThisWeek * dailyRate;
  const totalDeductions = attendanceDeduction + manualDeduction;

  const netSalary = Math.max(0, weeklyGross + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalNotPresent: totalNotPresentThisWeek,
    excessDaysCount: excessDaysThisWeek,
    dailyRate: dailyRate,
    grossSalary: weeklyGross,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary
  };
};

import React, { useState } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  const getStats = () => {
    const userAttendance = attendance.filter(a => a.userId === user.id);
    const userLeaves = leaveRequests.filter(l => l.userId === user.id && l.status === 'APPROVED');
    const late = userAttendance.filter(a => a.status === 'PRESENT' && a.isLate).length;
    const onTime = userAttendance.filter(a => a.status === 'PRESENT' && !a.isLate).length;
    return { late, onTime, leave: userLeaves.length };
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Gagal: Lokasi Anda terlalu jauh (${Math.round(dist)}m). Maksimal ${outletConfig.radius}m.`);
      }
    } catch (err) {
      setErrorLoc("Akses lokasi ditolak. Harap aktifkan GPS.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const stats = getStats();
  const history = [...attendance.filter(a => a.userId === user.id), ...leaveRequests.filter(l => l.userId === user.id).map(l => ({ ...l, type: 'LEAVE' }))]
    .sort((a, b) => b.date.localeCompare(a.date));

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      <div className="lg:col-span-5 space-y-6">
        <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm text-center">
          <h2 className="text-2xl font-black text-slate-900 mb-2">Halo, {user.name}!</h2>
          <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-8">{today}</p>

          <div className="mb-8">
            {!todayRecord?.clockIn ? (
              <button onClick={handleClockInAction} disabled={loadingLoc} className="w-full py-5 bg-indigo-600 text-white rounded-3xl font-black shadow-xl shadow-indigo-100 disabled:opacity-50 transition-all">
                {loadingLoc ? 'MENGECEK LOKASI...' : 'ABSEN MASUK'}
              </button>
            ) : !todayRecord?.clockOut ? (
              <button onClick={onClockOut} className="w-full py-5 bg-orange-500 text-white rounded-3xl font-black shadow-xl shadow-orange-100 transition-all">
                ABSEN KELUAR
              </button>
            ) : (
              <div className="py-5 bg-green-50 text-green-700 rounded-3xl font-black border border-green-100">SUDAH ABSEN HARI INI ✅</div>
            )}
          </div>

          <div className="grid grid-cols-3 gap-3">
            <div className="p-3 bg-green-50 rounded-2xl"><p className="text-[8px] font-black text-green-600 uppercase">Tepat Waktu</p><p className="text-xl font-black text-green-700">{stats.onTime}</p></div>
            <div className="p-3 bg-yellow-50 rounded-2xl"><p className="text-[8px] font-black text-yellow-600 uppercase">Terlambat</p><p className="text-xl font-black text-yellow-700">{stats.late}</p></div>
            <div className="p-3 bg-purple-50 rounded-2xl"><p className="text-[8px] font-black text-purple-600 uppercase">Izin</p><p className="text-xl font-black text-purple-700">{stats.leave}</p></div>
          </div>
          {errorLoc && <p className="mt-4 text-xs font-bold text-red-500">{errorLoc}</p>}
        </div>

        <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm">
          <h3 className="font-black text-xl mb-6">Ajukan Izin</h3>
          <div className="space-y-4">
            <input type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" min={today} />
            <textarea placeholder="Alasan izin..." value={leaveReason} onChange={e => setLeaveReason(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl h-24 font-medium" />
            <button onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason); setLeaveDate(''); setLeaveReason(''); } }} className="w-full bg-purple-600 text-white py-4 rounded-2xl font-black shadow-lg shadow-purple-50">KIRIM IZIN</button>
          </div>
        </div>
      </div>

      <div className="lg:col-span-7 bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm">
        <h3 className="font-black text-xl mb-8">Riwayat Aktivitas</h3>
        <div className="space-y-4">
          {history.map((h: any, idx) => (
            <div key={idx} className="flex justify-between items-center p-4 border-b border-slate-50 hover:bg-slate-50 transition-all rounded-xl">
              <div>
                <p className="font-black text-slate-800">{h.date}</p>
                <p className="text-[10px] text-slate-400 font-bold">{h.clockIn ? `${h.clockIn} - ${h.clockOut || '?'}` : h.reason || 'Izin'}</p>
              </div>
              <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${h.isLate ? 'bg-yellow-100 text-yellow-700' : h.status === 'PRESENT' ? 'bg-green-100 text-green-700' : 'bg-purple-100 text-purple-700'}`}>
                {h.isLate ? 'TERLAMBAT' : h.status === 'PRESENT' ? 'HADIR' : h.status || 'IZIN'}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

