import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[],
  allRecordsThisMonth: AttendanceRecord[],
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  let weeklyBase = 0;
  let methodLabel = "";

  // 1. Hitung Gaji Mingguan Berdasarkan Metode
  if (user.payrollMethod === PayrollMethod.DAILY_30) {
    const dailyGapok = user.gapok / DAYS_IN_MONTH;
    const dailyMakan = user.uangMakan / DAYS_IN_MONTH;
    weeklyBase = (dailyGapok + dailyMakan) * 7;
    methodLabel = "Dwi Style (Bagi 30 Hari)";
  } else {
    weeklyBase = (user.gapok + user.uangMakan) / 4;
    methodLabel = "Mega Style (Bagi 4 Minggu)";
  }

  // 2. Filter kehadiran periode
  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;
  const leaveCount = weekRecords.filter(r => r.status === 'LEAVE' || r.status === 'ABSENT').length;

  // 3. Logika Potongan: Cek jatah 3 hari gratis
  let excessLeaveCountInWeek = 0;
  let runningLeaveCountInMonth = 0;
  const sortedMonthRecords = [...allRecordsThisMonth].sort((a, b) => a.date.localeCompare(b.date));

  sortedMonthRecords.forEach(r => {
    if (r.status === 'LEAVE' || r.status === 'ABSENT') {
      runningLeaveCountInMonth++;
      const rDate = new Date(r.date);
      if (runningLeaveCountInMonth > FREE_LEAVE_QUOTA && rDate >= weekStart && rDate <= weekEnd) {
        excessLeaveCountInWeek++;
      }
    }
  });

  // 4. Hitung Rate Potongan (Uang Makan dahulu, jika 0 baru Gaji Pokok)
  // Sesuai permintaan: Jika ada uang makan, yang dipotong adalah komponen uang makan per harinya.
  let dailyDeductionRate = 0;
  if (user.uangMakan > 0) {
    dailyDeductionRate = user.uangMakan / DAYS_IN_MONTH;
  } else {
    dailyDeductionRate = user.gapok / DAYS_IN_MONTH;
  }

  const attendanceDeduction = excessLeaveCountInWeek * dailyDeductionRate;
  const totalDeductions = attendanceDeduction + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalLeave: leaveCount,
    excessLeaveCount: excessLeaveCountInWeek,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: dailyDeductionRate,
    methodLabel: methodLabel
  };
};

