             <span className="w-2 h-6 bg-purple-500 rounded-full mr-3"></span>
             Ajukan Izin
          </h3>
          <div className="space-y-5">
            <input type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" min={today} />
            <textarea value={leaveReason} onChange={e => setLeaveReason(e.target.value)} placeholder="Alasan izin..." className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-medium min-h-[100px]" />
            <div onClick={() => fileInputRef.current?.click()} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-all">
              {evidencePhoto ? <img src={evidencePhoto} alt="Bukti" className="h-24 object-contain rounded-lg" /> : <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Upload Foto Bukti (Opsional)</p>}
            </div>
            <input type="file" ref={fileInputRef} onChange={handlePhotoChange} accept="image/*" className="hidden" />
            <button onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason, evidencePhoto); setLeaveDate(''); setLeaveReason(''); setEvidencePhoto(undefined); } }} className="w-full bg-purple-600 text-white py-5 rounded-3xl font-black hover:bg-purple-700 transition-all shadow-lg uppercase tracking-widest">KIRIM PENGAJUAN</button>
          </div>
        </div>
      </div>

      <div className="lg:col-span-7 bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm min-h-[600px]">
        <h2 className="text-2xl font-black text-slate-900 mb-10 tracking-tight flex items-center">
          <span className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center mr-4 text-xl">📅</span>
          Riwayat Kehadiran
        </h2>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-[10px] font-black uppercase text-slate-400 tracking-widest border-b">
                <th className="pb-4">Tanggal</th>
                <th className="pb-4">Jam Masuk</th>
                <th className="pb-4 text-right">Status</th>
              </tr>
            </thead>
            <tbody>
              {history.map((item, idx) => (
                <tr key={idx} className="border-b last:border-0 hover:bg-slate-50 transition-colors">
                  <td className="py-4 font-black text-slate-800">{item.date}</td>
                  <td className="py-4 font-bold text-slate-500">{item.clockIn || '--:--'}</td>
                  <td className="py-4 text-right">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${
                      item.status === 'PRESENT' ? (item.isLate ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700') : 'bg-purple-100 text-purple-700'
                    }`}>
                      {item.status === 'PRESENT' ? (item.isLate ? 'TERLAMBAT' : 'HADIR') : 'IZIN'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

