  { id: '2', name: 'Budi Laundry', username: 'budi', password: '123', role: UserRole.EMPLOYEE, gapok: 3000000, uangMakan: 600000, payrollMethod: PayrollMethod.DAILY_30, isActive: true },
  { id: '3', name: 'Mega Clean', username: 'mega', password: '123', role: UserRole.EMPLOYEE, gapok: 3200000, uangMakan: 0, payrollMethod: PayrollMethod.FIXED_4, isActive: true },
