export const DAYS_IN_MONTH = 30;
export const FREE_LEAVE_QUOTA = 3;

import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[],
  allRecordsThisMonth: AttendanceRecord[],
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  // Logic for different payroll methods
  const isDaily30 = user.payrollMethod === PayrollMethod.DAILY_30;
  const methodLabel = isDaily30 ? 'Bagi 30 Hari (Dwi Style)' : 'Bagi 4 Minggu (Mega Style)';

  let weeklyBase = 0;
  let dailyDeductionRate = 0;

  if (isDaily30) {
    const dailyGapok = user.gapok / DAYS_IN_MONTH;
    const dailyUangMakan = user.uangMakan / DAYS_IN_MONTH;
    const dailyRateTotal = dailyGapok + dailyUangMakan;
    weeklyBase = dailyRateTotal * 7;
    // Logic: Uang Makan dipotong dulu. Jika Uang Makan 0, potong Gaji Pokok.
    dailyDeductionRate = user.uangMakan > 0 ? dailyUangMakan : dailyGapok;
  } else {
    // FIXED_4: Gaji per minggu adalah total / 4
    weeklyBase = (user.gapok + user.uangMakan) / 4;
    // Daily rate for deductions in FIXED_4 is weekly base divided by 7
    dailyDeductionRate = weeklyBase / 7;
  }

  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;
  const leaveCount = weekRecords.filter(r => r.status === 'LEAVE').length;

  let excessLeaveCount = 0;
  let runningLeaveCount = 0;

  // Sort monthly records to correctly calculate free leave quota
  const sortedMonthRecords = [...allRecordsThisMonth].sort((a, b) => a.date.localeCompare(b.date));

  sortedMonthRecords.forEach(r => {
    if (r.status === 'LEAVE' || r.status === 'ABSENT') {
      runningLeaveCount++;
      const rDate = new Date(r.date);
      if (runningLeaveCount > FREE_LEAVE_QUOTA && rDate >= weekStart && rDate <= weekEnd) {
        excessLeaveCount++;
      }
    }
  });

  // Deduction logic
  const attendanceDeduction = excessLeaveCount * dailyDeductionRate;

  const totalSlots = 7;
  const recordedCount = presentCount + leaveCount;
  const absentCount = Math.max(0, totalSlots - recordedCount);
  const absenceDeduction = absentCount * dailyDeductionRate;

  const totalDeductions = attendanceDeduction + absenceDeduction + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalLeave: leaveCount,
    excessLeaveCount,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: dailyDeductionRate,
    methodLabel
  };
};

import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[],
  allRecordsThisMonth: AttendanceRecord[],
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  const isDaily30 = user.payrollMethod === PayrollMethod.DAILY_30;
  const methodLabel = isDaily30 ? 'Bagi 30 Hari (Dwi Style)' : 'Bagi 4 Minggu (Mega Style)';

  let weeklyBase = 0;
  let dailyDeductionRate = 0;

  // Tentukan Rate Potongan sesuai aturan baru:
  // Jika ada uang makan, potong uang makan harian. Jika tidak ada, potong gapok harian.
  const dailyGapok = user.gapok / DAYS_IN_MONTH;
  const dailyUangMakan = user.uangMakan / DAYS_IN_MONTH;

  if (user.uangMakan > 0) {
    dailyDeductionRate = dailyUangMakan;
  } else {
    dailyDeductionRate = dailyGapok;
  }

  if (isDaily30) {
    const dailyRateTotal = dailyGapok + dailyUangMakan;
    weeklyBase = dailyRateTotal * 7;
  } else {
    // FIXED_4: Gaji per minggu adalah total / 4
    weeklyBase = (user.gapok + user.uangMakan) / 4;
  }

  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;
  const leaveCount = weekRecords.filter(r => r.status === 'LEAVE').length;

  let excessLeaveCount = 0;
  let runningLeaveCount = 0;

  const sortedMonthRecords = [...allRecordsThisMonth].sort((a, b) => a.date.localeCompare(b.date));

  sortedMonthRecords.forEach(r => {
    if (r.status === 'LEAVE' || r.status === 'ABSENT') {
      runningLeaveCount++;
      const rDate = new Date(r.date);
      if (runningLeaveCount > FREE_LEAVE_QUOTA && rDate >= weekStart && rDate <= weekEnd) {
        excessLeaveCount++;
      }
    }
  });

  const attendanceDeduction = excessLeaveCount * dailyDeductionRate;

  // Hitung absen tanpa keterangan (jika ada slot kosong dalam seminggu)
  const totalSlots = 7;
  const recordedCount = presentCount + leaveCount;
  const absentCount = Math.max(0, totalSlots - recordedCount);
  const absenceDeduction = absentCount * dailyDeductionRate;

  const totalDeductions = attendanceDeduction + absenceDeduction + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalLeave: leaveCount,
    excessLeaveCount,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: dailyDeductionRate,
    methodLabel
  };
};

import React, { useState, useRef } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';
import { FREE_LEAVE_QUOTA } from '../constants';
import { calculateWeeklyPayroll } from '../services/payrollService';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string, photo?: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');
  const [evidencePhoto, setEvidencePhoto] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  const getRemainingLeave = () => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    const usedQuota = attendance.filter(a => 
      a.userId === user.id && 
      (a.status === 'LEAVE' || a.status === 'ABSENT') &&
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;

    return Math.max(0, FREE_LEAVE_QUOTA - usedQuota);
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setEvidencePhoto(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Gagal: Lokasi Anda ${Math.round(dist)}m dari outlet. Maksimal radius ${outletConfig.radius}m.`);
      }
    } catch (err) {
      setErrorLoc("Akses lokasi ditolak. Aktifkan GPS Anda.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const handleDownloadSlip = () => {
    const { jsPDF } = (window as any).jspdf;
    const todayDate = new Date();

    // Tentukan Hari Kamis terdekat sebagai akhir periode
    const day = todayDate.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const weekEnd = new Date(todayDate);
    weekEnd.setDate(todayDate.getDate() + diffToThursday);

    const weekStart = new Date(weekEnd);
    weekStart.setDate(weekEnd.getDate() - 6);

    const monthStart = new Date(weekEnd.getFullYear(), weekEnd.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const report = calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, weekStart, weekEnd);

    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`SLIP GAJI MINGGUAN - ${report.methodLabel}`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);

    doc.setFontSize(10);
    doc.setTextColor(50);
    doc.text(`Nama Karyawan: ${user.name}`, 14, 45);
    doc.text(`Periode: ${report.weekStartDate} s/d ${report.weekEndDate}`, 14, 51);

    // Label potongan dinamis
    const deductionLabel = user.uangMakan > 0 ? 'Potongan Uang Makan' : 'Potongan Gaji Pokok';
    const potDetail = report.excessLeaveCount > 0 ? `${report.excessLeaveCount} Hari (>3x)` : 'Jatah Gratis Masih Ada';

    (doc as any).autoTable({
      startY: 60,
      head: [['DESKRIPSI', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Gaji Kotor Mingguan', 'Kalkulasi Sistem', `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus Mingguan', 'Dari Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        [deductionLabel, potDetail, `Rp ${(report.deductions - report.manualDeduction).toLocaleString('id-ID')}`],
        ['Potongan Lainnya', 'Manual', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.setFont(undefined, 'bold');
    doc.setTextColor(0);
    doc.text("TOTAL DITERIMA", 14, finalY);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rp ${report.netSalary.toLocaleString('id-ID')}`, 196, finalY, { align: 'right' });

    doc.save(`slip_${user.username}_${report.weekEndDate}.pdf`);
  };

  const sisaLibur = getRemainingLeave();
  const history = attendance.filter(a => a.userId === user.id).sort((a,b) => b.date.localeCompare(a.date));

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
      <div className="lg:col-span-5 space-y-8">
        <div className="bg-white p-12 rounded-[48px] border border-slate-100 shadow-sm text-center">
          <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 text-4xl shadow-sm rotate-6">
            🧺
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Halo, {user.name}!</h2>
          <p className="text-slate-400 text-sm mb-10 font-bold uppercase tracking-widest">
            Sisa Jatah Izin Gratis: <span className={sisaLibur > 0 ? 'text-green-600' : 'text-red-500'}>{sisaLibur}</span> / {FREE_LEAVE_QUOTA}x
          </p>

          <div className="mb-10">
            {!todayRecord?.clockIn && todayRecord?.status !== 'LEAVE' ? (
              <button
                onClick={handleClockInAction}
                disabled={loadingLoc}
                className="w-full py-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-3xl font-black text-xl shadow-2xl transition-all active:scale-95"
              >
                {loadingLoc ? 'MENGECEK LOKASI...' : 'ABSEN MASUK'}
              </button>
            ) : todayRecord?.status === 'LEAVE' ? (
              <div className="p-8 bg-purple-50 text-purple-700 rounded-[32px] font-black border border-purple-100 shadow-inner">
                 ANDA SEDANG IZIN HARI INI
              </div>
            ) : !todayRecord?.clockOut ? (
              <button
                onClick={onClockOut}
                className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-3xl font-black text-xl shadow-2xl transition-all active:scale-95"
              >
                ABSEN PULANG
              </button>
            ) : (
              <div className="p-8 bg-green-50 text-green-700 rounded-[32px] font-black border border-green-100 shadow-inner">
                ABSEN SELESAI ✅
              </div>
            )}
          </div>

          <button 
            onClick={handleDownloadSlip}
            className="w-full py-4 border-2 border-indigo-100 text-indigo-600 rounded-3xl font-black text-sm uppercase tracking-widest hover:bg-indigo-50 transition-all shadow-sm"
          >
            Download Slip Gaji Minggu Ini
          </button>
          {errorLoc && <p className="mt-4 text-xs font-bold text-red-500 bg-red-50 p-3 rounded-xl border border-red-100">{errorLoc}</p>}
        </div>

        <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm">
          <h3 className="font-black text-2xl text-slate-900 mb-8 flex items-center">
             <span className="w-2 h-6 bg-purple-500 rounded-full mr-3"></span>
             Ajukan Izin
          </h3>
          <div className="space-y-5">
            <input type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold" min={today} />
            <textarea value={leaveReason} onChange={e => setLeaveReason(e.target.value)} placeholder="Alasan izin..." className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-medium min-h-[100px]" />
            <div onClick={() => fileInputRef.current?.click()} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-all">
              {evidencePhoto ? (
                <img src={evidencePhoto} alt="Bukti" className="h-24 object-contain rounded-lg" />
              ) : (
                <div className="text-center">
                  <p className="text-2xl mb-1">📸</p>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Upload Foto Bukti</p>
                </div>
              )}
            </div>
            <input type="file" ref={fileInputRef} onChange={handlePhotoChange} accept="image/*" className="hidden" />
            <button onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason, evidencePhoto); setLeaveDate(''); setLeaveReason(''); setEvidencePhoto(undefined); } }} className="w-full bg-purple-600 text-white py-5 rounded-3xl font-black hover:bg-purple-700 transition-all shadow-lg uppercase tracking-widest">KIRIM PENGAJUAN</button>
          </div>
        </div>
      </div>

      <div className="lg:col-span-7 bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm min-h-[600px]">
        <h2 className="text-2xl font-black text-slate-900 mb-10 tracking-tight flex items-center">
          <span className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center mr-4 text-xl">📅</span>
          Riwayat Kehadiran
        </h2>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-[10px] font-black uppercase text-slate-400 tracking-widest border-b">
                <th className="pb-4">Tanggal</th>
                <th className="pb-4">Jam Masuk</th>
                <th className="pb-4 text-right">Status</th>
              </tr>
            </thead>
            <tbody>
              {history.length === 0 && (
                <tr><td colSpan={3} className="py-20 text-center text-slate-400 italic">Belum ada data absensi.</td></tr>
              )}
              {history.map((item, idx) => (
                <tr key={idx} className="border-b last:border-0 hover:bg-slate-50 transition-colors">
                  <td className="py-4 font-black text-slate-800">{item.date}</td>
                  <td className="py-4 font-bold text-slate-500">{item.clockIn || '--:--'}</td>
                  <td className="py-4 text-right">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${
                      item.status === 'PRESENT' ? (item.isLate ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700') : 'bg-purple-100 text-purple-700'
                    }`}>
                      {item.status === 'PRESENT' ? (item.isLate ? 'TERLAMBAT' : 'HADIR') : 'IZIN'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default EmployeeDashboard;

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollMethod } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');
  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');
  const [adjustments, setAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ 
    name: '', username: '', password: '', gapok: 0, uangMakan: 0, payrollMethod: PayrollMethod.DAILY_30 
  });
  const [tempConfig, setTempConfig] = useState(outletConfig);
  const [selectedPhoto, setSelectedPhoto] = useState<string | null>(null);

  // Inisialisasi Periode Gaji Kamis
  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  const getRemainingLeave = (userId: string) => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const monthlyRecords = attendance.filter(a => 
      a.userId === userId && 
      (a.status === 'LEAVE' || a.status === 'ABSENT') &&
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - monthlyRecords);
  };

  const handleAdjustmentChange = (userId: string, field: 'bonus' | 'deduction', value: string) => {
    const numValue = parseInt(value) || 0;
    setAdjustments(prev => ({
      ...prev,
      [userId]: { ...(prev[userId] || { bonus: 0, deduction: 0 }), [field]: numValue }
    }));
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const data = getMergedAttendance();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 15, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`MONITORING ABSENSI (${attStartDate} - ${attEndDate})`, 105, 22, { align: 'center' });

    const tableRows = data.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.date,
      item.clockIn || '--:--',
      item.statusText
    ]);
    (doc as any).autoTable({
      startY: 30,
      head: [['KARYAWAN', 'TANGGAL', 'JAM MASUK', 'STATUS']],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`absensi_damdam_${attEndDate}.pdf`);
  };

  const exportIndividualSlipPDF = (emp: User) => {
    const { jsPDF } = (window as any).jspdf;
    const report = getPayrollForUser(emp);
    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(10);
    doc.setTextColor(50);
    doc.text(`SLIP GAJI MINGGUAN (${report.methodLabel})`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);
    doc.text(`Nama: ${emp.name}`, 14, 45);
    doc.text(`Periode: ${payStartDate} s/d ${payEndDate}`, 14, 51);

    const deductionLabel = emp.uangMakan > 0 ? 'Potongan Uang Makan' : 'Potongan Gaji Pokok';
    const potAbsensi = report.deductions - report.manualDeduction;

    (doc as any).autoTable({
      startY: 60,
      head: [['DESKRIPSI', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Gaji Kotor Mingguan', report.methodLabel, `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus Mingguan', 'Input Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        [
          deductionLabel, 
          report.excessLeaveCount > 0 ? `${report.excessLeaveCount} Hari (>3x)` : 'Sesuai Jatah Kuota', 
          `Rp ${potAbsensi.toLocaleString('id-ID')}`
        ],
        ['Potongan Kasbon / Lainnya', 'Input Manual', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.text("TOTAL DITERIMA", 14, finalY);
    doc.text(`Rp ${report.netSalary.toLocaleString('id-ID')}`, 196, finalY, { align: 'right' });
    doc.save(`slip_${emp.username}_${payEndDate}.pdf`);
  };

  const getMergedAttendance = () => {
    const start = new Date(attStartDate);
    const end = new Date(attEndDate);
    const dailyAtt = attendance.filter(a => {
      const d = new Date(a.date);
      return d >= start && d <= end;
    });
    const combined: any[] = [];
    dailyAtt.forEach(a => {
      let statusText = a.status === 'PRESENT' ? 'HADIR' : 'IZIN/OFF';
      if (a.status === 'PRESENT' && a.isLate) statusText = 'TERLAMBAT';
      combined.push({ ...a, type: 'ATTENDANCE', statusText });
    });
    return combined.sort((a, b) => b.date.localeCompare(a.date));
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate);
    const end = new Date(payEndDate);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const adj = adjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`w-full flex items-center space-x-3 px-6 py-4 rounded-2xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'
      }`}
    >
      <span className="text-xl">{icon}</span>
      <span className="font-black text-[10px] uppercase tracking-widest">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-8">
      <aside className="w-full md:w-64 space-y-2">
        <SidebarItem icon="📊" label="Persetujuan" id="dashboard" />
        <SidebarItem icon="👥" label="Manajemen Staf" id="employees" />
        <SidebarItem icon="📅" label="Monitoring Absen" id="attendance" />
        <SidebarItem icon="💰" label="Payroll Mingguan" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      <div className="flex-1 bg-white rounded-[40px] border border-slate-100 shadow-sm p-10 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Menunggu Persetujuan</h2>
            <div className="space-y-4">
              {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                  const sisaLibur = getRemainingLeave(l.userId);
                  return (
                    <div key={l.id} className="p-8 bg-slate-50 rounded-[32px] border border-slate-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                      <div className="flex-1">
                        <div className="flex items-center space-x-3 mb-2">
                          <p className="font-black text-slate-900 text-lg">{employees.find(e => e.id === l.userId)?.name}</p>
                          <span className={`text-[10px] px-3 py-1 rounded-full font-black ${sisaLibur > 0 ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                              Sisa Jatah: {sisaLibur}x
                          </span>
                        </div>
                        <p className="text-sm text-slate-500 font-medium mb-3">{l.date} — "{l.reason}"</p>
                        {l.evidencePhoto && (
                          <button onClick={() => setSelectedPhoto(l.evidencePhoto!)} className="text-[10px] font-black text-indigo-600 uppercase tracking-widest hover:underline flex items-center">
                            📸 Lihat Bukti Foto
                          </button>
                        )}
                      </div>
                      <div className="flex space-x-3">
                        <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="bg-indigo-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Setuju</button>
                        <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="bg-red-500 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Tolak</button>
                      </div>
                    </div>
                  );
              })}
              {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && <p className="text-slate-400 italic text-center py-20">Tidak ada pengajuan izin baru.</p>}
            </div>
          </div>
        )}

        {activeMenu === 'employees' && (
          <div className="space-y-8">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Daftar Karyawan</h2>
              <button onClick={() => { setEditingEmp(null); setEmpForm({ name: '', username: '', password: '', gapok: 0, uangMakan: 0, payrollMethod: PayrollMethod.DAILY_30 }); setShowEmpModal(true); }} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-lg">+ Tambah Staf</button>
            </div>
            <div className="overflow-x-auto border border-slate-50 rounded-[32px] shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nama</th>
                    <th className="px-8 py-6 text-center">Jatah Izin</th>
                    <th className="px-8 py-6">Gapok</th>
                    <th className="px-8 py-6">Uang Makan</th>
                    <th className="px-8 py-6 text-right">Aksi</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm">
                  {employees.filter(e => e.role === UserRole.EMPLOYEE).map(e => (
                    <tr key={e.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-8 py-6 font-black text-slate-800">{e.name}</td>
                      <td className="px-8 py-6 text-center font-black">
                        <span className={getRemainingLeave(e.id) > 0 ? 'text-green-600' : 'text-red-500'}>
                          {getRemainingLeave(e.id)} / {FREE_LEAVE_QUOTA}x
                        </span>
                      </td>
                      <td className="px-8 py-6 font-bold text-slate-600">Rp {e.gapok.toLocaleString('id-ID')}</td>
                      <td className="px-8 py-6 font-bold text-slate-600">Rp {e.uangMakan.toLocaleString('id-ID')}</td>
                      <td className="px-8 py-6 text-right space-x-4">
                        <button onClick={() => { setEditingEmp(e); setEmpForm(e); setShowEmpModal(true); }} className="text-indigo-600 font-black uppercase text-[10px]">Edit</button>
                        <button onClick={() => onDeleteEmployee(e.id)} className="text-red-500 font-black uppercase text-[10px]">Hapus</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeMenu === 'payroll' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Siklus Gaji Mingguan</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-slate-50 p-8 rounded-[32px]">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Mulai (Jumat)</label>
                <input type="date" value={payStartDate} onChange={(e) => setPayStartDate(e.target.value)} className="w-full p-4 bg-white border border-slate-100 rounded-2xl font-black outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Selesai (Kamis)</label>
                <input type="date" value={payEndDate} onChange={(e) => setPayEndDate(e.target.value)} className="w-full p-4 bg-white border border-slate-100 rounded-2xl font-black outline-none" />
              </div>
            </div>

            <div className="space-y-6">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => {
                const report = getPayrollForUser(emp);
                const adj = adjustments[emp.id] || { bonus: 0, deduction: 0 };
                const potAbsensi = report.deductions - report.manualDeduction;
                const potLabel = emp.uangMakan > 0 ? 'Pot. Uang Makan' : 'Pot. Gaji Pokok';

                return (
                  <div key={emp.id} className="p-8 bg-white border border-slate-100 rounded-[40px] shadow-sm flex flex-col gap-6">
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="text-xl font-black text-slate-900">{emp.name}</h4>
                        <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mt-1">{report.methodLabel}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-3xl font-black text-indigo-700">Rp {report.netSalary.toLocaleString('id-ID')}</p>
                      </div>
                    </div>
                    <div className="grid grid-cols-3 gap-4 text-[9px] font-black uppercase tracking-widest bg-slate-50 p-5 rounded-2xl">
                        <div>Gaji Kotor: <span className="text-slate-900">Rp {report.grossSalary.toLocaleString('id-ID')}</span></div>
                        <div>Izin Berbayar: <span className="text-indigo-600">{report.totalLeave} Hari</span></div>
                        <div>{potLabel}: <span className={potAbsensi > 0 ? 'text-red-600' : 'text-green-600'}>Rp {potAbsensi.toLocaleString('id-ID')}</span></div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <input type="number" value={adj.bonus} onChange={(e) => handleAdjustmentChange(emp.id, 'bonus', e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-green-700 placeholder-green-300" placeholder="Bonus (Rp)"/>
                        <input type="number" value={adj.deduction} onChange={(e) => handleAdjustmentChange(emp.id, 'deduction', e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-red-700 placeholder-red-300" placeholder="Kasbon (Rp)"/>
                    </div>
                    <button onClick={() => exportIndividualSlipPDF(emp)} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-black transition-all">Download Slip Gaji Karyawan</button>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeMenu === 'attendance' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Monitoring Absensi</h2>
            <div className="flex justify-between items-center bg-slate-50 p-8 rounded-[32px] gap-4">
              <div className="flex-1 flex gap-4">
                <input type="date" value={attStartDate} onChange={(e) => setAttStartDate(e.target.value)} className="p-4 bg-white border border-slate-100 rounded-2xl font-black flex-1 outline-none" />
                <input type="date" value={attEndDate} onChange={(e) => setAttEndDate(e.target.value)} className="p-4 bg-white border border-slate-100 rounded-2xl font-black flex-1 outline-none" />
              </div>
              <button onClick={exportAttendanceToPDF} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Export PDF</button>
            </div>
            <div className="overflow-x-auto border border-slate-50 rounded-[32px] shadow-sm">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nama</th>
                    <th className="px-8 py-6">Tanggal</th>
                    <th className="px-8 py-6">Jam</th>
                    <th className="px-8 py-6 text-right">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 text-sm">
                  {getMergedAttendance().map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-8 py-6 font-black text-slate-800">{employees.find(e => e.id === item.userId)?.name}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.date}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.clockIn || '--:--'}</td>
                      <td className="px-8 py-6 text-right">
                        <span className={`px-4 py-1.5 rounded-full text-[10px] font-black ${item.statusText.includes('HADIR') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{item.statusText}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeMenu === 'settings' && (
          <div className="max-w-2xl space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Konfigurasi Outlet</h2>
            <div className="space-y-6 bg-slate-50 p-10 rounded-[40px] border border-slate-100 shadow-sm">
              <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Jam Masuk (Absen)</label>
                    <input type="time" value={tempConfig.clockInTime} onChange={e => setTempConfig({...tempConfig, clockInTime: e.target.value})} className="w-full p-4 bg-white border border-slate-100 rounded-2xl font-black shadow-sm"/>
                  </div>
                  <div className="space-y-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest pl-2">Radius Keamanan (M)</label>
                    <input type="number" value={tempConfig.radius} onChange={e => setTempConfig({...tempConfig, radius: parseInt(e.target.value)})} className="w-full p-4 bg-white border border-slate-100 rounded-2xl font-black shadow-sm"/>
                  </div>
              </div>
              <button onClick={() => onUpdateConfig(tempConfig)} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black shadow-xl uppercase text-[10px] tracking-widest transition-all">Update Pengaturan</button>
            </div>
          </div>
        )}

        {selectedPhoto && (
          <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4" onClick={() => setSelectedPhoto(null)}>
             <div className="bg-white p-2 rounded-3xl max-w-2xl w-full relative overflow-hidden" onClick={e => e.stopPropagation()}>
                <img src={selectedPhoto} alt="Bukti Foto" className="w-full h-auto max-h-[80vh] object-contain rounded-2xl" />
                <button onClick={() => setSelectedPhoto(null)} className="absolute top-4 right-4 bg-black/50 text-white w-10 h-10 rounded-full flex items-center justify-center font-black">✕</button>
             </div>
          </div>
        )}

        {showEmpModal && (
          <div className="fixed inset-0 bg-black/40 backdrop-blur-md z-[60] flex items-center justify-center p-4">
            <div className="bg-white rounded-[40px] w-full max-w-lg p-10 shadow-2xl border border-slate-100">
              <h3 className="text-2xl font-black text-slate-900 mb-8 text-center">{editingEmp ? 'Ubah Profil' : 'Daftarkan Staf'}</h3>
              <div className="space-y-4">
                <input placeholder="Nama Lengkap" value={empForm.name} onChange={e => setEmpForm({...empForm, name: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black outline-none shadow-inner"/>
                <div className="grid grid-cols-2 gap-4">
