export const FREE_LEAVE_QUOTA = 3;

import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[],
  allRecordsThisMonth: AttendanceRecord[],
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  const isDaily30 = user.payrollMethod === PayrollMethod.DAILY_30;
  const methodLabel = isDaily30 ? 'Bagi 30 Hari (Dwi Style)' : 'Bagi 4 Minggu (Mega Style)';

  const dailyGapok = user.gapok / DAYS_IN_MONTH;
  const dailyUangMakan = user.uangMakan / DAYS_IN_MONTH;

  let weeklyBase = 0;
  let dailyDeductionRate = 0;

  // LOGIKA POTONGAN:
  // Jika ada uang makan, potong uang makan harian. 
  // Jika tidak ada uang makan (seperti Mega), potong gaji pokok harian.
  if (user.uangMakan > 0) {
    dailyDeductionRate = dailyUangMakan;
  } else {
    dailyDeductionRate = dailyGapok;
  }

  if (isDaily30) {
    // Dwi Style: (Gapok + Makan) / 30 * 7 hari
    const dailyRateTotal = dailyGapok + dailyUangMakan;
    weeklyBase = dailyRateTotal * 7;
  } else {
    // Mega Style: (Gapok + Makan) / 4 minggu
    weeklyBase = (user.gapok + user.uangMakan) / 4;
  }

  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;
  const leaveCount = weekRecords.filter(r => r.status === 'LEAVE').length;

  let excessLeaveCount = 0;
  let runningLeaveCount = 0;

  // Urutkan data bulan ini untuk menghitung kuota 3 hari gratis
  const sortedMonthRecords = [...allRecordsThisMonth].sort((a, b) => a.date.localeCompare(b.date));

  sortedMonthRecords.forEach(r => {
    if (r.status === 'LEAVE' || r.status === 'ABSENT') {
      runningLeaveCount++;
      const rDate = new Date(r.date);
      // Jika sudah melewati kuota 3 hari, dan tanggal tersebut ada di minggu ini, tambahkan hitungan potongan
      if (runningLeaveCount > FREE_LEAVE_QUOTA && rDate >= weekStart && rDate <= weekEnd) {
        excessLeaveCount++;
      }
    }
  });

  // Total potongan dari absensi (izin > jatah atau absen tanpa keterangan)
  const attendanceDeduction = excessLeaveCount * dailyDeductionRate;

  // Slot kosong (absen tanpa keterangan) dalam 1 minggu (7 hari)
  const totalSlots = 7;
  const recordedCount = presentCount + leaveCount;
  const absentCount = Math.max(0, totalSlots - recordedCount);
  const absenceDeduction = absentCount * dailyDeductionRate;

  const totalDeductions = attendanceDeduction + absenceDeduction + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalLeave: leaveCount,
    excessLeaveCount,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: dailyDeductionRate,
    methodLabel
  };
};

import React, { useState, useEffect } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  useEffect(() => {
    const savedUsers = localStorage.getItem('damdam_users');
    const savedAttendance = localStorage.getItem('damdam_attendance');
    const savedLeave = localStorage.getItem('damdam_leave');
    const savedConfig = localStorage.getItem('damdam_config');

    // Jika ada data di localStorage, gunakan itu. Jika tidak, gunakan MOCK_USERS (Dwi & Mega).
    setUsers(savedUsers ? JSON.parse(savedUsers) : MOCK_USERS);
    if (savedAttendance) setAttendance(JSON.parse(savedAttendance));
    if (savedLeave) setLeaveRequests(JSON.parse(savedLeave));
    if (savedConfig) setOutletConfig(JSON.parse(savedConfig));
  }, []);

  useEffect(() => {
    if (users.length > 0) localStorage.setItem('damdam_users', JSON.stringify(users));
    localStorage.setItem('damdam_attendance', JSON.stringify(attendance));
    localStorage.setItem('damdam_leave', JSON.stringify(leaveRequests));
    localStorage.setItem('damdam_config', JSON.stringify(outletConfig));
  }, [users, attendance, leaveRequests, outletConfig]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    const user = users.find(u => u.username === loginUsername && u.password === loginPassword);
    if (user) {
      setCurrentUser(user);
      setLoginUsername('');
      setLoginPassword('');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => setCurrentUser(null);

  const handleAddEmployee = (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };
    setUsers(prev => [...prev, newUser]);
  };

  const handleEditEmployee = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
  };

  const handleDeleteEmployee = (userId: string) => {
    if (confirm('Hapus karyawan ini? Data absensi akan tetap ada.')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
    }
  };

  const handleClockIn = (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };
    setAttendance(prev => [...prev, newRecord]);
  };

  const handleClockOut = () => {
    if (!currentUser) return;
    const today = new Date().toISOString().split('T')[0];
    const now = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === today) ? { ...a, clockOut: now } : a
    ));
  };

  const handleSubmitLeave = (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const newLeave: LeaveRequest = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };
    setLeaveRequests(prev => [...prev, newLeave]);
  };

  const handleApproveLeave = (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    if (status === 'APPROVED') {
      const leave = leaveRequests.find(l => l.id === leaveId);
      if (leave) {
        setAttendance(prev => {
          const filtered = prev.filter(a => !(a.userId === leave.userId && a.date === leave.date));
          const leaveRecord: AttendanceRecord = {
            id: Math.random().toString(36).substr(2, 9),
            userId: leave.userId,
            date: leave.date,
            clockIn: null,
            clockOut: null,
            latitude: 0,
            longitude: 0,
            status: 'LEAVE'
          };
          return [...filtered, leaveRecord];
        });
      }
    }
  };

  const handleUpdateConfig = (config: OutletConfig) => {
    setOutletConfig(config);
    alert('Pengaturan operasional berhasil diperbarui.');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center bg-red-50 py-2 rounded-lg">{loginError}</p>}
            <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl">LOGIN</button>
          </form>
          <div className="mt-8 text-center text-[10px] font-bold text-slate-400">
             DEMO: owner/123, dwi/123, mega/123
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave} 
        />
      ) : (
        <OwnerDashboard 
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onUpdateConfig={handleUpdateConfig} 
          onApproveLeave={handleApproveLeave} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee} 
        />
      )}
    </Layout>
  );
};

