export interface PayrollReport {
  userId: string;
  userName: string;
  weekStartDate: string;
  weekEndDate: string;
  totalPresent: number;
  totalLeave: number;
  excessLeaveCount: number;
  grossSalary: number;
  deductions: number;
  bonus: number;
  manualDeduction: number;
  netSalary: number;
  dailyRate: number;
  methodLabel: string;
}

import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[], // All historical records for this user
  allRecordsThisMonth: AttendanceRecord[], // Records specifically for the current month
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  const isDaily30 = user.payrollMethod === PayrollMethod.DAILY_30;
  const methodLabel = isDaily30 ? 'Bagi 30 Hari (Dwi Style)' : 'Bagi 4 Minggu (Mega Style)';

  // Calculate default deduction rate if custom one is not provided
  const calculatedDeductionRate = user.deductionRate || 
    (user.uangMakan > 0 ? user.uangMakan / DAYS_IN_MONTH : user.gapok / DAYS_IN_MONTH);

  let weeklyBase = 0;
  if (isDaily30) {
    const dailyGapok = user.gapok / DAYS_IN_MONTH;
    const dailyUangMakan = user.uangMakan / DAYS_IN_MONTH;
    weeklyBase = (dailyGapok + dailyUangMakan) * 7;
  } else {
    weeklyBase = (user.gapok + user.uangMakan) / 4;
  }

  // Filter records that fall within the current payroll week
  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentCount = weekRecords.filter(r => r.status === 'PRESENT').length;
  const leaveCount = weekRecords.filter(r => r.status === 'LEAVE').length;

  // Sorting all month records to track the "first 3 free days" across the whole month
  const sortedMonthRecords = [...allRecordsThisMonth].sort((a, b) => a.date.localeCompare(b.date));

  let monthlyAbsentCounter = 0;
  let deductionsThisWeek = 0;
  let excessLeaveCountThisWeek = 0;

  sortedMonthRecords.forEach(record => {
    const isAbsentOrLeave = record.status === 'LEAVE' || record.status === 'ABSENT';
    if (isAbsentOrLeave) {
      monthlyAbsentCounter++;

      // If this record belongs to the current week AND it's past the quota
      const recordDate = new Date(record.date);
      if (recordDate >= weekStart && recordDate <= weekEnd) {
        if (monthlyAbsentCounter > FREE_LEAVE_QUOTA) {
          deductionsThisWeek += calculatedDeductionRate;
          excessLeaveCountThisWeek++;
        }
      }
    }
  });

  // Calculate potential deductions for "unrecorded" days in the 7-day week (Real Absences)
  // If the owner didn't mark them as LEAVE but they didn't CLOCK IN.
  const weekDays = 7;
  const recordedDaysCount = weekRecords.length;
  const unrecordedDays = Math.max(0, weekDays - recordedDaysCount);

  // Apply deduction for unrecorded days if they also push past the monthly quota
  for (let i = 0; i < unrecordedDays; i++) {
    monthlyAbsentCounter++;
    if (monthlyAbsentCounter > FREE_LEAVE_QUOTA) {
      deductionsThisWeek += calculatedDeductionRate;
    }
  }

  const totalDeductions = deductionsThisWeek + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentCount,
    totalLeave: leaveCount,
    excessLeaveCount: excessLeaveCountThisWeek,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: calculatedDeductionRate,
    methodLabel
  };
};

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollMethod } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');
  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');
  const [adjustments, setAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ 
    name: '', username: '', password: '', gapok: 0, uangMakan: 0, deductionRate: 0, payrollMethod: PayrollMethod.DAILY_30 
  });
  const [tempConfig, setTempConfig] = useState(outletConfig);
  const [selectedPhoto, setSelectedPhoto] = useState<string | null>(null);

  useEffect(() => {
    // Default periode payroll: Jumat ke Kamis
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  const getRemainingLeave = (userId: string) => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const monthlyRecords = attendance.filter(a => 
      a.userId === userId && 
      (a.status === 'LEAVE' || a.status === 'ABSENT') &&
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    ).length;
    return Math.max(0, FREE_LEAVE_QUOTA - monthlyRecords);
  };

  const handleAdjustmentChange = (userId: string, field: 'bonus' | 'deduction', value: string) => {
    const numValue = parseInt(value) || 0;
    setAdjustments(prev => ({
      ...prev,
      [userId]: { ...(prev[userId] || { bonus: 0, deduction: 0 }), [field]: numValue }
    }));
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const data = getMergedAttendance();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 15, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`MONITORING ABSENSI (${attStartDate} - ${attEndDate})`, 105, 22, { align: 'center' });

    const tableRows = data.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.date,
      item.clockIn || '--:--',
      item.statusText
    ]);
    (doc as any).autoTable({
      startY: 30,
      head: [['KARYAWAN', 'TANGGAL', 'JAM MASUK', 'STATUS']],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`absensi_damdam_${attEndDate}.pdf`);
  };

  const exportIndividualSlipPDF = (emp: User) => {
    const { jsPDF } = (window as any).jspdf;
    const report = getPayrollForUser(emp);
    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(10);
    doc.setTextColor(50);
    doc.text(`SLIP GAJI MINGGUAN (${report.methodLabel})`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);
    doc.text(`Nama: ${emp.name}`, 14, 45);
    doc.text(`Periode: ${payStartDate} s/d ${payEndDate}`, 14, 51);

