        <SidebarItem icon="👥" label="Manajemen Staf" id="employees" />
        <SidebarItem icon="📅" label="Monitoring Absen" id="attendance" />
        <SidebarItem icon="💰" label="Payroll Mingguan" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      <div className="flex-1 bg-white rounded-[40px] border border-slate-100 shadow-sm p-10 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Menunggu Persetujuan</h2>
            <div className="space-y-4">
              {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                  const sisaLibur = getRemainingLeave(l.userId);
                  return (
                    <div key={l.id} className="p-8 bg-slate-50 rounded-[32px] border border-slate-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                      <div className="flex-1">
                        <div className="flex items-center space-x-3 mb-2">
                          <p className="font-black text-slate-900 text-lg">{employees.find(e => e.id === l.userId)?.name}</p>
                          <span className={`text-[10px] px-3 py-1 rounded-full font-black ${sisaLibur > 0 ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                              Sisa Jatah: {sisaLibur}x
                          </span>
