                      <div className="flex space-x-3">
                        <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="bg-indigo-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Setuju</button>
                        <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="bg-red-500 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Tolak</button>
                      </div>
                    </div>
                  );
              })}
              {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && <p className="text-slate-400 italic text-center py-20">Tidak ada pengajuan izin baru.</p>}
            </div>
          </div>
