  clockOutTime: string; // HH:mm
}

export interface PayrollReport {
  userId: string;
  userName: string;
  weekStartDate: string;
  weekEndDate: string;
  totalPresent: number;
  totalOnTime: number;
  totalLate: number;
  totalLeave: number;
  excessLeaveCount: number;
  grossSalary: number;
  deductions: number;
  bonus: number;
  manualDeduction: number;
  netSalary: number;
  dailyRate: number;
  methodLabel: string;
}

import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[], 
  allRecordsThisMonth: AttendanceRecord[], 
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  const isDaily30 = user.payrollMethod === PayrollMethod.DAILY_30;
  const methodLabel = isDaily30 ? 'Bagi 30 Hari (Dwi Style)' : 'Bagi 4 Minggu (Mega Style)';

  const calculatedDeductionRate = user.deductionRate || 
    (user.uangMakan > 0 ? user.uangMakan / DAYS_IN_MONTH : user.gapok / DAYS_IN_MONTH);

  let weeklyBase = 0;
  if (isDaily30) {
    const dailyGapok = user.gapok / DAYS_IN_MONTH;
    const dailyUangMakan = user.uangMakan / DAYS_IN_MONTH;
    weeklyBase = (dailyGapok + dailyUangMakan) * 7;
  } else {
    weeklyBase = (user.gapok + user.uangMakan) / 4;
  }

  const weekRecords = records.filter(r => {
    const d = new Date(r.date);
    return d >= weekStart && d <= weekEnd;
  });

  const presentRecords = weekRecords.filter(r => r.status === 'PRESENT');
  const totalOnTime = presentRecords.filter(r => !r.isLate).length;
  const totalLate = presentRecords.filter(r => r.isLate).length;
  const leaveCount = weekRecords.filter(r => r.status === 'LEAVE').length;

  const sortedMonthRecords = [...allRecordsThisMonth].sort((a, b) => a.date.localeCompare(b.date));

  let monthlyAbsentCounter = 0;
  let deductionsThisWeek = 0;
  let excessLeaveCountThisWeek = 0;

  sortedMonthRecords.forEach(record => {
    const isAbsentOrLeave = record.status === 'LEAVE' || record.status === 'ABSENT';
    if (isAbsentOrLeave) {
      monthlyAbsentCounter++;

      const recordDate = new Date(record.date);
      if (recordDate >= weekStart && recordDate <= weekEnd) {
        if (monthlyAbsentCounter > FREE_LEAVE_QUOTA) {
          deductionsThisWeek += calculatedDeductionRate;
          excessLeaveCountThisWeek++;
        }
      }
    }
  });

  const totalDeductions = deductionsThisWeek + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: presentRecords.length,
    totalOnTime,
    totalLate,
    totalLeave: leaveCount,
    excessLeaveCount: excessLeaveCountThisWeek,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: calculatedDeductionRate,
    methodLabel
  };
};

import React, { useState, useRef } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';
import { FREE_LEAVE_QUOTA } from '../constants';
import { calculateWeeklyPayroll } from '../services/payrollService';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string, photo?: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');
  const [evidencePhoto, setEvidencePhoto] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const today = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === today && r.userId === user.id);

  // Current Month Stats
  const now = new Date();
  const currentMonth = now.getMonth();
  const currentYear = now.getFullYear();

  const monthRecords = attendance.filter(a => 
    a.userId === user.id && 
    new Date(a.date).getMonth() === currentMonth &&
    new Date(a.date).getFullYear() === currentYear
  );

  const usedQuota = monthRecords.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT').length;
  const sisaLibur = Math.max(0, FREE_LEAVE_QUOTA - usedQuota);
  const onTimeCount = monthRecords.filter(a => a.status === 'PRESENT' && !a.isLate).length;
  const lateCount = monthRecords.filter(a => a.status === 'PRESENT' && a.isLate).length;

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setEvidencePhoto(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Radius error: ${Math.round(dist)}m dari outlet.`);
      }
    } catch (err) {
      setErrorLoc("Aktifkan GPS Anda.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const handleDownloadSlip = () => {
    const { jsPDF } = (window as any).jspdf;
    const todayDate = new Date();
    const day = todayDate.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const weekEnd = new Date(todayDate);
    weekEnd.setDate(todayDate.getDate() + diffToThursday);
    const weekStart = new Date(weekEnd);
    weekStart.setDate(weekEnd.getDate() - 6);
    const monthStart = new Date(weekEnd.getFullYear(), weekEnd.getMonth(), 1);
    const mRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const report = calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), mRecords, weekStart, weekEnd);

    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`SLIP GAJI MINGGUAN`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);
    doc.setTextColor(50);
    doc.text(`Nama: ${user.name}`, 14, 45);
    doc.text(`Periode: ${report.weekStartDate} s/d ${report.weekEndDate}`, 14, 51);

    const deductionLabel = user.uangMakan > 0 ? 'Potongan Uang Makan' : 'Potongan Gaji Pokok';
    (doc as any).autoTable({
      startY: 60,
      head: [['DESKRIPSI', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Gaji Kotor Mingguan', report.methodLabel, `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus Mingguan', 'Input Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        [deductionLabel, `${report.excessLeaveCount} Hari Absen (>3x)`, `Rp ${(report.deductions - report.manualDeduction).toLocaleString('id-ID')}`],
        ['Potongan Lainnya', 'Manual', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.text("TOTAL DITERIMA", 14, finalY);
    doc.text(`Rp ${report.netSalary.toLocaleString('id-ID')}`, 196, finalY, { align: 'right' });
    doc.save(`slip_${user.username}.pdf`);
  };

  const history = attendance.filter(a => a.userId === user.id).sort((a,b) => b.date.localeCompare(a.date));

  return (
    <div className="space-y-8">
      {/* Stats Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center text-xl font-black">📅</div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Jatah Izin</p>
            <p className={`text-xl font-black ${sisaLibur > 0 ? 'text-green-600' : 'text-red-500'}`}>{sisaLibur} / {FREE_LEAVE_QUOTA}x</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-12 h-12 bg-green-50 text-green-600 rounded-2xl flex items-center justify-center text-xl font-black">✅</div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tepat Waktu</p>
            <p className="text-xl font-black text-slate-900">{onTimeCount} Hari</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[32px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-12 h-12 bg-amber-50 text-amber-600 rounded-2xl flex items-center justify-center text-xl font-black">⚠️</div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Terlambat</p>
            <p className="text-xl font-black text-slate-900">{lateCount} Hari</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
        <div className="lg:col-span-5 space-y-8">
          <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm text-center">
            <h2 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Halo, {user.name}</h2>

            <div className="mb-8">
              {!todayRecord?.clockIn && todayRecord?.status !== 'LEAVE' && todayRecord?.status !== 'LEAVE_PENDING' ? (
                <button
                  onClick={handleClockInAction}
                  disabled={loadingLoc}
                  className="w-full py-6 bg-indigo-600 hover:bg-indigo-700 text-white rounded-3xl font-black text-xl shadow-xl transition-all active:scale-95"
                >
                  {loadingLoc ? 'MENGECEK...' : 'ABSEN MASUK'}
                </button>
              ) : todayRecord?.status === 'LEAVE_PENDING' ? (
                <div className="p-8 bg-amber-50 text-amber-700 rounded-[32px] font-black border border-amber-100">
                   IZIN: MENUNGGU ACC ⏳
                </div>
              ) : todayRecord?.status === 'LEAVE' ? (
                <div className="p-8 bg-green-50 text-green-700 rounded-[32px] font-black border border-green-100">
                   IZIN: DISETUJUI ✅
                </div>
              ) : !todayRecord?.clockOut ? (
                <button
                  onClick={onClockOut}
                  className="w-full py-6 bg-orange-500 hover:bg-orange-600 text-white rounded-3xl font-black text-xl shadow-xl transition-all active:scale-95"
                >
                  ABSEN PULANG
                </button>
              ) : (
                <div className="p-8 bg-indigo-50 text-indigo-700 rounded-[32px] font-black border border-indigo-100">
                  ABSEN SELESAI ✅
                </div>
              )}
              {errorLoc && <p className="mt-4 text-xs font-bold text-red-500">{errorLoc}</p>}
            </div>

            <button onClick={handleDownloadSlip} className="w-full py-4 bg-slate-50 text-slate-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-100 transition-all">Download Slip Gaji</button>
          </div>

          <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm">
            <h3 className="font-black text-xl text-slate-900 mb-6 uppercase tracking-tight">Ajukan Izin Baru</h3>
            <div className="space-y-4">
              <input type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none" min={today} />
              <textarea value={leaveReason} onChange={e => setLeaveReason(e.target.value)} placeholder="Alasan izin..." className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-medium min-h-[100px] outline-none" />
              <div onClick={() => fileInputRef.current?.click()} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-all bg-white">
                {evidencePhoto ? (
                  <img src={evidencePhoto} alt="Bukti" className="h-24 object-contain rounded-lg" />
                ) : (
                  <div className="text-center text-slate-400">
                    <p className="text-2xl">📸</p>
                    <p className="text-[10px] font-black uppercase tracking-widest">Foto Bukti (Opsional)</p>
                  </div>
                )}
              </div>
              <input type="file" ref={fileInputRef} onChange={handlePhotoChange} accept="image/*" className="hidden" />
              <button onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason, evidencePhoto); setLeaveDate(''); setLeaveReason(''); setEvidencePhoto(undefined); } }} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black hover:bg-black transition-all shadow-lg uppercase tracking-widest text-[10px]">Kirim Pengajuan</button>
            </div>
          </div>
        </div>

        <div className="lg:col-span-7 bg-white p-10 rounded-[48px] border border-slate-100 shadow-sm min-h-[600px]">
          <h2 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Riwayat Kehadiran</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black uppercase text-slate-400 tracking-widest border-b pb-4">
                  <th className="pb-4">Tanggal</th>
                  <th className="pb-4">Jam</th>
                  <th className="pb-4 text-right">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {history.map((item, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                    <td className="py-5 font-black text-slate-800">{item.date}</td>
                    <td className="py-5 font-bold text-slate-500">{item.clockIn || '--:--'}</td>
                    <td className="py-5 text-right">
                      <span className={`px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                        item.status === 'PRESENT' ? (item.isLate ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700') : 
                        item.status === 'LEAVE_PENDING' ? 'bg-slate-100 text-slate-500' : 
                        item.status === 'LEAVE' ? 'bg-indigo-100 text-indigo-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {item.status === 'PRESENT' ? (item.isLate ? 'TERLAMBAT' : 'TEPAT WAKTU') : 
                         item.status === 'LEAVE_PENDING' ? 'MENUNGGU ACC' : 
                         item.status === 'LEAVE' ? 'IZIN DISETUJUI' : 'ABSEN'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

