      new Date(a.date).getFullYear() === currentYear
    );
    const onTime = monthRecs.filter(a => a.status === 'PRESENT' && !a.isLate).length;
    const late = monthRecs.filter(a => a.status === 'PRESENT' && a.isLate).length;
    const leaves = monthRecs.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT').length;
    const remaining = Math.max(0, FREE_LEAVE_QUOTA - leaves);
    return { onTime, late, leaves, remaining };
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const data = getMergedAttendance();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 15, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`MONITORING ABSENSI (${attStartDate} - ${attEndDate})`, 105, 22, { align: 'center' });

    const tableRows = data.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.date,
      item.clockIn || '--:--',
      item.statusText
    ]);
    (doc as any).autoTable({
      startY: 30,
      head: [['KARYAWAN', 'TANGGAL', 'JAM MASUK', 'STATUS']],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`monitoring_damdam.pdf`);
  };

  const getMergedAttendance = () => {
    const start = new Date(attStartDate);
    const end = new Date(attEndDate);
    const dailyAtt = attendance.filter(a => {
      const d = new Date(a.date);
      return d >= start && d <= end;
    });
    const combined: any[] = [];
    dailyAtt.forEach(a => {
      let statusText = a.status === 'PRESENT' ? (a.isLate ? 'TERLAMBAT' : 'HADIR') : 
                      a.status === 'LEAVE_PENDING' ? 'MENUNGGU' : 
                      a.status === 'LEAVE' ? 'IZIN/OFF' : 'ABSEN';
      combined.push({ ...a, statusText });
    });
    return combined.sort((a, b) => b.date.localeCompare(a.date));
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate);
    const end = new Date(payEndDate);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const adj = adjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`w-full flex items-center space-x-3 px-6 py-4 rounded-2xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'
      }`}
    >
      <span className="text-xl">{icon}</span>
      <span className="font-black text-[10px] uppercase tracking-widest">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-8">
      <aside className="w-full md:w-64 space-y-2">
        <SidebarItem icon="📊" label="Persetujuan" id="dashboard" />
        <SidebarItem icon="👥" label="Manajemen Staf" id="employees" />
        <SidebarItem icon="📅" label="Monitoring Absen" id="attendance" />
        <SidebarItem icon="💰" label="Payroll Mingguan" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      <div className="flex-1 bg-white rounded-[40px] border border-slate-100 shadow-sm p-10 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Persetujuan Izin</h2>
            <div className="space-y-4">
              {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                  const stats = getStatsForEmployee(l.userId);
                  return (
                    <div key={l.id} className="p-8 bg-slate-50 rounded-[32px] border border-slate-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                      <div className="flex-1">
                        <div className="flex items-center space-x-3 mb-2">
                          <p className="font-black text-slate-900 text-lg">{employees.find(e => e.id === l.userId)?.name}</p>
                          <span className={`text-[10px] px-3 py-1 rounded-full font-black ${stats.remaining > 0 ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                              Sisa Jatah: {stats.remaining}x
                          </span>
                        </div>
                        <p className="text-sm text-slate-500 font-medium mb-3">{l.date} — "{l.reason}"</p>
                        {l.evidencePhoto && (
                          <button onClick={() => setSelectedPhoto(l.evidencePhoto!)} className="text-[10px] font-black text-indigo-600 uppercase tracking-widest flex items-center">
                            📸 Lihat Bukti
                          </button>
                        )}
                      </div>
                      <div className="flex space-x-3">
                        <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="bg-indigo-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Setuju</button>
                        <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="bg-red-500 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Tolak</button>
                      </div>
                    </div>
                  );
              })}
              {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && <p className="text-slate-400 italic text-center py-20">Tidak ada pengajuan baru.</p>}
            </div>
          </div>
        )}

        {activeMenu === 'employees' && (
          <div className="space-y-8">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Manajemen Staf</h2>
              <button onClick={() => { setEditingEmp(null); setShowEmpModal(true); }} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-lg">+ Tambah Staf</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(e => {
                const stats = getStatsForEmployee(e.id);
                return (
                  <div key={e.id} className="p-8 bg-white border border-slate-100 rounded-[32px] shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                      <h4 className="text-xl font-black text-slate-900">{e.name}</h4>
                      <div className="space-x-2">
                        <button onClick={() => { setEditingEmp(e); setEmpForm(e); setShowEmpModal(true); }} className="text-indigo-600 font-black text-[10px] uppercase">Edit</button>
                        <button onClick={() => onDeleteEmployee(e.id)} className="text-red-500 font-black text-[10px] uppercase">Hapus</button>
                      </div>
                    </div>
                    <div className="grid grid-cols-3 gap-2 text-center text-[9px] font-black uppercase tracking-tighter">
                      <div className="bg-green-50 p-2 rounded-xl">
                        <p className="text-green-600">Tepat</p>
                        <p className="text-slate-900 text-sm">{stats.onTime}</p>
                      </div>
                      <div className="bg-amber-50 p-2 rounded-xl">
                        <p className="text-amber-600">Telat</p>
                        <p className="text-slate-900 text-sm">{stats.late}</p>
                      </div>
                      <div className="bg-indigo-50 p-2 rounded-xl">
                        <p className="text-indigo-600">Sisa Izin</p>
                        <p className="text-slate-900 text-sm">{stats.remaining}</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeMenu === 'attendance' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Log Absensi</h2>
            <div className="flex justify-between items-center bg-slate-50 p-8 rounded-[32px] gap-4">
              <div className="flex-1 flex gap-4">
                <input type="date" value={attStartDate} onChange={(e) => setAttStartDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black flex-1" />
                <input type="date" value={attEndDate} onChange={(e) => setAttEndDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black flex-1" />
              </div>
              <button onClick={exportAttendanceToPDF} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest">Export PDF</button>
            </div>
            <div className="overflow-x-auto border border-slate-50 rounded-[32px]">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nama</th>
                    <th className="px-8 py-6">Tanggal</th>
                    <th className="px-8 py-6">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {getMergedAttendance().map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50">
                      <td className="px-8 py-6 font-black text-slate-800">{employees.find(e => e.id === item.userId)?.name}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.date}</td>
                      <td className="px-8 py-6">
                        <span className={`px-4 py-1.5 rounded-full text-[9px] font-black ${item.statusText.includes('HADIR') || item.statusText.includes('TEPAT') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{item.statusText}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeMenu === 'payroll' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Payroll Mingguan</h2>
            <div className="grid grid-cols-2 gap-4 bg-slate-50 p-6 rounded-[32px]">
              <input type="date" value={payStartDate} onChange={(e) => setPayStartDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black" />
              <input type="date" value={payEndDate} onChange={(e) => setPayEndDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black" />
            </div>
            <div className="space-y-4">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => {
                const report = getPayrollForUser(emp);
                return (
                  <div key={emp.id} className="p-8 bg-white border border-slate-100 rounded-[32px] shadow-sm">
                    <div className="flex justify-between items-center mb-6">
                      <h4 className="text-xl font-black text-slate-900">{emp.name}</h4>
                      <p className="text-2xl font-black text-indigo-700">Rp {report.netSalary.toLocaleString('id-ID')}</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mb-6">
                      <input type="number" placeholder="Bonus" className="p-4 bg-slate-50 rounded-xl font-bold" onChange={(e) => handleAdjustmentChange(emp.id, 'bonus', e.target.value)} />
                      <input type="number" placeholder="Potongan" className="p-4 bg-slate-50 rounded-xl font-bold" onChange={(e) => handleAdjustmentChange(emp.id, 'deduction', e.target.value)} />
                    </div>
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest grid grid-cols-2 gap-2">
                      <p>Hadir: {report.totalOnTime} | Telat: {report.totalLate} | Izin: {report.totalLeave}</p>
                      <p className="text-right">Deduction: Rp {report.deductions.toLocaleString('id-ID')}</p>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeMenu === 'settings' && (
          <div className="max-w-xl space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Pengaturan Outlet</h2>
            <div className="space-y-6 bg-white border border-slate-200 p-10 rounded-[40px]">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Jam Masuk</label>
                <input type="time" value={tempConfig.clockInTime} onChange={e => setTempConfig({...tempConfig, clockInTime: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <input type="number" step="any" placeholder="Latitude" value={tempConfig.latitude} onChange={e => setTempConfig({...tempConfig, latitude: parseFloat(e.target.value)})} className="p-4 border border-slate-200 rounded-2xl font-black" />
                <input type="number" step="any" placeholder="Longitude" value={tempConfig.longitude} onChange={e => setTempConfig({...tempConfig, longitude: parseFloat(e.target.value)})} className="p-4 border border-slate-200 rounded-2xl font-black" />
              </div>
              <button onClick={() => onUpdateConfig(tempConfig)} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl">Simpan Pengaturan</button>
            </div>
          </div>
        )}
      </div>

      {selectedPhoto && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4" onClick={() => setSelectedPhoto(null)}>
           <img src={selectedPhoto} className="max-w-full max-h-[90vh] rounded-3xl" />
        </div>
      )}

      {showEmpModal && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[40px] w-full max-w-lg p-10 shadow-2xl border border-slate-100">
            <h3 className="text-2xl font-black text-slate-900 mb-8 text-center uppercase tracking-tighter">Profil Karyawan</h3>
            <div className="space-y-4">
              <input placeholder="Nama Lengkap" value={empForm.name} onChange={e => setEmpForm({...empForm, name: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
              <div className="grid grid-cols-2 gap-4">
                <input placeholder="Username" value={empForm.username} onChange={e => setEmpForm({...empForm, username: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
                <input placeholder="Password" value={empForm.password} onChange={e => setEmpForm({...empForm, password: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
              </div>
              <div className="grid grid-cols-3 gap-4">
                <input type="number" placeholder="Gapok" value={empForm.gapok} onChange={e => setEmpForm({...empForm, gapok: parseInt(e.target.value)})} className="p-4 border border-slate-200 rounded-xl font-bold" />
                <input type="number" placeholder="Makan" value={empForm.uangMakan} onChange={e => setEmpForm({...empForm, uangMakan: parseInt(e.target.value)})} className="p-4 border border-slate-200 rounded-xl font-bold" />
                <input type="number" placeholder="Pot. Harian" value={empForm.deductionRate} onChange={e => setEmpForm({...empForm, deductionRate: parseInt(e.target.value)})} className="p-4 border border-slate-200 rounded-xl font-bold" />
              </div>
              <select value={empForm.payrollMethod} onChange={e => setEmpForm({...empForm, payrollMethod: e.target.value as PayrollMethod})} className="w-full p-4 border border-slate-200 rounded-2xl font-black">
                <option value={PayrollMethod.DAILY_30}>Bagi 30 (Dwi)</option>
                <option value={PayrollMethod.FIXED_4}>Bagi 4 (Mega)</option>
              </select>
              <div className="flex gap-4 pt-4">
                <button onClick={() => setShowEmpModal(false)} className="flex-1 py-4 bg-slate-100 rounded-2xl font-black uppercase text-[10px]">Batal</button>
                <button onClick={() => { if(editingEmp) onEditEmployee({...editingEmp, ...empForm} as User); else onAddEmployee(empForm); setShowEmpModal(false); }} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px]">Simpan</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OwnerDashboard;

import React, { useState, useEffect } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  useEffect(() => {
    const savedUsers = localStorage.getItem('damdam_users');
    const savedAttendance = localStorage.getItem('damdam_attendance');
    const savedLeave = localStorage.getItem('damdam_leave');
    const savedConfig = localStorage.getItem('damdam_config');

    setUsers(savedUsers ? JSON.parse(savedUsers) : MOCK_USERS);
    if (savedAttendance) setAttendance(JSON.parse(savedAttendance));
    if (savedLeave) setLeaveRequests(JSON.parse(savedLeave));
    if (savedConfig) setOutletConfig(JSON.parse(savedConfig));
  }, []);

  useEffect(() => {
    if (users.length > 0) localStorage.setItem('damdam_users', JSON.stringify(users));
    localStorage.setItem('damdam_attendance', JSON.stringify(attendance));
    localStorage.setItem('damdam_leave', JSON.stringify(leaveRequests));
    localStorage.setItem('damdam_config', JSON.stringify(outletConfig));
  }, [users, attendance, leaveRequests, outletConfig]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    const user = users.find(u => u.username === loginUsername && u.password === loginPassword);
    if (user) {
      setCurrentUser(user);
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => setCurrentUser(null);

  const handleAddEmployee = (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };
    setUsers(prev => [...prev, newUser]);
  };

  const handleEditEmployee = (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
  };

  const handleDeleteEmployee = (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
    }
  };

  const handleClockIn = (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };
    setAttendance(prev => [...prev, newRecord]);
  };

  const handleClockOut = () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const now = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: now } : a
    ));
  };

  const handleSubmitLeave = (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };
    setLeaveRequests(prev => [...prev, newLeave]);

    // Karyawan izin -> data langsung masuk riwayat dengan status LEAVE_PENDING
    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };
    setAttendance(prev => {
      // Remove any existing record for same date (e.g. auto absent)
      const filtered = prev.filter(a => !(a.userId === currentUser.id && a.date === date));
      return [...filtered, newAttRecord];
    });
  };

  const handleApproveLeave = (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));

    setAttendance(prev => prev.map(a => {
      if (a.leaveRequestId === leaveId) {
        return { 
          ...a, 
          status: status === 'APPROVED' ? 'LEAVE' : 'ABSENT' 
        };
      }
      return a;
    }));
  };

  const handleUpdateConfig = (config: OutletConfig) => {
    setOutletConfig(config);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl uppercase tracking-widest">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout}>
      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave} 
        />
      ) : (
        <OwnerDashboard 
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onUpdateConfig={handleUpdateConfig} 
          onApproveLeave={handleApproveLeave} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollMethod } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');
  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');
  const [adjustments, setAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ 
    name: '', username: '', password: '', gapok: 0, uangMakan: 0, deductionRate: 0, payrollMethod: PayrollMethod.DAILY_30 
  });
  const [tempConfig, setTempConfig] = useState(outletConfig);
  const [selectedPhoto, setSelectedPhoto] = useState<string | null>(null);

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  const getStatsForEmployee = (userId: string) => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const monthRecs = attendance.filter(a => 
      a.userId === userId && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    );
    const onTime = monthRecs.filter(a => a.status === 'PRESENT' && !a.isLate).length;
    const late = monthRecs.filter(a => a.status === 'PRESENT' && a.isLate).length;
    const leaves = monthRecs.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT').length;
    const remaining = Math.max(0, FREE_LEAVE_QUOTA - leaves);
    return { onTime, late, leaves, remaining };
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const data = getMergedAttendance();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 15, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`MONITORING ABSENSI (${attStartDate} - ${attEndDate})`, 105, 22, { align: 'center' });

    const tableRows = data.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.date,
      item.clockIn || '--:--',
      item.statusText
    ]);
    (doc as any).autoTable({
      startY: 30,
      head: [['KARYAWAN', 'TANGGAL', 'JAM MASUK', 'STATUS']],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`monitoring_damdam.pdf`);
  };

  const getMergedAttendance = () => {
    const start = new Date(attStartDate);
    const end = new Date(attEndDate);
    const dailyAtt = attendance.filter(a => {
      const d = new Date(a.date);
      return d >= start && d <= end;
    });
    const combined: any[] = [];
    dailyAtt.forEach(a => {
      let statusText = a.status === 'PRESENT' ? (a.isLate ? 'TERLAMBAT' : 'HADIR') : 
                      a.status === 'LEAVE_PENDING' ? 'MENUNGGU' : 
                      a.status === 'LEAVE' ? 'IZIN/OFF' : 'ABSEN';
      combined.push({ ...a, statusText });
    });
    return combined.sort((a, b) => b.date.localeCompare(a.date));
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate);
    const end = new Date(payEndDate);
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const adj = adjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  // Fix: Added handleAdjustmentChange to update adjustments state for bonus and deduction
  const handleAdjustmentChange = (userId: string, field: 'bonus' | 'deduction', value: string) => {
    const numValue = parseFloat(value) || 0;
    setAdjustments(prev => ({
      ...prev,
      [userId]: {
        ...(prev[userId] || { bonus: 0, deduction: 0 }),
        [field]: numValue
      }
    }));
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`w-full flex items-center space-x-3 px-6 py-4 rounded-2xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-slate-50'
      }`}
    >
      <span className="text-xl">{icon}</span>
      <span className="font-black text-[10px] uppercase tracking-widest">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-8">
      <aside className="w-full md:w-64 space-y-2">
        <SidebarItem icon="📊" label="Persetujuan" id="dashboard" />
        <SidebarItem icon="👥" label="Manajemen Staf" id="employees" />
        <SidebarItem icon="📅" label="Monitoring Absen" id="attendance" />
        <SidebarItem icon="💰" label="Payroll Mingguan" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      <div className="flex-1 bg-white rounded-[40px] border border-slate-100 shadow-sm p-10 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-10">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Persetujuan Izin</h2>
            <div className="space-y-4">
              {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                  const stats = getStatsForEmployee(l.userId);
                  return (
                    <div key={l.id} className="p-8 bg-slate-50 rounded-[32px] border border-slate-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                      <div className="flex-1">
                        <div className="flex items-center space-x-3 mb-2">
                          <p className="font-black text-slate-900 text-lg">{employees.find(e => e.id === l.userId)?.name}</p>
                          <span className={`text-[10px] px-3 py-1 rounded-full font-black ${stats.remaining > 0 ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                              Sisa Jatah: {stats.remaining}x
                          </span>
                        </div>
                        <p className="text-sm text-slate-500 font-medium mb-3">{l.date} — "{l.reason}"</p>
                        {l.evidencePhoto && (
                          <button onClick={() => setSelectedPhoto(l.evidencePhoto!)} className="text-[10px] font-black text-indigo-600 uppercase tracking-widest flex items-center">
                            📸 Lihat Bukti
                          </button>
                        )}
                      </div>
                      <div className="flex space-x-3">
                        <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="bg-indigo-600 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Setuju</button>
                        <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="bg-red-500 text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest">Tolak</button>
                      </div>
                    </div>
                  );
              })}
              {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && <p className="text-slate-400 italic text-center py-20">Tidak ada pengajuan baru.</p>}
            </div>
          </div>
        )}

        {activeMenu === 'employees' && (
          <div className="space-y-8">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Manajemen Staf</h2>
              <button onClick={() => { setEditingEmp(null); setShowEmpModal(true); }} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-lg">+ Tambah Staf</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(e => {
                const stats = getStatsForEmployee(e.id);
                return (
                  <div key={e.id} className="p-8 bg-white border border-slate-100 rounded-[32px] shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                      <h4 className="text-xl font-black text-slate-900">{e.name}</h4>
                      <div className="space-x-2">
                        <button onClick={() => { setEditingEmp(e); setEmpForm(e); setShowEmpModal(true); }} className="text-indigo-600 font-black text-[10px] uppercase">Edit</button>
                        <button onClick={() => onDeleteEmployee(e.id)} className="text-red-500 font-black text-[10px] uppercase">Hapus</button>
                      </div>
                    </div>
                    <div className="grid grid-cols-3 gap-2 text-center text-[9px] font-black uppercase tracking-tighter">
                      <div className="bg-green-50 p-2 rounded-xl">
                        <p className="text-green-600">Tepat</p>
                        <p className="text-slate-900 text-sm">{stats.onTime}</p>
                      </div>
                      <div className="bg-amber-50 p-2 rounded-xl">
                        <p className="text-amber-600">Telat</p>
                        <p className="text-slate-900 text-sm">{stats.late}</p>
                      </div>
                      <div className="bg-indigo-50 p-2 rounded-xl">
                        <p className="text-indigo-600">Sisa Izin</p>
                        <p className="text-slate-900 text-sm">{stats.remaining}</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeMenu === 'attendance' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Log Absensi</h2>
            <div className="flex justify-between items-center bg-slate-50 p-8 rounded-[32px] gap-4">
              <div className="flex-1 flex gap-4">
                <input type="date" value={attStartDate} onChange={(e) => setAttStartDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black flex-1" />
                <input type="date" value={attEndDate} onChange={(e) => setAttEndDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black flex-1" />
              </div>
              <button onClick={exportAttendanceToPDF} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest">Export PDF</button>
            </div>
            <div className="overflow-x-auto border border-slate-50 rounded-[32px]">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nama</th>
                    <th className="px-8 py-6">Tanggal</th>
                    <th className="px-8 py-6">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {getMergedAttendance().map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50">
                      <td className="px-8 py-6 font-black text-slate-800">{employees.find(e => e.id === item.userId)?.name}</td>
                      <td className="px-8 py-6 text-slate-500 font-bold">{item.date}</td>
                      <td className="px-8 py-6">
                        <span className={`px-4 py-1.5 rounded-full text-[9px] font-black ${item.statusText.includes('HADIR') || item.statusText.includes('TEPAT') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{item.statusText}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeMenu === 'payroll' && (
          <div className="space-y-8">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Payroll Mingguan</h2>
            <div className="grid grid-cols-2 gap-4 bg-slate-50 p-6 rounded-[32px]">
              <input type="date" value={payStartDate} onChange={(e) => setPayStartDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black" />
              <input type="date" value={payEndDate} onChange={(e) => setPayEndDate(e.target.value)} className="p-4 bg-white border border-slate-200 rounded-2xl font-black" />
            </div>
            <div className="space-y-4">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => {
                const report = getPayrollForUser(emp);
                return (
                  <div key={emp.id} className="p-8 bg-white border border-slate-100 rounded-[32px] shadow-sm">
                    <div className="flex justify-between items-center mb-6">
                      <h4 className="text-xl font-black text-slate-900">{emp.name}</h4>
                      <p className="text-2xl font-black text-indigo-700">Rp {report.netSalary.toLocaleString('id-ID')}</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mb-6">
                      <input type="number" placeholder="Bonus" className="p-4 bg-slate-50 rounded-xl font-bold" onChange={(e) => handleAdjustmentChange(emp.id, 'bonus', e.target.value)} />
