                      <p>Hadir: {report.totalOnTime} | Telat: {report.totalLate} | Izin: {report.totalLeave}</p>
                      <p className="text-right">Deduction: Rp {report.deductions.toLocaleString('id-ID')}</p>
                    </div>
                  </div>
                );
              })}
            </div>
