                <input type="time" value={tempConfig.clockInTime} onChange={e => setTempConfig({...tempConfig, clockInTime: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <input type="number" step="any" placeholder="Latitude" value={tempConfig.latitude} onChange={e => setTempConfig({...tempConfig, latitude: parseFloat(e.target.value)})} className="p-4 border border-slate-200 rounded-2xl font-black" />
                <input type="number" step="any" placeholder="Longitude" value={tempConfig.longitude} onChange={e => setTempConfig({...tempConfig, longitude: parseFloat(e.target.value)})} className="p-4 border border-slate-200 rounded-2xl font-black" />
