            <h3 className="text-2xl font-black text-slate-900 mb-8 text-center uppercase tracking-tighter">Profil Karyawan</h3>
            <div className="space-y-4">
              <input placeholder="Nama Lengkap" value={empForm.name} onChange={e => setEmpForm({...empForm, name: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
              <div className="grid grid-cols-2 gap-4">
                <input placeholder="Username" value={empForm.username} onChange={e => setEmpForm({...empForm, username: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
                <input placeholder="Password" value={empForm.password} onChange={e => setEmpForm({...empForm, password: e.target.value})} className="w-full p-4 border border-slate-200 rounded-2xl font-black" />
              </div>
              <div className="grid grid-cols-3 gap-4">
                <input type="number" placeholder="Gapok" value={empForm.gapok} onChange={e => setEmpForm({...empForm, gapok: parseInt(e.target.value)})} className="p-4 border border-slate-200 rounded-xl font-bold" />
                <input type="number" placeholder="Makan" value={empForm.uangMakan} onChange={e => setEmpForm({...empForm, uangMakan: parseInt(e.target.value)})} className="p-4 border border-slate-200 rounded-xl font-bold" />
                <input type="number" placeholder="Pot. Harian" value={empForm.deductionRate} onChange={e => setEmpForm({...empForm, deductionRate: parseInt(e.target.value)})} className="p-4 border border-slate-200 rounded-xl font-bold" />
              </div>
              <select value={empForm.payrollMethod} onChange={e => setEmpForm({...empForm, payrollMethod: e.target.value as PayrollMethod})} className="w-full p-4 border border-slate-200 rounded-2xl font-black">
                <option value={PayrollMethod.DAILY_30}>Bagi 30 (Dwi)</option>
                <option value={PayrollMethod.FIXED_4}>Bagi 4 (Mega)</option>
              </select>
              <div className="flex gap-4 pt-4">
                <button onClick={() => setShowEmpModal(false)} className="flex-1 py-4 bg-slate-100 rounded-2xl font-black uppercase text-[10px]">Batal</button>
                <button onClick={() => { if(editingEmp) onEditEmployee({...editingEmp, ...empForm} as User); else onAddEmployee(empForm); setShowEmpModal(false); }} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[10px]">Simpan</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

