interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string, photo?: string) => void;
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave
}) => {
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');
  const [evidencePhoto, setEvidencePhoto] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [slipStartDate, setSlipStartDate] = useState('');
  const [slipEndDate, setSlipEndDate] = useState('');

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setSlipStartDate(start.toISOString().split('T')[0]);
    setSlipEndDate(end.toISOString().split('T')[0]);
  }, []);

  const todayStr = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === todayStr && r.userId === user.id);

  const now = new Date();
  const currentMonth = now.getMonth();
  const currentYear = now.getFullYear();

  const monthRecords = attendance.filter(a => 
    a.userId === user.id && 
    new Date(a.date).getMonth() === currentMonth &&
    new Date(a.date).getFullYear() === currentYear
  );

  const usedQuota = monthRecords.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT').length;
  const sisaLibur = Math.max(0, FREE_LEAVE_QUOTA - usedQuota);
  const onTimeCount = monthRecords.filter(a => a.status === 'PRESENT' && !a.isLate).length;
  const lateCount = monthRecords.filter(a => a.status === 'PRESENT' && a.isLate).length;

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setEvidencePhoto(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      if (dist <= outletConfig.radius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Radius error: Anda berada ${Math.round(dist)}m dari outlet.`);
      }
    } catch (err) {
      setErrorLoc("Mohon aktifkan GPS perangkat Anda.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const handleDownloadSlip = () => {
    if (!slipStartDate || !slipEndDate) return alert("Pilih tanggal!");
    const { jsPDF } = (window as any).jspdf;
    const weekStart = new Date(slipStartDate);
    const weekEnd = new Date(slipEndDate);
    const monthStart = new Date(weekEnd.getFullYear(), weekEnd.getMonth(), 1);
    const mRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const report = calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), mRecords, weekStart, weekEnd);

    const doc = new jsPDF();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });
    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`SLIP GAJI KARYAWAN`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);
    doc.setTextColor(50);
    doc.text(`Nama: ${user.name}`, 14, 45);
    doc.text(`Periode: ${report.weekStartDate} s/d ${report.weekEndDate}`, 14, 51);

    (doc as any).autoTable({
      startY: 60,
      head: [['DESKRIPSI', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Gaji Kotor', report.methodLabel, `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus', 'Input Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        ['Potongan Absen', `${report.excessLeaveCount} Hari (>3x)`, `Rp ${(report.deductions - report.manualDeduction).toLocaleString('id-ID')}`],
        ['Potongan Lain', 'Manual', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.text("TOTAL DITERIMA: Rp " + report.netSalary.toLocaleString('id-ID'), 14, finalY);
    doc.save(`slip_${user.username}.pdf`);
  };

  const history = attendance.filter(a => a.userId === user.id).sort((a,b) => b.date.localeCompare(a.date));

  return (
    <div className="space-y-6 md:space-y-8">
      {/* Kartu Statistik - Mobile 1 kolom, Desktop 3 kolom */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-lg">📅</div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Jatah Izin</p>
            <p className={`text-lg font-black ${sisaLibur > 0 ? 'text-green-600' : 'text-red-500'}`}>{sisaLibur} / {FREE_LEAVE_QUOTA}x</p>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-10 h-10 bg-green-50 text-green-600 rounded-xl flex items-center justify-center text-lg">✅</div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Tepat Waktu</p>
            <p className="text-lg font-black text-slate-900">{onTimeCount} Hari</p>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-10 h-10 bg-amber-50 text-amber-600 rounded-xl flex items-center justify-center text-lg">⚠️</div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Terlambat</p>
            <p className="text-lg font-black text-slate-900">{lateCount} Hari</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8 items-start">
        <div className="lg:col-span-5 space-y-6 md:space-y-8">
          {/* Panel Absen Utama */}
          <div className="bg-white p-8 md:p-10 rounded-[32px] md:rounded-[48px] border border-slate-100 shadow-sm text-center">
            <h2 className="text-xl md:text-2xl font-black text-slate-900 mb-6 tracking-tight">Halo, {user.name}</h2>

            <div className="mb-8">
              {!todayRecord?.clockIn && todayRecord?.status !== 'LEAVE' && todayRecord?.status !== 'LEAVE_PENDING' ? (
                <button
                  onClick={handleClockInAction}
                  disabled={loadingLoc}
                  className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-[20px] font-black text-lg shadow-xl shadow-indigo-100 active:scale-95 transition-all"
                >
                  {loadingLoc ? 'MENGECEK LOKASI...' : 'ABSEN MASUK'}
                </button>
              ) : todayRecord?.status === 'LEAVE_PENDING' ? (
                <div className="p-6 bg-amber-50 text-amber-700 rounded-2xl font-black border border-amber-100 text-sm">
                   IZIN: MENUNGGU PERSETUJUAN ⏳
                </div>
              ) : todayRecord?.status === 'LEAVE' ? (
                <div className="p-6 bg-green-50 text-green-700 rounded-2xl font-black border border-green-100 text-sm">
                   IZIN: DISETUJU ✅
                </div>
              ) : !todayRecord?.clockOut ? (
                <button
                  onClick={onClockOut}
                  className="w-full py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-[20px] font-black text-lg shadow-xl shadow-orange-100 active:scale-95 transition-all"
                >
                  ABSEN PULANG
                </button>
              ) : (
                <div className="p-6 bg-indigo-50 text-indigo-700 rounded-2xl font-black border border-indigo-100 text-sm">
                  ABSEN HARI INI SELESAI ✅
                </div>
              )}
              {errorLoc && <p className="mt-4 text-[10px] font-black text-red-500 uppercase">{errorLoc}</p>}
            </div>

            <div className="bg-slate-50 p-6 rounded-[24px] space-y-4">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest text-left">Unduh Slip Gaji</p>
              <div className="grid grid-cols-2 gap-2">
                <input type="date" value={slipStartDate} onChange={e => setSlipStartDate(e.target.value)} className="p-3 bg-white border border-slate-200 rounded-xl text-[10px] font-bold outline-none" />
                <input type="date" value={slipEndDate} onChange={e => setSlipEndDate(e.target.value)} className="p-3 bg-white border border-slate-200 rounded-xl text-[10px] font-bold outline-none" />
              </div>
              <button onClick={handleDownloadSlip} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg active:scale-95 transition-all">Unduh PDF</button>
            </div>
          </div>

          {/* Form Pengajuan Izin */}
          <div className="bg-white p-8 md:p-10 rounded-[32px] md:rounded-[48px] border border-slate-100 shadow-sm">
            <h3 className="font-black text-lg text-slate-900 mb-6 uppercase tracking-tight">Ajukan Izin Baru</h3>
            <div className="space-y-4">
              <input type="date" value={leaveDate} onChange={e => setLeaveDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-xl font-bold outline-none" min={todayStr} />
              <textarea value={leaveReason} onChange={e => setLeaveReason(e.target.value)} placeholder="Alasan ketidakhadiran..." className="w-full p-4 bg-white border border-slate-200 rounded-xl font-medium min-h-[100px] outline-none text-sm" />
              <div onClick={() => fileInputRef.current?.click()} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-all bg-white">
                {evidencePhoto ? (
                  <img src={evidencePhoto} alt="Bukti" className="h-20 object-contain rounded-lg shadow-sm" />
                ) : (
                  <div className="text-center text-slate-400">
                    <p className="text-xl">📸</p>
                    <p className="text-[9px] font-black uppercase tracking-widest mt-1">Foto Bukti (Jika ada)</p>
                  </div>
                )}
              </div>
              <input type="file" ref={fileInputRef} onChange={handlePhotoChange} accept="image/*" className="hidden" />
              <button onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason, evidencePhoto); setLeaveDate(''); setLeaveReason(''); setEvidencePhoto(undefined); } }} className="w-full bg-indigo-600 text-white py-5 rounded-xl font-black shadow-lg uppercase tracking-widest text-[10px]">Kirim Pengajuan</button>
            </div>
          </div>
        </div>

        {/* Riwayat - Scrolling Tabel di Mobile */}
        <div className="lg:col-span-7 bg-white p-6 md:p-10 rounded-[32px] md:rounded-[48px] border border-slate-100 shadow-sm min-h-[400px]">
          <h2 className="text-xl font-black text-slate-900 mb-8 tracking-tight uppercase">Riwayat Kehadiran</h2>
          <div className="overflow-x-auto -mx-4 px-4 sm:mx-0 sm:px-0">
            <table className="w-full text-left min-w-[300px]">
              <thead>
                <tr className="text-[9px] font-black uppercase text-slate-400 tracking-widest border-b pb-4">
                  <th className="pb-4">Tanggal</th>
                  <th className="pb-4">Waktu</th>
                  <th className="pb-4 text-right">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {history.map((item, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                    <td className="py-4 font-black text-slate-800 text-sm">{item.date}</td>
                    <td className="py-4 font-bold text-slate-400 text-xs">{item.clockIn || '--:--'}</td>
                    <td className="py-4 text-right">
                      <span className={`px-3 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest ${
                        item.status === 'PRESENT' ? (item.isLate ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700') : 
                        item.status === 'LEAVE_PENDING' ? 'bg-slate-100 text-slate-500' : 
                        item.status === 'LEAVE' ? 'bg-indigo-100 text-indigo-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {item.status === 'PRESENT' ? (item.isLate ? 'Telat' : 'Hadir') : 
                         item.status === 'LEAVE_PENDING' ? 'Menunggu' : 
                         item.status === 'LEAVE' ? 'Izin' : 'Absen'}
                      </span>
                    </td>
                  </tr>
                ))}
                {history.length === 0 && <tr><td colSpan={3} className="text-center py-20 text-slate-300 italic text-sm">Belum ada riwayat.</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeDashboard;

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollMethod } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface OwnerDashboardProps {
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee
}) => {
  const [activeMenu, setActiveMenu] = useState<'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings'>('dashboard');
  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');
  const [adjustments, setAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ 
    name: '', username: '', password: '', gapok: 0, uangMakan: 0, deductionRate: 0, payrollMethod: PayrollMethod.DAILY_30 
  });
  const [tempConfig, setTempConfig] = useState(outletConfig);
  const [selectedPhoto, setSelectedPhoto] = useState<string | null>(null);

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  const getStatsForEmployee = (userId: string) => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const monthRecs = attendance.filter(a => 
      a.userId === userId && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    );
    const onTime = monthRecs.filter(a => a.status === 'PRESENT' && !a.isLate).length;
    const late = monthRecs.filter(a => a.status === 'PRESENT' && a.isLate).length;
    const leaves = monthRecs.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT').length;
    const remaining = Math.max(0, FREE_LEAVE_QUOTA - leaves);
    return { onTime, late, leaves, remaining };
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const data = getMergedAttendance();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 15, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`MONITORING ABSENSI (${attStartDate} - ${attEndDate})`, 105, 22, { align: 'center' });

    const tableRows = data.map(item => [
      employees.find(e => e.id === item.userId)?.name || 'Unknown',
      item.date,
      item.clockIn || '--:--',
      item.statusText
    ]);
    (doc as any).autoTable({
      startY: 30,
      head: [['KARYAWAN', 'TANGGAL', 'JAM MASUK', 'STATUS']],
      body: tableRows,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`absensi_damdam.pdf`);
  };

  const exportPayrollSummaryToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 15, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`LAPORAN GAJI (${payStartDate} - ${payEndDate})`, 105, 22, { align: 'center' });

    const rows = employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => {
      const report = getPayrollForUser(emp);
      return [emp.name, `Rp ${report.grossSalary.toLocaleString()}`, `Rp ${report.bonus.toLocaleString()}`, `Rp ${report.deductions.toLocaleString()}`, `Rp ${report.netSalary.toLocaleString()}`];
    });

    (doc as any).autoTable({
      startY: 35,
      head: [['NAMA', 'KOTOR', 'BONUS', 'POTONGAN', 'BERSIH']],
      body: rows,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });
    doc.save(`laporan_gaji_damdam.pdf`);
  };

  const getMergedAttendance = () => {
    const start = new Date(attStartDate);
    const end = new Date(attEndDate);
    const dailyAtt = attendance.filter(a => {
      const d = new Date(a.date);
      return d >= start && d <= end;
    });
    const combined: any[] = [];
    dailyAtt.forEach(a => {
      let statusText = a.status === 'PRESENT' ? (a.isLate ? 'TERLAMBAT' : 'HADIR') : 
                      a.status === 'LEAVE_PENDING' ? 'MENUNGGU' : 
                      a.status === 'LEAVE' ? 'IZIN' : 'ABSEN';
      combined.push({ ...a, statusText });
    });
    return combined.sort((a, b) => b.date.localeCompare(a.date));
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate || new Date());
    const end = new Date(payEndDate || new Date());
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart);
    const adj = adjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  const handleAdjustmentChange = (userId: string, field: 'bonus' | 'deduction', value: string) => {
    const numValue = parseFloat(value) || 0;
    setAdjustments(prev => ({
      ...prev,
      [userId]: { ...(prev[userId] || { bonus: 0, deduction: 0 }), [field]: numValue }
    }));
  };

  const SidebarItem = ({ icon, label, id }: { icon: string, label: string, id: typeof activeMenu }) => (
    <button
      onClick={() => setActiveMenu(id)}
      className={`whitespace-nowrap flex items-center space-x-2 px-6 py-4 rounded-2xl transition-all ${
        activeMenu === id ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-50'
      }`}
    >
      <span className="text-lg">{icon}</span>
      <span className="font-black text-[10px] uppercase tracking-widest">{label}</span>
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-6 md:gap-8">
      {/* Navigasi - Horizontal Scroll di Mobile, Sidebar di Desktop */}
      <aside className="w-full md:w-64 flex md:flex-col overflow-x-auto md:overflow-visible gap-2 pb-2 md:pb-0 scrollbar-hide">
        <SidebarItem icon="📊" label="Persetujuan" id="dashboard" />
        <SidebarItem icon="👥" label="Karyawan" id="employees" />
        <SidebarItem icon="📅" label="Monitoring" id="attendance" />
        <SidebarItem icon="💰" label="Payroll" id="payroll" />
        <SidebarItem icon="⚙️" label="Pengaturan" id="settings" />
      </aside>

      <div className="flex-1 bg-white rounded-[32px] md:rounded-[48px] border border-slate-100 shadow-sm p-6 md:p-10 min-h-[600px]">
        {activeMenu === 'dashboard' && (
          <div className="space-y-8">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Persetujuan Izin</h2>
            <div className="space-y-4">
              {leaveRequests.filter(l => l.status === 'PENDING').map(l => {
                  const stats = getStatsForEmployee(l.userId);
                  return (
                    <div key={l.id} className="p-6 bg-slate-50 rounded-[24px] border border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                      <div className="flex-1">
                        <div className="flex items-center space-x-3 mb-2">
                          <p className="font-black text-slate-900 text-base">{employees.find(e => e.id === l.userId)?.name}</p>
                          <span className={`text-[8px] px-2 py-1 rounded-full font-black uppercase ${stats.remaining > 0 ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                              Sisa Izin: {stats.remaining}x
                          </span>
                        </div>
                        <p className="text-xs text-slate-500 mb-4">{l.date} — "{l.reason}"</p>
                        {l.evidencePhoto && (
                          <button onClick={() => setSelectedPhoto(l.evidencePhoto!)} className="text-[9px] font-black text-indigo-600 uppercase tracking-widest hover:underline flex items-center">
                            📸 Lihat Bukti Foto
                          </button>
                        )}
                      </div>
                      <div className="flex w-full sm:w-auto space-x-2">
                        <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="flex-1 sm:flex-none bg-indigo-600 text-white px-6 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Setuju</button>
                        <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="flex-1 sm:flex-none bg-red-500 text-white px-6 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Tolak</button>
                      </div>
                    </div>
                  );
              })}
              {leaveRequests.filter(l => l.status === 'PENDING').length === 0 && <p className="text-slate-400 italic text-center py-20 text-sm font-bold">Tidak ada antrean pengajuan.</p>}
            </div>
          </div>
        )}

        {activeMenu === 'employees' && (
          <div className="space-y-8">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
              <h2 className="text-2xl font-black text-slate-900 tracking-tight uppercase">Manajemen Staf</h2>
              <button onClick={() => { setEditingEmp(null); setEmpForm({ name: '', username: '', password: '', gapok: 0, uangMakan: 0, deductionRate: 0, payrollMethod: PayrollMethod.DAILY_30 }); setShowEmpModal(true); }} className="w-full sm:w-auto bg-indigo-600 text-white px-8 py-4 rounded-xl font-black uppercase text-[10px] tracking-widest shadow-lg">+ Tambah Staf</button>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {employees.filter(e => e.role === UserRole.EMPLOYEE).map(e => {
                const stats = getStatsForEmployee(e.id);
                return (
                  <div key={e.id} className="p-6 bg-white border border-slate-100 rounded-[24px] shadow-sm space-y-4">
                    <div className="flex justify-between items-start">
                      <h4 className="text-lg font-black text-slate-900">{e.name}</h4>
                      <div className="flex space-x-2">
                        <button onClick={() => { setEditingEmp(e); setEmpForm(e); setShowEmpModal(true); }} className="text-indigo-600 font-black text-[9px] uppercase">Edit</button>
                        <button onClick={() => onDeleteEmployee(e.id)} className="text-red-500 font-black text-[9px] uppercase">Hapus</button>
