      {activeMenu === 'guide' && (
        <div className="space-y-12">
          <div className="text-center max-w-2xl mx-auto">
             <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase mb-4">Luncurkan ke Cloud 🚀</h2>
             <p className="text-sm font-medium text-slate-500 italic">"Gunakan Cloudflare + Supabase untuk operasional Gratis Rp 0 selamanya."</p>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
             {/* STEP 1: SUPABASE */}
             <div className="bg-slate-50 rounded-[40px] p-10 border border-slate-100 space-y-6">
                <div className="w-12 h-12 bg-green-600 text-white rounded-2xl flex items-center justify-center font-black shadow-lg">1</div>
                <h3 className="text-xl font-black text-slate-900 uppercase">Setup Database (Supabase)</h3>
                <ol className="text-sm text-slate-600 space-y-4 list-decimal ml-4 font-medium">
                   <li>Buat akun di <a href="https://supabase.com" target="_blank" className="text-indigo-600 underline">supabase.com</a></li>
                   <li>Buat Project: <span className="font-bold">DamDam Laundry</span>.</li>
                   <li>Masuk ke <span className="font-bold">SQL Editor</span>, Paste & Run kode di bawah:</li>
                </ol>
                <div className="relative group">
                   <pre className="bg-slate-900 text-slate-300 p-6 rounded-2xl text-[10px] overflow-x-auto max-h-48 border border-white/10">
                      {sqlSchema}
