                   <button onClick={() => copyToClipboard(sqlSchema)} className="absolute top-4 right-4 bg-white/10 hover:bg-white/20 text-white text-[9px] font-black uppercase px-4 py-2 rounded-xl backdrop-blur transition-all">Salin SQL</button>
