                   <p className="font-black text-amber-400 uppercase text-[10px] tracking-[0.2em]">Penyimpanan Foto Izin</p>
                   <p className="text-sm text-slate-300 leading-relaxed font-medium">Limit 1 GB cukup untuk sekitar <span className="text-white font-bold">5.000 foto bukti izin</span>. Jika karyawan jarang izin, ini akan bertahan selamanya.</p>
                </div>
                <div className="space-y-4">
                   <p className="font-black text-amber-400 uppercase text-[10px] tracking-[0.2em]">Status "Paused" (Hibernasi)</p>
                   <p className="text-sm text-slate-300 leading-relaxed font-medium">Jika website tidak dibuka sama sekali selama 7 hari, database akan "tidur". Saat dibuka lagi, tunggu <span className="text-white font-bold">10-20 detik</span> agar sistem bangun otomatis.</p>
                </div>
                <div className="space-y-4">
                   <p className="font-black text-amber-400 uppercase text-[10px] tracking-[0.2em]">Biaya Bulanan</p>
                   <p className="text-sm text-slate-300 leading-relaxed font-medium">Selama data Anda di bawah limit di atas, Anda membayar <span className="text-green-400 font-bold underline">Rp 0 (GRATIS)</span> selamanya ke Supabase dan Cloudflare.</p>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* RENDER LAINNYA DIBAWAH... */}
      {activeMenu === 'attendance' && (
        <div className="space-y-10">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Monitoring Absensi</h2>
          <div className="flex flex-col sm:flex-row justify-between items-end bg-slate-50 p-8 rounded-[32px] gap-6">
            <div className="grid grid-cols-2 gap-4 w-full">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Mulai</label>
                <input type="date" value={attStartDate} onChange={(e) => setAttStartDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-black text-sm outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Selesai</label>
                <input type="date" value={attEndDate} onChange={(e) => setAttEndDate(e.target.value)} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-black text-sm outline-none" />
              </div>
            </div>
          </div>
        </div>
      )}

      {selectedPhoto && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[100] flex flex-col items-center justify-center p-6" onClick={() => setSelectedPhoto(null)}>
           <div className="relative max-w-full max-h-[80vh] bg-white p-4 rounded-[40px] shadow-2xl">
              <img src={selectedPhoto} className="max-w-full max-h-[70vh] rounded-[28px] object-contain shadow-inner" alt="Bukti" />
           </div>
           <button className="mt-10 bg-white text-slate-900 px-12 py-4 rounded-full font-black uppercase text-[11px] tracking-widest hover:bg-indigo-600 hover:text-white transition-all shadow-xl" onClick={() => setSelectedPhoto(null)}>Tutup Preview</button>
        </div>
      )}

      {showEmpModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[60] flex items-center justify-center p-6">
          <div className="bg-white rounded-[48px] w-full max-w-xl p-10 md:p-14 shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-black text-slate-900 mb-8 text-center uppercase tracking-tight">Detail Profil Staf</h3>
            <div className="space-y-6">
              <div className="space-y-1">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Nama Lengkap</label>
                 <input placeholder="Masukkan Nama..." value={empForm.name} onChange={e => setEmpForm({...empForm, name: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Username</label>
                  <input placeholder="Username..." value={empForm.username} onChange={e => setEmpForm({...empForm, username: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Password</label>
                  <input type="password" placeholder="Password..." value={empForm.password} onChange={e => setEmpForm({...empForm, password: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" />
                </div>
              </div>
              <div className="flex gap-4 pt-8">
                <button onClick={() => setShowEmpModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-[11px] tracking-widest hover:bg-slate-200 transition-all">Batalkan</button>
                <button onClick={() => { if(editingEmp) onEditEmployee({...editingEmp, ...empForm} as User); else onAddEmployee(empForm); setShowEmpModal(false); }} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[11px] tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">Simpan Data</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OwnerDashboard;

// File ini digunakan untuk menghubungkan aplikasi ke database Supabase Anda.
// Error 'Invalid URL' biasanya terjadi jika URL yang dimasukkan bukan format http/https yang valid.
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';

// Gunakan process.env yang merupakan standar di Cloudflare Pages / Vercel.
// Kami menyediakan fallback format URL yang valid agar constructor tidak crash saat inisialisasi.
const supabaseUrl = process.env.SUPABASE_URL || 'https://your-project-id.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || 'placeholder-key';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React, { useState, useEffect } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  // Setup penyesuaian payroll awal: Bu Mega bayar kasbon 50rb (mengurangi total kasbon 350rb)
  // Di sini kita asumsikan manualDeduction adalah cicilan kasbon minggu ini atau sisa saldo.
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({
    '3': { bonus: 0, deduction: 50000 } // Bu Mega bayar kasbon 50rb minggu ini
  });
  const [activeMenu, setActiveMenu] = useState<string>('dashboard');
  const [isSyncing, setIsSyncing] = useState(false);
  const [dbError, setDbError] = useState<string | null>(null);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  useEffect(() => {
    fetchInitialData();
  }, []);

  const fetchInitialData = async () => {
    setIsSyncing(true);
    setDbError(null);
    try {
      const [
        { data: userData },
        { data: attData },
        { data: leaveData },
        { data: configData },
        { data: adjData }
      ] = await Promise.all([
        supabase.from('employees').select('*'),
        supabase.from('attendance').select('*').order('date', { ascending: false }),
        supabase.from('leave_requests').select('*'),
        supabase.from('config').select('*').maybeSingle(),
        supabase.from('payroll_adjustments').select('*')
      ]);

      // Integrasi Data Karyawan
      const finalUsers = userData && userData.length > 0 ? userData : MOCK_USERS;
      setUsers(finalUsers);

      // Setup Mock Attendance untuk Izin Januari jika database kosong
      // 2 Izin untuk Bu Mega (ID: 3), 1 Izin untuk Mba Dwi (ID: 2)
      const mockAttendance: AttendanceRecord[] = [
        { id: 'm1', userId: '3', date: '2025-01-06', clockIn: null, clockOut: null, latitude: 0, longitude: 0, status: 'LEAVE' },
        { id: 'm2', userId: '3', date: '2025-01-07', clockIn: null, clockOut: null, latitude: 0, longitude: 0, status: 'LEAVE' },
        { id: 'm3', userId: '2', date: '2025-01-08', clockIn: null, clockOut: null, latitude: 0, longitude: 0, status: 'LEAVE' },
      ];

      if (attData && attData.length > 0) {
        setAttendance(attData);
      } else {
        setAttendance(mockAttendance);
      }

      if (leaveData) setLeaveRequests(leaveData);
      if (configData) setOutletConfig(configData);

      if (adjData && adjData.length > 0) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: curr.bonus, deduction: curr.deduction };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }
    } catch (error: any) {
      console.error("Cloud Sync Error:", error);
      setDbError("Gagal terhubung ke Database. Menggunakan data lokal.");
      setUsers(MOCK_USERS);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    const user = users.find(u => u.username === loginUsername && u.password === loginPassword);
    if (user) {
      setCurrentUser(user);
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => setCurrentUser(null);

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };

    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([newUser]);
  };

  const handleEditEmployee = async (updatedUser: User) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    await supabase.from('employees').update(updatedUser).eq('id', updatedUser.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };

    setAttendance(prev => [...prev, newRecord]);
    await supabase.from('attendance').insert([newRecord]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const now = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: now } : a
    ));

    await supabase.from('attendance')
      .update({ clockOut: now })
      .match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };

    setLeaveRequests(prev => [...prev, newLeave]);
    await supabase.from('leave_requests').insert([newLeave]);

    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };

    setAttendance(prev => {
      const filtered = prev.filter(a => !(a.userId === currentUser.id && a.date === date));
      return [...filtered, newAttRecord];
    });
    await supabase.from('attendance').insert([newAttRecord]);
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);

    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => 
      a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a
    ));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    setOutletConfig(config);
    await supabase.from('config').upsert([config]);
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = {
      ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }),
      [field]: value
    };

    setPayrollAdjustments(prev => ({
      ...prev,
      [userId]: updated
    }));

    await supabase.from('payroll_adjustments').upsert({
      user_id: userId,
      bonus: updated.bonus,
      deduction: updated.deduction
    }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Payroll Cloud System</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all">Login Sistem</button>
          </form>

          <div className="mt-8 pt-8 border-t border-slate-100">
            <div className="flex items-center justify-center space-x-3">
              <div className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : (dbError ? 'bg-red-500' : 'bg-green-500')}`} />
              <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">
                {isSyncing ? 'Sinkronisasi Cloud...' : (dbError ? 'Mode Offline' : 'Cloud Terhubung')}
              </span>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      user={currentUser} 
      onLogout={handleLogout} 
      activeMenu={activeMenu} 
      setActiveMenu={setActiveMenu}
    >
      {isSyncing && (
