// File ini digunakan untuk menghubungkan aplikasi ke database Supabase Anda.
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';

const supabaseUrl = (window as any).env?.SUPABASE_URL || 'http://localhost:54321'; // Default fallback
const supabaseAnonKey = (window as any).env?.SUPABASE_ANON_KEY || 'placeholder';

const isValidUrl = (url: string) => {
  try {
    return url.startsWith('http');
  } catch {
    return false;
  }
};

// Pastikan aplikasi tidak crash jika URL belum dikonfigurasi
export const supabase = (isValidUrl(supabaseUrl) && supabaseAnonKey !== 'placeholder')
  ? createClient(supabaseUrl, supabaseAnonKey)
  : new Proxy({}, {
      get: () => ({
        select: () => ({ order: () => ({ data: null, error: null }), maybeSingle: () => ({ data: null, error: null }), data: null }),
        from: () => ({
          select: () => ({ order: () => ({ data: null, error: null }), maybeSingle: () => ({ data: null, error: null }), data: null }),
          insert: () => Promise.resolve({ data: null, error: null }),
          update: () => ({ eq: () => ({ match: () => Promise.resolve({ data: null, error: null }) }) }),
          delete: () => ({ eq: () => Promise.resolve({ data: null, error: null }) }),
          upsert: () => Promise.resolve({ data: null, error: null })
        })
      })
    }) as any;

