  // Cek window.env (untuk local testing)
  if (typeof window !== 'undefined' && (window as any).env?.[key]) {
    return (window as any).env[key];
  }

  // Cek process.env (Standar Netlify/Node)
  try {
    if (typeof process !== 'undefined' && process.env?.[key]) {
      return process.env[key] as string;
    }
  } catch (e) {
    // Abaikan jika process tidak terdefinisi di browser tertentu
  }

  // Fallback ke string kosong jika tidak ditemukan
  return '';
};

