 * Mendukung standar Vite (VITE_) dan standar Netlify (process.env).
 */
const getEnv = (key: string): string => {
  const viteKey = `VITE_${key}`;

  // 1. Cek window.env (Local/Manual injection)
  if (typeof window !== 'undefined' && (window as any).env?.[key]) return (window as any).env[key];
  if (typeof window !== 'undefined' && (window as any).env?.[viteKey]) return (window as any).env[viteKey];

  // 2. Cek import.meta.env (Standar Vite Modern)
  try {
    const metaEnv = (import.meta as any).env;
    if (metaEnv?.[viteKey]) return metaEnv[viteKey];
    if (metaEnv?.[key]) return metaEnv[key];
  } catch (e) {}

  // 3. Cek process.env (Standar Netlify/Node build time)
  try {
    if (typeof process !== 'undefined' && process.env) {
      return process.env[viteKey] || process.env[key] || '';
    }
  } catch (e) {}

  return '';
};

