import React, { useState, useEffect, useCallback } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('damdam_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [activeMenu, setActiveMenu] = useState<string>(() => {
    return localStorage.getItem('damdam_active_menu') || 'dashboard';
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Fungsi fetch data utama (digunakan untuk polling dan awal)
  const fetchData = useCallback(async (isInitial = false): Promise<User[]> => {
    if (isInitial) setIsSyncing(true);
    else setIsBackgroundSyncing(true);

    let fetchedUsers: User[] = [];

    try {
      // 1. Fetch Employees
      const { data: userData } = await supabase.from('employees').select('*');
      if (userData && userData.length > 0) {
        fetchedUsers = userData.map((u: any) => ({
          id: u.id,
          name: u.name,
          username: u.username,
          password: u.password,
          role: u.role,
          gapok: Number(u.gapok) || 0,
          uangMakan: Number(u.uang_makan) || 0,
          deductionRate: Number(u.deduction_rate) || 0,
          payrollMethod: u.payroll_method,
          isActive: u.is_active
        }));
        setUsers(fetchedUsers);

        // FIX: Hanya update currentUser jika memang ada user yang login (cegah relogin otomatis saat logout)
        if (currentUser) {
          const latestMe = fetchedUsers.find(u => u.id === currentUser.id);
          if (latestMe) {
            setCurrentUser(prev => prev ? { ...prev, ...latestMe } : null);
          }
        }
      } else if (isInitial) {
        setUsers(MOCK_USERS);
        fetchedUsers = MOCK_USERS;
      }

      // 2. Fetch Attendance
      const { data: attData } = await supabase.from('attendance').select('*').order('date', { ascending: false });
      if (attData) {
        setAttendance(attData.map((a: any) => ({
          id: a.id,
          userId: a.user_id,
          date: a.date,
          clockIn: a.clock_in,
          clockOut: a.clock_out,
          latitude: a.latitude !== null ? Number(a.latitude) : 0,
          longitude: a.longitude !== null ? Number(a.longitude) : 0,
          status: a.status,
          isLate: a.is_late,
          leaveRequestId: a.leave_request_id
        })));
      }

      // 3. Fetch Config
      const { data: configData } = await supabase.from('config').select('*').eq('id', 1).maybeSingle();
      if (configData) {
        setOutletConfig({
          latitude: configData.latitude !== null ? Number(configData.latitude) : INITIAL_OUTLET_CONFIG.latitude,
          longitude: configData.longitude !== null ? Number(configData.longitude) : INITIAL_OUTLET_CONFIG.longitude,
          radius: configData.radius !== null ? Number(configData.radius) : INITIAL_OUTLET_CONFIG.radius,
          clockInTime: configData.clock_in_time || INITIAL_OUTLET_CONFIG.clockInTime,
          clockOutTime: configData.clock_out_time || INITIAL_OUTLET_CONFIG.clockOutTime
        });
      }

      // 4. Fetch Adjustments
      const { data: adjData } = await supabase.from('payroll_adjustments').select('*');
      if (adjData) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: Number(curr.bonus), deduction: Number(curr.deduction) };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }

      // 5. Fetch Leave Requests
      const { data: leaveData } = await supabase.from('leave_requests').select('*').order('date', { ascending: false });
      if (leaveData) {
        setLeaveRequests(leaveData.map((l: any) => ({
          id: l.id,
          userId: l.user_id,
          date: l.date,
          reason: l.reason,
          status: l.status,
          evidencePhoto: l.evidence_photo
        })));
      }

    } catch (error) {
      console.error("Cloud Sync Error:", error);
    } finally {
      setIsSyncing(false);
      setIsBackgroundSyncing(false);
    }
    return fetchedUsers;
  }, [currentUser]);

  // Initial Data Fetch
  useEffect(() => {
    fetchData(true);
  }, []);

  // Polling Auto-Sync setiap 15 detik
  useEffect(() => {
    const interval = setInterval(() => {
      fetchData(false);
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchData]);

  // Simpan user ke localStorage jika berubah
  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
    }
  }, [currentUser]);

  // Simpan activeMenu ke localStorage
  useEffect(() => {
    localStorage.setItem('damdam_active_menu', activeMenu);
  }, [activeMenu]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');

    let foundUser = users.find(u => u.username === loginUsername && u.password === loginPassword);

    if (!foundUser) {
      const freshUsers = await fetchData(true);
      foundUser = freshUsers.find(u => u.username === loginUsername && u.password === loginPassword);
    }

    if (foundUser) {
      setCurrentUser(foundUser);
      setActiveMenu(foundUser.role === UserRole.OWNER ? 'dashboard' : 'home');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => {
    // Gunakan konfirmasi browser standar tapi pastikan state dibersihkan segera
    if (window.confirm('Keluar dari aplikasi?')) {
      localStorage.clear(); // Bersihkan semua data local
      setCurrentUser(null);
    }
  };

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };

    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([{
      id: newUser.id,
      name: newUser.name,
      username: newUser.username,
      password: newUser.password,
      role: newUser.role,
      gapok: newUser.gapok,
      uang_makan: newUser.uangMakan,
      deduction_rate: newUser.deductionRate,
      payroll_method: newUser.payrollMethod,
      is_active: newUser.isActive
    }]);
  };

  const handleEditEmployee = async (u: User) => {
    setUsers(prev => prev.map(item => item.id === u.id ? u : item));
    await supabase.from('employees').update({
      name: u.name,
      username: u.username,
      password: u.password,
      role: u.role,
      gapok: u.gapok,
      uang_makan: u.uangMakan,
      deduction_rate: u.deductionRate,
      // Fix: Property 'payroll_method' does not exist on type 'User'. Corrected to 'payrollMethod'.
      payroll_method: u.payrollMethod,
      is_active: u.isActive
    }).eq('id', u.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };

    setAttendance(prev => [newRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newRecord.id,
      user_id: newRecord.userId,
      date: newRecord.date,
      clock_in: newRecord.clockIn,
      status: newRecord.status,
      is_late: newRecord.isLate,
      latitude: newRecord.latitude,
      longitude: newRecord.longitude
    }]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const nowTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: nowTime } : a
    ));

    await supabase.from('attendance')
      .update({ clock_out: nowTime })
      .match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };

    setLeaveRequests(prev => [newLeave, ...prev]);
    await supabase.from('leave_requests').insert([{
      id: newLeave.id,
      user_id: newLeave.userId,
      date: newLeave.date,
      reason: newLeave.reason,
      status: newLeave.status,
      evidence_photo: newLeave.evidencePhoto
    }]);

    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };

    setAttendance(prev => [newAttRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newAttRecord.id,
      user_id: newAttRecord.userId,
      date: newAttRecord.date,
      status: newAttRecord.status,
      leave_request_id: newAttRecord.leaveRequestId
    }]);
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);

    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => 
      a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a
    ));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    const lat = parseFloat(String(config.latitude));
    const lng = parseFloat(String(config.longitude));
    const rad = parseInt(String(config.radius));

    const updatedConfig = { ...config, latitude: lat, longitude: lng, radius: rad };
    setOutletConfig(updatedConfig);

    try {
      const configToSave = {
        id: 1, 
        latitude: lat,
        longitude: lng,
        radius: rad,
        clock_in_time: config.clockInTime,
        clock_out_time: config.clockOutTime
      };

      const { error } = await supabase.from('config').upsert([configToSave], { onConflict: 'id' });
      if (error) throw error;
      alert('Konfigurasi outlet berhasil disimpan ke Cloud!');
    } catch (err: any) {
      alert("Gagal simpan config: " + err.message);
    }
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = {
      ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }),
      [field]: value
    };

    setPayrollAdjustments(prev => ({ ...prev, [userId]: updated }));

    await supabase.from('payroll_adjustments').upsert({
      user_id: userId,
      bonus: updated.bonus,
      deduction: updated.deduction
    }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Payroll Cloud System</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" disabled={isSyncing} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all disabled:opacity-50">
              {isSyncing ? 'MENGHUBUNGKAN...' : 'LOGIN SISTEM'}
            </button>
          </form>
          <div className="mt-8 flex items-center justify-center space-x-2">
             <div className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`} />
             <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">SINKRONISASI AKTIF</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} activeMenu={activeMenu} setActiveMenu={setActiveMenu}>
      {isBackgroundSyncing && (
        <div className="fixed bottom-6 right-6 z-50 flex items-center space-x-2 bg-white/90 backdrop-blur shadow-lg px-4 py-2 rounded-full border border-slate-100">
           <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>
           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">SINKRONISASI CLOUD...</span>
        </div>
      )}

      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave}
          payrollAdjustments={payrollAdjustments[currentUser.id] || { bonus: 0, deduction: 0 }}
        />
      ) : (
        <OwnerDashboard 
          activeMenu={activeMenu as any}
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onUpdateConfig={handleUpdateConfig} 
          onApproveLeave={handleApproveLeave} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee}
          payrollAdjustments={payrollAdjustments}
          onUpdateAdjustment={handleUpdateAdjustment}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('damdam_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [activeMenu, setActiveMenu] = useState<string>(() => {
    return localStorage.getItem('damdam_active_menu') || 'dashboard';
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Ref untuk melacak status login terbaru tanpa terikat closure callback
  const currentUserRef = useRef<User | null>(currentUser);
  useEffect(() => {
    currentUserRef.current = currentUser;
  }, [currentUser]);

  // Fungsi fetch data utama
  const fetchData = useCallback(async (isInitial = false): Promise<User[]> => {
    if (isInitial) setIsSyncing(true);
    else setIsBackgroundSyncing(true);

    let fetchedUsers: User[] = [];

    try {
      // 1. Fetch Employees
      const { data: userData } = await supabase.from('employees').select('*');
      if (userData && userData.length > 0) {
        fetchedUsers = userData.map((u: any) => ({
          id: u.id,
          name: u.name,
          username: u.username,
          password: u.password,
          role: u.role,
          gapok: Number(u.gapok) || 0,
          uangMakan: Number(u.uang_makan) || 0,
          deductionRate: Number(u.deduction_rate) || 0,
          payrollMethod: u.payroll_method,
          isActive: u.is_active
        }));
        setUsers(fetchedUsers);

        // Hanya update jika user masih dalam status login (cegah relogin otomatis saat logout)
        const currentRef = currentUserRef.current;
        if (currentRef) {
          const latestMe = fetchedUsers.find(u => u.id === currentRef.id);
          if (latestMe) {
            setCurrentUser(prev => prev ? { ...prev, ...latestMe } : null);
          }
        }
      } else if (isInitial) {
        setUsers(MOCK_USERS);
        fetchedUsers = MOCK_USERS;
      }

      // 2. Fetch Attendance
      const { data: attData } = await supabase.from('attendance').select('*').order('date', { ascending: false });
      if (attData) {
        setAttendance(attData.map((a: any) => ({
          id: a.id,
          userId: a.user_id,
          date: a.date,
          clockIn: a.clock_in,
          clockOut: a.clock_out,
          latitude: a.latitude !== null ? Number(a.latitude) : 0,
          longitude: a.longitude !== null ? Number(a.longitude) : 0,
          status: a.status,
          isLate: a.is_late,
          leaveRequestId: a.leave_request_id
        })));
      }

      // 3. Fetch Config
      const { data: configData } = await supabase.from('config').select('*').eq('id', 1).maybeSingle();
      if (configData) {
        setOutletConfig({
          latitude: configData.latitude !== null ? Number(configData.latitude) : INITIAL_OUTLET_CONFIG.latitude,
          longitude: configData.longitude !== null ? Number(configData.longitude) : INITIAL_OUTLET_CONFIG.longitude,
          radius: configData.radius !== null ? Number(configData.radius) : INITIAL_OUTLET_CONFIG.radius,
          clockInTime: configData.clock_in_time || INITIAL_OUTLET_CONFIG.clockInTime,
          clockOutTime: configData.clock_out_time || INITIAL_OUTLET_CONFIG.clockOutTime
        });
      }

      // 4. Fetch Adjustments
      const { data: adjData } = await supabase.from('payroll_adjustments').select('*');
      if (adjData) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: Number(curr.bonus), deduction: Number(curr.deduction) };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }

      // 5. Fetch Leave Requests
      const { data: leaveData } = await supabase.from('leave_requests').select('*').order('date', { ascending: false });
      if (leaveData) {
        setLeaveRequests(leaveData.map((l: any) => ({
          id: l.id,
          userId: l.user_id,
          date: l.date,
          reason: l.reason,
          status: l.status,
          evidencePhoto: l.evidence_photo
        })));
      }

    } catch (error) {
      console.error("Cloud Sync Error:", error);
    } finally {
      setIsSyncing(false);
      setIsBackgroundSyncing(false);
    }
    return fetchedUsers;
  }, []); // Hapus currentUser dari dep agar tidak re-create interval setiap detik

  // Initial Data Fetch
  useEffect(() => {
    fetchData(true);
  }, [fetchData]);

  // Polling Auto-Sync setiap 15 detik (Hanya jika ada user login)
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      fetchData(false);
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchData, currentUser]);

  // Simpan user ke localStorage
  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
    }
  }, [currentUser]);

  // Simpan activeMenu ke localStorage
  useEffect(() => {
    localStorage.setItem('damdam_active_menu', activeMenu);
  }, [activeMenu]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');

    let foundUser = users.find(u => u.username === loginUsername && u.password === loginPassword);

    if (!foundUser) {
      const freshUsers = await fetchData(true);
      foundUser = freshUsers.find(u => u.username === loginUsername && u.password === loginPassword);
    }

    if (foundUser) {
      setCurrentUser(foundUser);
      setActiveMenu(foundUser.role === UserRole.OWNER ? 'dashboard' : 'home');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => {
    // Segera hapus state dan storage tanpa menunggu konfirmasi berbelit
    localStorage.removeItem('damdam_user');
    localStorage.removeItem('damdam_active_menu');
    setCurrentUser(null);
    setAttendance([]);
    setLeaveRequests([]);
    // Memberikan feedback instan ke user
  };

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };

    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([{
      id: newUser.id,
      name: newUser.name,
      username: newUser.username,
      password: newUser.password,
      role: newUser.role,
      gapok: newUser.gapok,
      uang_makan: newUser.uangMakan,
      deduction_rate: newUser.deductionRate,
      payroll_method: newUser.payrollMethod,
      is_active: newUser.isActive
    }]);
  };

  const handleEditEmployee = async (u: User) => {
    setUsers(prev => prev.map(item => item.id === u.id ? u : item));
    await supabase.from('employees').update({
      name: u.name,
      username: u.username,
      password: u.password,
      role: u.role,
      gapok: u.gapok,
      uang_makan: u.uangMakan,
      deduction_rate: u.deductionRate,
      payroll_method: u.payrollMethod,
      is_active: u.isActive
    }).eq('id', u.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };

    setAttendance(prev => [newRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newRecord.id,
      user_id: newRecord.userId,
      date: newRecord.date,
      clock_in: newRecord.clockIn,
      status: newRecord.status,
      is_late: newRecord.isLate,
      latitude: newRecord.latitude,
      longitude: newRecord.longitude
    }]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const nowTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: nowTime } : a
    ));

    await supabase.from('attendance')
      .update({ clock_out: nowTime })
      .match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };

    setLeaveRequests(prev => [newLeave, ...prev]);
    await supabase.from('leave_requests').insert([{
      id: newLeave.id,
      user_id: newLeave.userId,
      date: newLeave.date,
      reason: newLeave.reason,
      status: newLeave.status,
      evidence_photo: newLeave.evidencePhoto
    }]);

    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };

    setAttendance(prev => [newAttRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newAttRecord.id,
      user_id: newAttRecord.userId,
      date: newAttRecord.date,
      status: newAttRecord.status,
      leave_request_id: newAttRecord.leaveRequestId
    }]);
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);

    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => 
      a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a
    ));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    const lat = parseFloat(String(config.latitude));
    const lng = parseFloat(String(config.longitude));
    const rad = parseInt(String(config.radius));

    const updatedConfig = { ...config, latitude: lat, longitude: lng, radius: rad };
    setOutletConfig(updatedConfig);

    try {
      const configToSave = {
        id: 1, 
        latitude: lat,
        longitude: lng,
        radius: rad,
        clock_in_time: config.clockInTime,
        clock_out_time: config.clockOutTime
      };

      const { error } = await supabase.from('config').upsert([configToSave], { onConflict: 'id' });
      if (error) throw error;
      alert('Konfigurasi outlet berhasil disimpan ke Cloud!');
    } catch (err: any) {
      alert("Gagal simpan config: " + err.message);
    }
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = {
      ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }),
      [field]: value
    };

    setPayrollAdjustments(prev => ({ ...prev, [userId]: updated }));

    await supabase.from('payroll_adjustments').upsert({
      user_id: userId,
      bonus: updated.bonus,
      deduction: updated.deduction
    }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Payroll Cloud System</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" disabled={isSyncing} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all disabled:opacity-50">
              {isSyncing ? 'MENGHUBUNGKAN...' : 'LOGIN SISTEM'}
            </button>
          </form>
          <div className="mt-8 flex items-center justify-center space-x-2">
             <div className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`} />
             <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">SINKRONISASI AKTIF</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} activeMenu={activeMenu} setActiveMenu={setActiveMenu}>
      {isBackgroundSyncing && currentUser && (
        <div className="fixed bottom-6 right-6 z-50 flex items-center space-x-2 bg-white/90 backdrop-blur shadow-lg px-4 py-2 rounded-full border border-slate-100">
           <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>
           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">SINKRONISASI CLOUD...</span>
        </div>
      )}

      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave}
          payrollAdjustments={payrollAdjustments[currentUser.id] || { bonus: 0, deduction: 0 }}
        />
      ) : (
        <OwnerDashboard 
          activeMenu={activeMenu as any}
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onUpdateConfig={handleUpdateConfig} 
          onApproveLeave={handleApproveLeave} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee}
          payrollAdjustments={payrollAdjustments}
          onUpdateAdjustment={handleUpdateAdjustment}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('damdam_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [activeMenu, setActiveMenu] = useState<string>(() => {
    return localStorage.getItem('damdam_active_menu') || 'dashboard';
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Menggunakan Ref untuk melacak status login terbaru guna menghindari race condition pada async fetch
  const isLoggingOut = useRef(false);

  const fetchData = useCallback(async (isInitial = false): Promise<User[]> => {
    // Jangan lakukan sinkronisasi jika sedang dalam proses logout
    if (isLoggingOut.current) return [];

    if (isInitial) setIsSyncing(true);
    else setIsBackgroundSyncing(true);

    let fetchedUsers: User[] = [];

    try {
      // 1. Fetch Employees
      const { data: userData } = await supabase.from('employees').select('*');
      if (userData && userData.length > 0) {
        fetchedUsers = userData.map((u: any) => ({
          id: u.id,
          name: u.name,
          username: u.username,
          password: u.password,
          role: u.role,
          gapok: Number(u.gapok) || 0,
          uangMakan: Number(u.uang_makan) || 0,
          deductionRate: Number(u.deduction_rate) || 0,
          payrollMethod: u.payroll_method,
          isActive: u.is_active
        }));
        setUsers(fetchedUsers);

        // Update profile user login jika masih aktif
        if (currentUser && !isLoggingOut.current) {
          const latestMe = fetchedUsers.find(u => u.id === currentUser.id);
          if (latestMe) setCurrentUser(prev => prev ? {...prev, ...latestMe} : latestMe);
        }
      } else if (isInitial) {
        setUsers(MOCK_USERS);
        fetchedUsers = MOCK_USERS;
      }

      // 2. Fetch Attendance
      const { data: attData } = await supabase.from('attendance').select('*').order('date', { ascending: false });
      if (attData) {
        setAttendance(attData.map((a: any) => ({
          id: a.id,
          userId: a.user_id,
          date: a.date,
          clockIn: a.clock_in,
          clockOut: a.clock_out,
          latitude: a.latitude !== null ? Number(a.latitude) : 0,
          longitude: a.longitude !== null ? Number(a.longitude) : 0,
          status: a.status,
          isLate: a.is_late,
          leaveRequestId: a.leave_request_id
        })));
      }

      // 3. Fetch Config
      const { data: configData } = await supabase.from('config').select('*').eq('id', 1).maybeSingle();
      if (configData) {
        setOutletConfig({
          latitude: configData.latitude !== null ? Number(configData.latitude) : INITIAL_OUTLET_CONFIG.latitude,
          longitude: configData.longitude !== null ? Number(configData.longitude) : INITIAL_OUTLET_CONFIG.longitude,
          radius: configData.radius !== null ? Number(configData.radius) : INITIAL_OUTLET_CONFIG.radius,
          clockInTime: configData.clock_in_time || INITIAL_OUTLET_CONFIG.clockInTime,
          clockOutTime: configData.clock_out_time || INITIAL_OUTLET_CONFIG.clockOutTime
        });
      }

      // 4. Fetch Adjustments
      const { data: adjData } = await supabase.from('payroll_adjustments').select('*');
      if (adjData) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: Number(curr.bonus), deduction: Number(curr.deduction) };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }

      // 5. Fetch Leave Requests - PASTIKAN SELALU TERAMBIL TERBARU
      const { data: leaveData } = await supabase.from('leave_requests').select('*').order('date', { ascending: false });
      if (leaveData) {
        setLeaveRequests(leaveData.map((l: any) => ({
          id: l.id,
          userId: l.user_id,
          date: l.date,
          reason: l.reason,
          status: l.status,
          evidencePhoto: l.evidence_photo
        })));
      }

    } catch (error) {
      console.error("Cloud Sync Error:", error);
    } finally {
      setIsSyncing(false);
      setIsBackgroundSyncing(false);
    }
    return fetchedUsers;
  }, [currentUser]);

  // Initial Data Fetch
  useEffect(() => {
    fetchData(true);
  }, []);

  // Polling Auto-Sync setiap 15 detik (Hanya jika user login)
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      fetchData(false);
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchData, currentUser]);

  // Simpan/Hapus user ke localStorage
  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
    }
  }, [currentUser]);

  // Simpan activeMenu ke localStorage
  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_active_menu', activeMenu);
    }
  }, [activeMenu, currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    isLoggingOut.current = false;

    let foundUser = users.find(u => u.username === loginUsername && u.password === loginPassword);

    if (!foundUser) {
      const freshUsers = await fetchData(true);
      foundUser = freshUsers.find(u => u.username === loginUsername && u.password === loginPassword);
    }

    if (foundUser) {
      setCurrentUser(foundUser);
      setActiveMenu(foundUser.role === UserRole.OWNER ? 'dashboard' : 'home');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => {
    if (confirm('Apakah Anda yakin ingin keluar?')) {
      isLoggingOut.current = true;
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
      setCurrentUser(null);
      setAttendance([]);
      setLeaveRequests([]);
      setLoginUsername('');
      setLoginPassword('');
    }
  };

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };

    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([{
      id: newUser.id,
      name: newUser.name,
      username: newUser.username,
      password: newUser.password,
      role: newUser.role,
      gapok: newUser.gapok,
      uang_makan: newUser.uangMakan,
      deduction_rate: newUser.deductionRate,
      payroll_method: newUser.payrollMethod,
      is_active: newUser.isActive
    }]);
  };

  const handleEditEmployee = async (u: User) => {
    setUsers(prev => prev.map(item => item.id === u.id ? u : item));
    await supabase.from('employees').update({
      name: u.name,
      username: u.username,
      password: u.password,
      role: u.role,
      gapok: u.gapok,
      uang_makan: u.uangMakan,
      deduction_rate: u.deductionRate,
      payroll_method: u.payrollMethod,
      is_active: u.isActive
    }).eq('id', u.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };

    setAttendance(prev => [newRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newRecord.id,
      user_id: newRecord.userId,
      date: newRecord.date,
      clock_in: newRecord.clockIn,
      status: newRecord.status,
      is_late: newRecord.isLate,
      latitude: newRecord.latitude,
      longitude: newRecord.longitude
    }]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const nowTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: nowTime } : a
    ));

    await supabase.from('attendance')
      .update({ clock_out: nowTime })
      .match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };

    // Simpan ke state lokal agar langsung terlihat
    setLeaveRequests(prev => [newLeave, ...prev]);

    // Simpan ke Supabase
    await supabase.from('leave_requests').insert([{
      id: newLeave.id,
      user_id: newLeave.userId,
      date: newLeave.date,
      reason: newLeave.reason,
      status: newLeave.status,
      evidence_photo: newLeave.evidencePhoto
    }]);

    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };

    setAttendance(prev => [newAttRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newAttRecord.id,
      user_id: newAttRecord.userId,
      date: newAttRecord.date,
      status: newAttRecord.status,
      leave_request_id: newAttRecord.leaveRequestId
    }]);

    alert('Izin berhasil diajukan! Menunggu persetujuan owner.');
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);

    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => 
      a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a
    ));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    const lat = parseFloat(String(config.latitude));
    const lng = parseFloat(String(config.longitude));
    const rad = parseInt(String(config.radius));

    const updatedConfig = { ...config, latitude: lat, longitude: lng, radius: rad };
    setOutletConfig(updatedConfig);

    try {
      const configToSave = {
        id: 1, 
        latitude: lat,
        longitude: lng,
        radius: rad,
        clock_in_time: config.clockInTime,
        clock_out_time: config.clockOutTime
      };

      const { error } = await supabase.from('config').upsert([configToSave], { onConflict: 'id' });
      if (error) throw error;
      alert('Konfigurasi outlet berhasil disimpan ke Cloud!');
    } catch (err: any) {
      alert("Gagal simpan config: " + err.message);
    }
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = {
      ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }),
      [field]: value
    };

    setPayrollAdjustments(prev => ({ ...prev, [userId]: updated }));

    await supabase.from('payroll_adjustments').upsert({
      user_id: userId,
      bonus: updated.bonus,
      deduction: updated.deduction
    }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Payroll Cloud System</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" disabled={isSyncing} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all disabled:opacity-50">
              {isSyncing ? 'MENGHUBUNGKAN...' : 'LOGIN SISTEM'}
            </button>
          </form>
          <div className="mt-8 flex items-center justify-center space-x-2">
             <div className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`} />
             <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">SINKRONISASI AKTIF</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} activeMenu={activeMenu} setActiveMenu={setActiveMenu}>
      {isBackgroundSyncing && (
        <div className="fixed bottom-6 right-6 z-50 flex items-center space-x-2 bg-white/90 backdrop-blur shadow-lg px-4 py-2 rounded-full border border-slate-100">
           <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>
           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">SINKRONISASI CLOUD...</span>
        </div>
      )}

      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave}
          payrollAdjustments={payrollAdjustments[currentUser.id] || { bonus: 0, deduction: 0 }}
        />
      ) : (
        <OwnerDashboard 
          activeMenu={activeMenu as any}
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onApproveLeave={handleApproveLeave} 
          onUpdateConfig={handleUpdateConfig} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee}
          payrollAdjustments={payrollAdjustments}
          onUpdateAdjustment={handleUpdateAdjustment}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('damdam_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [activeMenu, setActiveMenu] = useState<string>(() => {
    return localStorage.getItem('damdam_active_menu') || 'dashboard';
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Ref untuk mengunci proses async agar tidak mengganggu proses logout
  const isLoggingOutRef = useRef(false);

  const fetchData = useCallback(async (isInitial = false): Promise<User[]> => {
    if (isLoggingOutRef.current) return [];

    if (isInitial) setIsSyncing(true);
    else setIsBackgroundSyncing(true);

    let fetchedUsers: User[] = [];

    try {
      // 1. Fetch Employees
      const { data: userData } = await supabase.from('employees').select('*');
      if (userData && userData.length > 0) {
        fetchedUsers = userData.map((u: any) => ({
          id: u.id,
          name: u.name,
          username: u.username,
          password: u.password,
          role: u.role,
          gapok: Number(u.gapok) || 0,
          uangMakan: Number(u.uang_makan) || 0,
          deductionRate: Number(u.deduction_rate) || 0,
          payrollMethod: u.payroll_method,
          isActive: u.is_active
        }));
        setUsers(fetchedUsers);

        // Hanya update profile jika tidak sedang logout
        if (!isLoggingOutRef.current) {
          const savedUser = localStorage.getItem('damdam_user');
          if (savedUser) {
            const current = JSON.parse(savedUser);
            const latestMe = fetchedUsers.find(u => u.id === current.id);
            if (latestMe) setCurrentUser(latestMe);
          }
        }
      } else if (isInitial) {
        setUsers(MOCK_USERS);
        fetchedUsers = MOCK_USERS;
      }

      // 2. Fetch Attendance
      const { data: attData } = await supabase.from('attendance').select('*').order('date', { ascending: false });
      if (attData) {
        setAttendance(attData.map((a: any) => ({
          id: a.id,
          userId: a.user_id,
          date: a.date,
          clockIn: a.clock_in,
          clockOut: a.clock_out,
          latitude: a.latitude !== null ? Number(a.latitude) : 0,
          longitude: a.longitude !== null ? Number(a.longitude) : 0,
          status: a.status,
          isLate: a.is_late,
          leaveRequestId: a.leave_request_id
        })));
      }

      // 3. Fetch Config
      const { data: configData } = await supabase.from('config').select('*').eq('id', 1).maybeSingle();
      if (configData) {
        setOutletConfig({
          latitude: configData.latitude !== null ? Number(configData.latitude) : INITIAL_OUTLET_CONFIG.latitude,
          longitude: configData.longitude !== null ? Number(configData.longitude) : INITIAL_OUTLET_CONFIG.longitude,
          radius: configData.radius !== null ? Number(configData.radius) : INITIAL_OUTLET_CONFIG.radius,
          clockInTime: configData.clock_in_time || INITIAL_OUTLET_CONFIG.clockInTime,
          clockOutTime: configData.clock_out_time || INITIAL_OUTLET_CONFIG.clockOutTime
        });
      }

      // 4. Fetch Adjustments
      const { data: adjData } = await supabase.from('payroll_adjustments').select('*');
      if (adjData) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: Number(curr.bonus), deduction: Number(curr.deduction) };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }

      // 5. Fetch Leave Requests
      const { data: leaveData } = await supabase.from('leave_requests').select('*').order('date', { ascending: false });
      if (leaveData) {
        setLeaveRequests(leaveData.map((l: any) => ({
          id: l.id,
          userId: l.user_id,
          date: l.date,
          reason: l.reason,
          status: l.status,
          evidencePhoto: l.evidence_photo
        })));
      }

    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsBackgroundSyncing(false);
    }
    return fetchedUsers;
  }, []);

  useEffect(() => {
    fetchData(true);
  }, [fetchData]);

  // Polling Auto-Sync (Hanya jika user sedang login)
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      if (!isLoggingOutRef.current) fetchData(false);
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchData, currentUser]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
    }
  }, [currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    isLoggingOutRef.current = false;

    let foundUser = users.find(u => u.username === loginUsername && u.password === loginPassword);

    if (!foundUser) {
      const freshUsers = await fetchData(true);
      foundUser = freshUsers.find(u => u.username === loginUsername && u.password === loginPassword);
    }

    if (foundUser) {
      setCurrentUser(foundUser);
      setActiveMenu(foundUser.role === UserRole.OWNER ? 'dashboard' : 'home');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => {
    // Segera blokir proses background sync
    isLoggingOutRef.current = true;

    // Bersihkan semua jejak session
    localStorage.removeItem('damdam_user');
    localStorage.removeItem('damdam_active_menu');

    // Update state secara massal
    setCurrentUser(null);
    setAttendance([]);
    setLeaveRequests([]);
    setLoginUsername('');
    setLoginPassword('');

    // Redirect instan ke halaman login
  };

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };

    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([{
      id: newUser.id,
      name: newUser.name,
      username: newUser.username,
      password: newUser.password,
      role: newUser.role,
      gapok: newUser.gapok,
      uang_makan: newUser.uangMakan,
      deduction_rate: newUser.deductionRate,
      payroll_method: newUser.payrollMethod,
      is_active: newUser.isActive
    }]);
  };

  const handleEditEmployee = async (u: User) => {
    setUsers(prev => prev.map(item => item.id === u.id ? u : item));
    await supabase.from('employees').update({
      name: u.name,
      username: u.username,
      password: u.password,
      role: u.role,
      gapok: u.gapok,
      uang_makan: u.uangMakan,
      deduction_rate: u.deductionRate,
      payroll_method: u.payrollMethod,
      is_active: u.isActive
    }).eq('id', u.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };

    setAttendance(prev => [newRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newRecord.id,
      user_id: newRecord.userId,
      date: newRecord.date,
      clock_in: newRecord.clockIn,
      status: newRecord.status,
      is_late: newRecord.isLate,
      latitude: newRecord.latitude,
      longitude: newRecord.longitude
    }]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const nowTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: nowTime } : a
    ));

    await supabase.from('attendance')
      .update({ clock_out: nowTime })
      .match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };

    setLeaveRequests(prev => [newLeave, ...prev]);

    await supabase.from('leave_requests').insert([{
      id: newLeave.id,
      user_id: newLeave.userId,
      date: newLeave.date,
      reason: newLeave.reason,
      status: newLeave.status,
      evidence_photo: newLeave.evidencePhoto
    }]);

    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };

    setAttendance(prev => [newAttRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newAttRecord.id,
      user_id: newAttRecord.userId,
      date: newAttRecord.date,
      status: newAttRecord.status,
      leave_request_id: newAttRecord.leaveRequestId
    }]);

    alert('Izin terkirim. Menunggu persetujuan owner.');
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);

    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => 
      a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a
    ));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    setOutletConfig(config);
    await supabase.from('config').upsert([{
      id: 1, 
      latitude: config.latitude,
      longitude: config.longitude,
      radius: config.radius,
      clock_in_time: config.clockInTime,
      clock_out_time: config.clockOutTime
    }]);
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = {
      ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }),
      [field]: value
    };
    setPayrollAdjustments(prev => ({ ...prev, [userId]: updated }));
    await supabase.from('payroll_adjustments').upsert({
      user_id: userId,
      bonus: updated.bonus,
      deduction: updated.deduction
    }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Payroll Cloud System</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" disabled={isSyncing} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all disabled:opacity-50">
              {isSyncing ? 'MENGHUBUNGKAN...' : 'MASUK KE SISTEM'}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} activeMenu={activeMenu} setActiveMenu={setActiveMenu}>
      {isBackgroundSyncing && (
        <div className="fixed bottom-6 right-6 z-50 flex items-center space-x-2 bg-white/90 backdrop-blur shadow-lg px-4 py-2 rounded-full border border-slate-100">
           <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>
           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Sinkronisasi...</span>
        </div>
      )}

      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave}
          payrollAdjustments={payrollAdjustments[currentUser.id] || { bonus: 0, deduction: 0 }}
        />
      ) : (
        <OwnerDashboard 
          activeMenu={activeMenu as any}
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onApproveLeave={handleApproveLeave} 
          onUpdateConfig={handleUpdateConfig} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee}
          payrollAdjustments={payrollAdjustments}
          onUpdateAdjustment={handleUpdateAdjustment}
        />
      )}
    </Layout>
  );
};

export default App;

