                  value={tempConfig.latitude} 
                  onChange={e => {
                    const val = e.target.value;
                    setTempConfig({...tempConfig, latitude: val as any});
                  }} 
                  onBlur={e => {
                    const num = parseFloat(e.target.value) || 0;
                    setTempConfig({...tempConfig, latitude: num});
