                  type="text" 
                  inputMode="decimal"
                  value={tempConfig.longitude} 
                  onChange={e => {
                    const val = e.target.value;
                    setTempConfig({...tempConfig, longitude: val as any});
                  }} 
                  onBlur={e => {
                    const num = parseFloat(e.target.value) || 0;
                    setTempConfig({...tempConfig, longitude: num});
                  }}
                  className="w-full p-5 bg-white border border-slate-200 rounded-2xl font-black text-sm outline-none focus:border-indigo-500 transition-all" 
                />
              </div>
            </div>
            <div className="p-6 bg-amber-50 rounded-2xl border border-amber-100">
               <p className="text-[10px] font-bold text-amber-700 uppercase leading-relaxed tracking-wide">
                 ⚠️ Pastikan koordinat akurat. Jika tidak sesuai, karyawan tidak akan bisa melakukan absen masuk di lokasi outlet.
               </p>
            </div>
            <button onClick={handleSaveConfig} className="w-full bg-indigo-600 text-white py-6 rounded-2xl font-black uppercase text-[11px] tracking-widest shadow-2xl hover:bg-indigo-700 active:scale-95 transition-all">Simpan Konfigurasi Sekarang</button>
          </div>
        </div>
      )}

      {selectedPhoto && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[100] flex flex-col items-center justify-center p-6" onClick={() => setSelectedPhoto(null)}>
           <div className="relative max-w-full max-h-[80vh] bg-white p-4 rounded-[40px] shadow-2xl">
              <img src={selectedPhoto} className="max-w-full max-h-[70vh] rounded-[28px] object-contain shadow-inner" alt="Bukti" />
           </div>
           <button className="mt-10 bg-white text-slate-900 px-12 py-4 rounded-full font-black uppercase text-[11px] tracking-widest hover:bg-indigo-600 hover:text-white transition-all shadow-xl" onClick={() => setSelectedPhoto(null)}>Tutup Preview</button>
        </div>
      )}

      {showEmpModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[60] flex items-center justify-center p-6">
          <div className="bg-white rounded-[48px] w-full max-w-xl p-10 md:p-14 shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-2xl font-black text-slate-900 mb-8 text-center uppercase tracking-tight">Detail Profil Staf</h3>
            <div className="space-y-6">
              <div className="space-y-1">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Nama Lengkap</label>
                 <input placeholder="Masukkan Nama..." value={empForm.name} onChange={e => setEmpForm({...empForm, name: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Username (Login)</label>
                  <input placeholder="Username..." value={empForm.username} onChange={e => setEmpForm({...empForm, username: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Password</label>
                  <input type="password" placeholder="Password..." value={empForm.password} onChange={e => setEmpForm({...empForm, password: e.target.value})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" />
                </div>
              </div>
              <div className="grid grid-cols-3 gap-3">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Gapok</label>
                  <input type="number" placeholder="Rp" value={empForm.gapok} onChange={e => setEmpForm({...empForm, gapok: parseInt(e.target.value) || 0})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-xs outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Makan</label>
                  <input type="number" placeholder="Rp" value={empForm.uangMakan} onChange={e => setEmpForm({...empForm, uangMakan: parseInt(e.target.value) || 0})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-xs outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Potongan</label>
                  <input type="number" placeholder="Rp" value={empForm.deductionRate} onChange={e => setEmpForm({...empForm, deductionRate: parseInt(e.target.value) || 0})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-xs outline-none" />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Metode Payroll</label>
                <select value={empForm.payrollMethod} onChange={e => setEmpForm({...empForm, payrollMethod: e.target.value as PayrollMethod})} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none appearance-none">
                  <option value={PayrollMethod.DAILY_30}>Harian (Total / 30 Hari)</option>
                  <option value={PayrollMethod.FIXED_4}>Mingguan (Total / 4 Minggu)</option>
                </select>
              </div>
              <div className="flex gap-4 pt-8">
                <button onClick={() => setShowEmpModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-[11px] tracking-widest hover:bg-slate-200 transition-all">Batalkan</button>
                <button onClick={() => { if(editingEmp) onEditEmployee({...editingEmp, ...empForm} as User); else onAddEmployee(empForm); setShowEmpModal(false); }} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-[11px] tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">Simpan Data</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OwnerDashboard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('damdam_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [activeMenu, setActiveMenu] = useState<string>(() => {
    return localStorage.getItem('damdam_active_menu') || 'dashboard';
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Flag untuk benar-benar menghentikan semua aktifitas async saat logout
  const isTerminated = useRef(false);

  const fetchData = useCallback(async (isInitial = false): Promise<User[]> => {
    if (isTerminated.current) return [];

    if (isInitial) setIsSyncing(true);
    else setIsBackgroundSyncing(true);

    let fetchedUsers: User[] = [];

    try {
      // 1. Fetch Employees - Perbaikan Logika Fallback
      const { data: userData, error: userError } = await supabase.from('employees').select('*');

      // Jika database cloud memberikan data, gunakan itu.
      // Jika data kosong ATAU error (mock mode), gunakan MOCK_USERS sebagai fallback.
      if (userData && userData.length > 0) {
        fetchedUsers = userData.map((u: any) => ({
          id: u.id,
          name: u.name,
          username: u.username,
          password: u.password,
          role: u.role,
          gapok: Number(u.gapok) || 0,
          uangMakan: Number(u.uang_makan) || 0,
          deductionRate: Number(u.deduction_rate) || 0,
          payrollMethod: u.payroll_method,
          isActive: u.is_active
        }));
      } else {
        // Fallback ke MOCK_USERS jika DB kosong atau gagal (Initial Load)
        fetchedUsers = MOCK_USERS;
      }

      setUsers(fetchedUsers);

      // 2. Fetch Attendance
      const { data: attData } = await supabase.from('attendance').select('*').order('date', { ascending: false });
      if (attData) {
        setAttendance(attData.map((a: any) => ({
          id: a.id,
          userId: a.user_id,
          date: a.date,
          clockIn: a.clock_in,
          clockOut: a.clock_out,
          latitude: a.latitude !== null ? Number(a.latitude) : 0,
          longitude: a.longitude !== null ? Number(a.longitude) : 0,
          status: a.status,
          isLate: a.is_late,
          leaveRequestId: a.leave_request_id
        })));
      }

      // 3. Fetch Config
      const { data: configData } = await supabase.from('config').select('*').eq('id', 1).maybeSingle();
      if (configData) {
        setOutletConfig({
          latitude: configData.latitude !== null ? Number(configData.latitude) : INITIAL_OUTLET_CONFIG.latitude,
          longitude: configData.longitude !== null ? Number(configData.longitude) : INITIAL_OUTLET_CONFIG.longitude,
          radius: configData.radius !== null ? Number(configData.radius) : INITIAL_OUTLET_CONFIG.radius,
          clockInTime: configData.clock_in_time || INITIAL_OUTLET_CONFIG.clockInTime,
          clockOutTime: configData.clock_out_time || INITIAL_OUTLET_CONFIG.clockOutTime
        });
      }

      // 4. Fetch Adjustments
      const { data: adjData } = await supabase.from('payroll_adjustments').select('*');
      if (adjData) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: Number(curr.bonus), deduction: Number(curr.deduction) };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }

      // 5. Fetch Leave Requests
      const { data: leaveData } = await supabase.from('leave_requests').select('*').order('date', { ascending: false });
      if (leaveData) {
        setLeaveRequests(leaveData.map((l: any) => ({
          id: l.id,
          userId: l.user_id,
          date: l.date,
          reason: l.reason,
          status: String(l.status).toUpperCase() as any,
          evidencePhoto: l.evidence_photo
        })));
      }

    } catch (error) {
      console.error("Sinkronisasi gagal:", error);
      // Jika gagal koneksi total, pastikan ada user untuk login di mode offline
      if (users.length === 0) setUsers(MOCK_USERS);
    } finally {
      setIsSyncing(false);
      setIsBackgroundSyncing(false);
    }
    return fetchedUsers;
  }, [users.length]);

  useEffect(() => {
    fetchData(true);
  }, []);

  // Polling Auto-Sync (Hanya jika user sedang login)
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      if (!isTerminated.current) fetchData(false);
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchData, currentUser]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
    }
  }, [currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    isTerminated.current = false;

    // Gunakan users yang ada atau coba fetch ulang sekali lagi
    let currentUsers = users.length > 0 ? users : await fetchData(true);

    const foundUser = currentUsers.find(
      u => u.username === loginUsername && String(u.password) === String(loginPassword)
    );

    if (foundUser) {
      setCurrentUser(foundUser);
      setActiveMenu(foundUser.role === UserRole.OWNER ? 'dashboard' : 'home');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => {
    if (!confirm('Keluar dari sistem?')) return;

    isTerminated.current = true;
    localStorage.removeItem('damdam_user');
    localStorage.removeItem('damdam_active_menu');

    setCurrentUser(null);
    setAttendance([]);
    setLeaveRequests([]);
    setLoginUsername('');
    setLoginPassword('');
  };

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };

    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([{
      id: newUser.id,
      name: newUser.name,
      username: newUser.username,
      password: newUser.password,
      role: newUser.role,
      gapok: newUser.gapok,
      uang_makan: newUser.uangMakan,
      deduction_rate: newUser.deductionRate,
      payroll_method: newUser.payrollMethod,
      is_active: newUser.isActive
    }]);
  };

  const handleEditEmployee = async (u: User) => {
    setUsers(prev => prev.map(item => item.id === u.id ? u : item));
    await supabase.from('employees').update({
      name: u.name,
      username: u.username,
      password: u.password,
      role: u.role,
      gapok: u.gapok,
      uang_makan: u.uangMakan,
      deduction_rate: u.deductionRate,
      payroll_method: u.payrollMethod,
      is_active: u.isActive
    }).eq('id', u.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };

    setAttendance(prev => [newRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newRecord.id,
      user_id: newRecord.userId,
      date: newRecord.date,
      clock_in: newRecord.clockIn,
      status: newRecord.status,
      is_late: newRecord.isLate,
      latitude: newRecord.latitude,
      longitude: newRecord.longitude
    }]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const nowTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: nowTime } : a
    ));

    await supabase.from('attendance')
      .update({ clock_out: nowTime })
      .match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };

    setLeaveRequests(prev => [newLeave, ...prev]);

    await supabase.from('leave_requests').insert([{
      id: newLeave.id,
      user_id: newLeave.userId,
      date: newLeave.date,
      reason: newLeave.reason,
      status: 'PENDING',
      evidence_photo: newLeave.evidencePhoto
    }]);

    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };

    setAttendance(prev => [newAttRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newAttRecord.id,
      user_id: newAttRecord.userId,
      date: newAttRecord.date,
      status: 'LEAVE_PENDING',
      leave_request_id: newAttRecord.leaveRequestId
    }]);

    alert('Izin terkirim. Menunggu persetujuan owner.');
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);

    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => 
      a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a
    ));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    setOutletConfig(config);
    await supabase.from('config').upsert([{
      id: 1, 
      latitude: config.latitude,
      longitude: config.longitude,
      radius: config.radius,
      clock_in_time: config.clockInTime,
      clock_out_time: config.clockOutTime
    }]);
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = {
      ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }),
      [field]: value
    };
    setPayrollAdjustments(prev => ({ ...prev, [userId]: updated }));
    await supabase.from('payroll_adjustments').upsert({
      user_id: userId,
      bonus: updated.bonus,
      deduction: updated.deduction
    }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Payroll Cloud System</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" disabled={isSyncing} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all disabled:opacity-50">
              {isSyncing ? 'MENGHUBUNGKAN...' : 'MASUK KE SISTEM'}
            </button>
          </form>
          <div className="mt-8 flex justify-center items-center space-x-2">
            <div className={`w-1.5 h-1.5 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></div>
            <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
              {isSyncing ? 'Sinkronisasi Cloud...' : 'Sistem Cloud Aktif'}
            </span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} activeMenu={activeMenu} setActiveMenu={setActiveMenu}>
      {isBackgroundSyncing && (
        <div className="fixed bottom-6 right-6 z-50 flex items-center space-x-2 bg-white/90 backdrop-blur shadow-lg px-4 py-2 rounded-full border border-slate-100">
           <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>
           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Syncing...</span>
        </div>
      )}

      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave}
          payrollAdjustments={payrollAdjustments[currentUser.id] || { bonus: 0, deduction: 0 }}
        />
      ) : (
        <OwnerDashboard 
          activeMenu={activeMenu as any}
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onApproveLeave={handleApproveLeave} 
          onUpdateConfig={handleUpdateConfig} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee}
          payrollAdjustments={payrollAdjustments}
          onUpdateAdjustment={handleUpdateAdjustment}
          onRefreshData={() => fetchData(false)}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, UserRole, AttendanceRecord, LeaveRequest, OutletConfig, PayrollMethod } from './types';
import { MOCK_USERS, INITIAL_OUTLET_CONFIG } from './constants';
import Layout from './components/Layout';
import EmployeeDashboard from './components/EmployeeDashboard';
import OwnerDashboard from './components/OwnerDashboard';
import { supabase } from './services/supabaseClient';

const App: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('damdam_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [activeMenu, setActiveMenu] = useState<string>(() => {
    return localStorage.getItem('damdam_active_menu') || 'dashboard';
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Flag untuk menghentikan aktivitas async saat logout
  const isTerminated = useRef(false);

  const fetchData = useCallback(async (isInitial = false): Promise<User[]> => {
    if (isTerminated.current) return [];

    if (isInitial) setIsSyncing(true);
    else setIsBackgroundSyncing(true);

    let fetchedUsers: User[] = [];

    try {
      // 1. Fetch Employees
      const { data: userData } = await supabase.from('employees').select('*');
      if (isTerminated.current) return [];

      if (userData && userData.length > 0) {
        fetchedUsers = userData.map((u: any) => ({
          id: u.id,
          name: u.name,
          username: u.username,
          password: u.password,
          role: u.role,
          gapok: Number(u.gapok) || 0,
          uangMakan: Number(u.uang_makan) || 0,
          deductionRate: Number(u.deduction_rate) || 0,
          payrollMethod: u.payroll_method,
          isActive: u.is_active
        }));
      } else {
        fetchedUsers = MOCK_USERS;
      }

      setUsers(fetchedUsers);

      // 2. Fetch Attendance
      const { data: attData } = await supabase.from('attendance').select('*').order('date', { ascending: false });
      if (isTerminated.current) return fetchedUsers;

      if (attData) {
        setAttendance(attData.map((a: any) => ({
          id: a.id,
          userId: a.user_id,
          date: a.date,
          clockIn: a.clock_in,
          clockOut: a.clock_out,
          latitude: a.latitude !== null ? Number(a.latitude) : 0,
          longitude: a.longitude !== null ? Number(a.longitude) : 0,
          status: a.status,
          isLate: a.is_late,
          leaveRequestId: a.leave_request_id
        })));
      }

      // 3. Fetch Config
      const { data: configData } = await supabase.from('config').select('*').eq('id', 1).maybeSingle();
      if (isTerminated.current) return fetchedUsers;

      if (configData) {
        setOutletConfig({
          latitude: configData.latitude !== null ? Number(configData.latitude) : INITIAL_OUTLET_CONFIG.latitude,
          longitude: configData.longitude !== null ? Number(configData.longitude) : INITIAL_OUTLET_CONFIG.longitude,
          radius: configData.radius !== null ? Number(configData.radius) : INITIAL_OUTLET_CONFIG.radius,
          clockInTime: configData.clock_in_time || INITIAL_OUTLET_CONFIG.clockInTime,
          clockOutTime: configData.clock_out_time || INITIAL_OUTLET_CONFIG.clockOutTime
        });
      }

      // 4. Fetch Adjustments
      const { data: adjData } = await supabase.from('payroll_adjustments').select('*');
      if (isTerminated.current) return fetchedUsers;

      if (adjData) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: Number(curr.bonus), deduction: Number(curr.deduction) };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }

      // 5. Fetch Leave Requests
      const { data: leaveData } = await supabase.from('leave_requests').select('*').order('date', { ascending: false });
      if (isTerminated.current) return fetchedUsers;

      if (leaveData) {
        setLeaveRequests(leaveData.map((l: any) => ({
          id: l.id,
          userId: l.user_id,
          date: l.date,
          reason: l.reason,
          status: String(l.status).toUpperCase() as any,
          evidencePhoto: l.evidence_photo
        })));
      }

    } catch (error) {
      console.error("Sinkronisasi gagal:", error);
      if (users.length === 0) setUsers(MOCK_USERS);
    } finally {
      setIsSyncing(false);
      setIsBackgroundSyncing(false);
    }
    return fetchedUsers;
  }, [users.length]);

  useEffect(() => {
    fetchData(true);
  }, []);

  // Polling Auto-Sync
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      if (!isTerminated.current) fetchData(false);
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchData, currentUser]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_user', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
    }
  }, [currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    isTerminated.current = false;

    let currentUsers = users.length > 0 ? users : await fetchData(true);

    const foundUser = currentUsers.find(
      u => u.username === loginUsername && String(u.password) === String(loginPassword)
    );

    if (foundUser) {
      setCurrentUser(foundUser);
      setActiveMenu(foundUser.role === UserRole.OWNER ? 'dashboard' : 'home');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => {
    // Logout instan tanpa confirm untuk menghindari isu di mobile/iOS
    isTerminated.current = true;

    // Hapus data session segera
    localStorage.removeItem('damdam_user');
    localStorage.removeItem('damdam_active_menu');

    // Reset State Aplikasi secara total
    setCurrentUser(null);
    setAttendance([]);
    setLeaveRequests([]);
    setUsers([]);
    setLoginUsername('');
    setLoginPassword('');
    setLoginError('');
  };

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      isActive: true
    };

    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([{
      id: newUser.id,
      name: newUser.name,
      username: newUser.username,
      password: newUser.password,
      role: newUser.role,
      gapok: newUser.gapok,
      uang_makan: newUser.uangMakan,
      deduction_rate: newUser.deductionRate,
      payroll_method: newUser.payrollMethod,
      is_active: newUser.isActive
    }]);
  };

  const handleEditEmployee = async (u: User) => {
    setUsers(prev => prev.map(item => item.id === u.id ? u : item));
    await supabase.from('employees').update({
      name: u.name,
      username: u.username,
      password: u.password,
      role: u.role,
      gapok: u.gapok,
      uang_makan: u.uangMakan,
      deduction_rate: u.deductionRate,
      payroll_method: u.payrollMethod,
      is_active: u.isActive
    }).eq('id', u.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime,
      clockOut: null,
      latitude: lat,
      longitude: lng,
      status: 'PRESENT',
      isLate: isLate
    };

    setAttendance(prev => [newRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newRecord.id,
      user_id: newRecord.userId,
      date: newRecord.date,
      clock_in: newRecord.clockIn,
      status: newRecord.status,
      is_late: newRecord.isLate,
      latitude: newRecord.latitude,
      longitude: newRecord.longitude
    }]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const nowTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: nowTime } : a
    ));

    await supabase.from('attendance')
      .update({ clock_out: nowTime })
      .match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = {
      id: leaveId,
      userId: currentUser.id,
      date,
      reason,
      status: 'PENDING',
      evidencePhoto: photo
    };

    setLeaveRequests(prev => [newLeave, ...prev]);

    await supabase.from('leave_requests').insert([{
      id: newLeave.id,
      user_id: newLeave.userId,
      date: newLeave.date,
      reason: newLeave.reason,
      status: 'PENDING',
      evidence_photo: newLeave.evidencePhoto
    }]);

    const newAttRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date,
      clockIn: null,
      clockOut: null,
      latitude: 0,
      longitude: 0,
      status: 'LEAVE_PENDING',
      leaveRequestId: leaveId
    };

    setAttendance(prev => [newAttRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newAttRecord.id,
      user_id: newAttRecord.userId,
      date: newAttRecord.date,
      status: 'LEAVE_PENDING',
      leave_request_id: newAttRecord.leaveRequestId
    }]);

    alert('Izin terkirim. Menunggu persetujuan owner.');
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);

    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => 
      a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a
    ));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    setOutletConfig(config);
    await supabase.from('config').upsert([{
      id: 1, 
      latitude: config.latitude,
      longitude: config.longitude,
      radius: config.radius,
      clock_in_time: config.clockInTime,
      clock_out_time: config.clockOutTime
    }]);
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = {
      ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }),
      [field]: value
    };
    setPayrollAdjustments(prev => ({ ...prev, [userId]: updated }));
    await supabase.from('payroll_adjustments').upsert({
      user_id: userId,
      bonus: updated.bonus,
      deduction: updated.deduction
    }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100">
              <span className="text-4xl text-white">🧺</span>
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">Payroll Cloud System</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" disabled={isSyncing} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all disabled:opacity-50">
              {isSyncing ? 'MENGHUBUNGKAN...' : 'MASUK KE SISTEM'}
            </button>
          </form>
          <div className="mt-8 flex justify-center items-center space-x-2">
            <div className={`w-1.5 h-1.5 rounded-full ${isSyncing ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></div>
            <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
              {isSyncing ? 'Sinkronisasi Cloud...' : 'Sistem Cloud Aktif'}
            </span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} activeMenu={activeMenu} setActiveMenu={setActiveMenu}>
      {isBackgroundSyncing && (
        <div className="fixed bottom-6 right-6 z-50 flex items-center space-x-2 bg-white/90 backdrop-blur shadow-lg px-4 py-2 rounded-full border border-slate-100">
           <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>
           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Syncing...</span>
        </div>
      )}

      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard 
          user={currentUser} 
          outletConfig={outletConfig} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          onClockIn={handleClockIn} 
          onClockOut={handleClockOut} 
          onSubmitLeave={handleSubmitLeave}
          payrollAdjustments={payrollAdjustments[currentUser.id] || { bonus: 0, deduction: 0 }}
        />
      ) : (
        <OwnerDashboard 
          activeMenu={activeMenu as any}
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onApproveLeave={handleApproveLeave} 
          onUpdateConfig={handleUpdateConfig} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee}
          payrollAdjustments={payrollAdjustments}
          onUpdateAdjustment={handleUpdateAdjustment}
          onRefreshData={() => fetchData(false)}
        />
      )}
    </Layout>
  );
};

