    const isActuallyAbsent = !record || record.status === 'ABSENT';
    const isLeave = record?.status === 'LEAVE';
    const isPresent = record?.status === 'PRESENT';

    if (isActuallyAbsent || isLeave) {
      monthlyAbsentCounter++;

      if (isInCurrentWeek) {
        weekLeave++;

        if (isDwi) {
          // ATURAN DWI:
          // 1-3 kali: Potong 20rb (Uang Makan)
          // > 3 kali: Potong 70rb (Gapok + Makan)
          if (monthlyAbsentCounter <= 3) {
            totalDeductionsThisWeek += 20000;
          } else {
            totalDeductionsThisWeek += 70000;
            excessLeaveCountThisWeek++;
          }
        } else if (isMega) {
          // ATURAN MEGA:
          // 1-3 kali: Potong 0 (Gratis)
          // > 3 kali: Potong 55rb
          if (monthlyAbsentCounter > 3) {
            totalDeductionsThisWeek += 55000;
            excessLeaveCountThisWeek++;
          }
        } else {
          // ATURAN UMUM: Potong jika lewat jatah standar (3 hari)
          if (monthlyAbsentCounter > FREE_LEAVE_QUOTA) {
            totalDeductionsThisWeek += dailyRateForDeduction;
            excessLeaveCountThisWeek++;
          }
        }
      }
    } else if (isPresent && isInCurrentWeek) {
      weekPresent++;
      if (record.isLate) weekLate++;
      else weekOnTime++;
    }
  });

  const totalDeductions = totalDeductionsThisWeek + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: weekPresent,
    totalOnTime: weekOnTime,
    totalLate: weekLate,
    totalLeave: weekLeave,
    monthlyLeaveCount: monthlyAbsentCounter,
    excessLeaveCount: excessLeaveCountThisWeek,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: dailyRateForDeduction,
    methodLabel
  };
};

