import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

export const calculateWeeklyPayroll = (
  user: User,
  records: AttendanceRecord[], 
  allRecordsThisMonth: AttendanceRecord[], 
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  const usernameLower = user.username.toLowerCase();
  const isDwi = usernameLower.includes('dwi');
  const isMega = usernameLower.includes('mega');
  const isDaily30 = user.payrollMethod === PayrollMethod.DAILY_30;

  // 1. Tentukan Base Mingguan & Label
  let weeklyBase = 0;
  let methodLabel = isDaily30 ? 'Harian (Bagi 30)' : 'Mingguan (Bagi 4)';
  let dailyRateForDeduction = 0;

  if (isDwi) {
    // Dwi: 375rb (Gapok) + 140rb (Makan 7 hari) = 515rb
    weeklyBase = 515000;
    dailyRateForDeduction = 20000; 
  } else if (isMega) {
    // Mega: 1.65jt / 4 = 412.500
    weeklyBase = user.gapok / 4;
    dailyRateForDeduction = 55000;
  } else {
    const dailyGapok = user.gapok / DAYS_IN_MONTH;
    const dailyUangMakan = user.uangMakan / DAYS_IN_MONTH;
    dailyRateForDeduction = user.deductionRate || (dailyGapok + dailyUangMakan);

    if (isDaily30) {
      weeklyBase = (dailyGapok + dailyUangMakan) * 7;
    } else {
      weeklyBase = (user.gapok + user.uangMakan) / 4;
    }
  }

  const todayStr = new Date().toISOString().split('T')[0];
  const monthStart = new Date(weekEnd.getFullYear(), weekEnd.getMonth(), 1);

  let monthlyAbsentCounter = 0;
  let totalDeductionsThisWeek = 0;
  let excessLeaveCountThisWeek = 0;
  let weekPresent = 0;
  let weekOnTime = 0;
  let weekLate = 0;
  let weekLeave = 0;

  // Siapkan urutan tanggal dari awal bulan sampai akhir minggu ini
  const datesToProcess: Date[] = [];
  const tempDate = new Date(monthStart);
  while (tempDate <= weekEnd) {
    datesToProcess.push(new Date(tempDate));
    tempDate.setDate(tempDate.getDate() + 1);
  }

  datesToProcess.forEach(d => {
    const dateStr = d.toISOString().split('T')[0];

    // Jangan hitung hari yang belum terjadi
    if (dateStr > todayStr && dateStr > weekEnd.toISOString().split('T')[0]) return;

    const record = allRecordsThisMonth.find(r => r.date === dateStr);
    const isInCurrentWeek = d >= weekStart && d <= weekEnd;

    const isActuallyAbsent = !record || record.status === 'ABSENT';
    const isLeave = record?.status === 'LEAVE';
    const isPresent = record?.status === 'PRESENT';

    if (isActuallyAbsent || isLeave) {
      monthlyAbsentCounter++;

      if (isInCurrentWeek) {
        weekLeave++;

        if (isDwi) {
          // ATURAN DWI:
          // 1-3 kali: Potong 20rb (Uang Makan)
          // > 3 kali: Potong 70rb (Gapok + Makan)
          if (monthlyAbsentCounter <= 3) {
            totalDeductionsThisWeek += 20000;
          } else {
            totalDeductionsThisWeek += 70000;
            excessLeaveCountThisWeek++;
          }
        } else if (isMega) {
          // ATURAN MEGA:
          // 1-3 kali: Potong 0 (Gratis)
          // > 3 kali: Potong 55rb
          if (monthlyAbsentCounter > 3) {
            totalDeductionsThisWeek += 55000;
            excessLeaveCountThisWeek++;
          }
        } else {
          // ATURAN UMUM: Potong jika lewat jatah standar (3 hari)
          if (monthlyAbsentCounter > FREE_LEAVE_QUOTA) {
            totalDeductionsThisWeek += dailyRateForDeduction;
            excessLeaveCountThisWeek++;
          }
        }
      }
    } else if (isPresent && isInCurrentWeek) {
      weekPresent++;
      if (record.isLate) weekLate++;
      else weekOnTime++;
    }
  });

  const totalDeductions = totalDeductionsThisWeek + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStart.toISOString().split('T')[0],
    weekEndDate: weekEnd.toISOString().split('T')[0],
    totalPresent: weekPresent,
    totalOnTime: weekOnTime,
    totalLate: weekLate,
    totalLeave: weekLeave,
    monthlyLeaveCount: monthlyAbsentCounter,
    excessLeaveCount: excessLeaveCountThisWeek,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: dailyRateForDeduction,
    methodLabel,
    totalKasbon: user.totalKasbon // Masukkan saldo kasbon ke report
  };
};

