  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [outletConfig, setOutletConfig] = useState<OutletConfig>(INITIAL_OUTLET_CONFIG);
  const [payrollAdjustments, setPayrollAdjustments] = useState<Record<string, { bonus: number, deduction: number }>>({});

  const [activeMenu, setActiveMenu] = useState<string>(() => {
    return localStorage.getItem('damdam_active_menu') || 'dashboard';
  });

  const [isSyncing, setIsSyncing] = useState(false);
  const [isBackgroundSyncing, setIsBackgroundSyncing] = useState(false);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const isTerminated = useRef(false);

  const fetchData = useCallback(async (isInitial = false): Promise<User[]> => {
    if (isTerminated.current) return [];

    if (isInitial) setIsSyncing(true);
    else setIsBackgroundSyncing(true);

    let fetchedUsers: User[] = [];

    try {
      const { data: userData } = await supabase.from('employees').select('*');
      if (isTerminated.current) return [];

      if (userData && userData.length > 0) {
        fetchedUsers = userData.map((u: any) => ({
          id: u.id,
          name: u.name,
          username: u.username,
          password: u.password,
          role: u.role,
          gapok: Number(u.gapok) || 0,
          uangMakan: Number(u.uang_makan) || 0,
          deductionRate: Number(u.deduction_rate) || 0,
          payrollMethod: u.payroll_method,
          totalKasbon: Number(u.total_kasbon) || 0,
          isActive: u.is_active
        }));
      } else {
        fetchedUsers = MOCK_USERS;
      }
      setUsers(fetchedUsers);

      const { data: leaveData } = await supabase.from('leave_requests').select('*').order('date', { ascending: false });
      let currentLeaves: LeaveRequest[] = [];
      if (leaveData) {
        currentLeaves = leaveData.map((l: any) => ({
          id: l.id,
          userId: l.user_id,
          date: l.date,
          reason: l.reason,
          status: String(l.status).toUpperCase() as any,
          evidencePhoto: l.evidence_photo
        }));
        setLeaveRequests(currentLeaves);
      }

      const { data: attData } = await supabase.from('attendance').select('*').order('date', { ascending: false });
      if (isTerminated.current) return fetchedUsers;

      let currentAtt: AttendanceRecord[] = [];
      if (attData) {
        currentAtt = attData.map((a: any) => ({
          id: a.id,
          userId: a.user_id,
          date: a.date,
          clockIn: a.clock_in,
          clockOut: a.clock_out,
          latitude: a.latitude !== null ? Number(a.latitude) : 0,
          longitude: a.longitude !== null ? Number(a.longitude) : 0,
          status: String(a.status).toUpperCase() as any,
          isLate: a.is_late,
          leaveRequestId: a.leave_request_id
        }));
      }

      const today = new Date();
      const monthStart = new Date(today.getFullYear(), today.getMonth(), 1);
      const yesterday = new Date(today);
      yesterday.setDate(today.getDate() - 1);

      fetchedUsers.forEach(emp => {
        if (emp.role !== UserRole.EMPLOYEE) return;
        for (let d = new Date(monthStart); d <= yesterday; d.setDate(d.getDate() + 1)) {
          const dateStr = d.toISOString().split('T')[0];
          const hasRecord = currentAtt.some(a => a.userId === emp.id && a.date === dateStr);
          const approvedLeave = currentLeaves.find(l => l.userId === emp.id && l.date === dateStr && l.status === 'APPROVED');
          const pendingLeave = currentLeaves.find(l => l.userId === emp.id && l.date === dateStr && l.status === 'PENDING');
          if (!hasRecord) {
            currentAtt.push({
              id: `auto-${emp.id}-${dateStr}`,
              userId: emp.id,
              date: dateStr,
              clockIn: null, clockOut: null, latitude: 0, longitude: 0,
              status: approvedLeave ? 'LEAVE' : (pendingLeave ? 'LEAVE_PENDING' : 'ABSENT'),
              leaveRequestId: approvedLeave?.id || pendingLeave?.id
            });
          }
        }
      });
      setAttendance(currentAtt.sort((a,b) => b.date.localeCompare(a.date)));

      const { data: configData } = await supabase.from('config').select('*').eq('id', 1).maybeSingle();
      if (configData) {
        setOutletConfig({
          latitude: configData.latitude !== null ? Number(configData.latitude) : INITIAL_OUTLET_CONFIG.latitude,
          longitude: configData.longitude !== null ? Number(configData.longitude) : INITIAL_OUTLET_CONFIG.longitude,
          radius: configData.radius !== null ? Number(configData.radius) : INITIAL_OUTLET_CONFIG.radius,
          clockInTime: configData.clock_in_time || INITIAL_OUTLET_CONFIG.clockInTime,
          clockOutTime: configData.clock_out_time || INITIAL_OUTLET_CONFIG.clockOutTime
        });
      }

      const { data: adjData } = await supabase.from('payroll_adjustments').select('*');
      if (adjData) {
        const adjMap = adjData.reduce((acc: any, curr: any) => {
          acc[curr.user_id] = { bonus: Number(curr.bonus), deduction: Number(curr.deduction) };
          return acc;
        }, {});
        setPayrollAdjustments(adjMap);
      }

    } catch (error) {
      console.error("Sinkronisasi gagal:", error);
      if (users.length === 0) setUsers(MOCK_USERS);
    } finally {
      setIsSyncing(false);
      setIsBackgroundSyncing(false);
    }
    return fetchedUsers;
  }, [users.length]);

  useEffect(() => { fetchData(true); }, []);

  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(() => {
      if (!isTerminated.current) fetchData(false);
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchData, currentUser]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('damdam_user', JSON.stringify(currentUser));
      localStorage.setItem('damdam_active_menu', activeMenu);
    } else {
      localStorage.removeItem('damdam_user');
      localStorage.removeItem('damdam_active_menu');
    }
  }, [currentUser, activeMenu]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    isTerminated.current = false;
    let currentUsers = users.length > 0 ? users : await fetchData(true);
    const foundUser = currentUsers.find(
      u => u.username === loginUsername && String(u.password) === String(loginPassword)
    );
    if (foundUser) {
      setCurrentUser(foundUser);
      setActiveMenu(foundUser.role === UserRole.OWNER ? 'dashboard' : 'home');
    } else {
      setLoginError('Username atau password salah.');
    }
  };

  const handleLogout = () => {
    isTerminated.current = true;
    localStorage.removeItem('damdam_user');
    localStorage.removeItem('damdam_active_menu');
    setCurrentUser(null);
    setAttendance([]);
    setLeaveRequests([]);
    setUsers([]);
    setLoginUsername('');
    setLoginPassword('');
  };

  const handleUpdateKasbon = async (userId: string, amount: number) => {
    const user = users.find(u => u.id === userId);
    if (!user) return;
    const newTotal = Math.max(0, user.totalKasbon + amount);
    setUsers(prev => prev.map(u => u.id === userId ? { ...u, totalKasbon: newTotal } : u));
    await supabase.from('employees').update({ total_kasbon: newTotal }).eq('id', userId);
  };

  const handleAddEmployee = async (userData: Partial<User>) => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name || 'Karyawan Baru',
      username: userData.username || 'emp' + Math.floor(Math.random() * 100),
      password: userData.password || '123456', 
      role: UserRole.EMPLOYEE,
      gapok: userData.gapok || 0,
      uangMakan: userData.uangMakan || 0,
      deductionRate: userData.deductionRate || 0,
      payrollMethod: userData.payrollMethod || PayrollMethod.DAILY_30,
      totalKasbon: userData.totalKasbon || 0,
      isActive: true
    };
    setUsers(prev => [...prev, newUser]);
    await supabase.from('employees').insert([{
      id: newUser.id,
      name: newUser.name,
      username: newUser.username,
      password: newUser.password,
      role: newUser.role,
      gapok: newUser.gapok,
      uang_makan: newUser.uangMakan,
      deduction_rate: newUser.deductionRate,
      payroll_method: newUser.payrollMethod,
      total_kasbon: newUser.totalKasbon,
      is_active: newUser.isActive
    }]);
  };

  const handleEditEmployee = async (u: User) => {
    setUsers(prev => prev.map(item => item.id === u.id ? u : item));
    await supabase.from('employees').update({
      name: u.name,
      username: u.username,
      password: u.password,
      gapok: u.gapok,
      uang_makan: u.uangMakan,
      deduction_rate: u.deductionRate,
      payroll_method: u.payrollMethod,
      total_kasbon: u.totalKasbon,
      is_active: u.isActive
    }).eq('id', u.id);
  };

  const handleDeleteEmployee = async (userId: string) => {
    if (confirm('Hapus karyawan ini?')) {
      setUsers(prev => prev.filter(u => u.id !== userId));
      await supabase.from('employees').delete().eq('id', userId);
    }
  };

  const handleClockIn = async (lat: number, lng: number) => {
    if (!currentUser) return;
    const now = new Date();
    const clockInTime = now.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    const [nowH, nowM] = clockInTime.split(':').map(Number);
    const [targetH, targetM] = outletConfig.clockInTime.split(':').map(Number);
    const isLate = (nowH > targetH) || (nowH === targetH && nowM > targetM);

    const newRecord: AttendanceRecord = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      date: now.toISOString().split('T')[0],
      clockIn: clockInTime, clockOut: null, latitude: lat, longitude: lng,
      status: 'PRESENT', isLate: isLate
    };
    setAttendance(prev => [newRecord, ...prev]);
    await supabase.from('attendance').insert([{
      id: newRecord.id, user_id: newRecord.userId, date: newRecord.date,
      clock_in: newRecord.clockIn, status: newRecord.status, is_late: newRecord.isLate,
      latitude: newRecord.latitude, longitude: newRecord.longitude
    }]);
  };

  const handleClockOut = async () => {
    if (!currentUser) return;
    const todayStr = new Date().toISOString().split('T')[0];
    const nowTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });
    setAttendance(prev => prev.map(a => 
      (a.userId === currentUser.id && a.date === todayStr) ? { ...a, clockOut: nowTime } : a
    ));
    await supabase.from('attendance').update({ clock_out: nowTime }).match({ user_id: currentUser.id, date: todayStr });
  };

  const handleSubmitLeave = async (date: string, reason: string, photo?: string) => {
    if (!currentUser) return;
    const leaveId = Math.random().toString(36).substr(2, 9);
    const newLeave: LeaveRequest = { id: leaveId, userId: currentUser.id, date, reason, status: 'PENDING', evidencePhoto: photo };
    setLeaveRequests(prev => [newLeave, ...prev]);
    await supabase.from('leave_requests').insert([{ id: newLeave.id, user_id: newLeave.userId, date: newLeave.date, reason: newLeave.reason, status: 'PENDING', evidence_photo: newLeave.evidencePhoto }]);
    setAttendance(prev => [{ id: `v-${leaveId}`, userId: currentUser.id, date, clockIn: null, clockOut: null, latitude: 0, longitude: 0, status: 'LEAVE_PENDING', leaveRequestId: leaveId }, ...prev]);
    alert('Izin terkirim.');
  };

  const handleApproveLeave = async (leaveId: string, status: 'APPROVED' | 'REJECTED') => {
    setLeaveRequests(prev => prev.map(l => l.id === leaveId ? { ...l, status } : l));
    await supabase.from('leave_requests').update({ status }).eq('id', leaveId);
    const newStatus = status === 'APPROVED' ? 'LEAVE' : 'ABSENT';
    setAttendance(prev => prev.map(a => a.leaveRequestId === leaveId ? { ...a, status: newStatus } : a));
    await supabase.from('attendance').update({ status: newStatus }).eq('leave_request_id', leaveId);
  };

  const handleUpdateConfig = async (config: OutletConfig) => {
    setOutletConfig(config);
    await supabase.from('config').upsert([{ id: 1, latitude: config.latitude, longitude: config.longitude, radius: config.radius, clock_in_time: config.clockInTime, clock_out_time: config.clockOutTime }]);
  };

  const handleUpdateAdjustment = async (userId: string, field: 'bonus' | 'deduction', value: number) => {
    const updated = { ...(payrollAdjustments[userId] || { bonus: 0, deduction: 0 }), [field]: value };
    setPayrollAdjustments(prev => ({ ...prev, [userId]: updated }));
    await supabase.from('payroll_adjustments').upsert({ user_id: userId, bonus: updated.bonus, deduction: updated.deduction }, { onConflict: 'user_id' });
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-[40px] shadow-2xl p-10 md:p-12 border border-slate-100">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-indigo-100"><span className="text-4xl text-white">🧺</span></div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DamDam Laundry</h1>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input type="text" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Username" required />
            <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="w-full p-4 border border-slate-200 rounded-2xl outline-none font-bold focus:border-indigo-600 transition-colors" placeholder="Password" required />
            {loginError && <p className="text-red-500 text-[10px] font-black uppercase text-center">{loginError}</p>}
            <button type="submit" disabled={isSyncing} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-xl shadow-indigo-100 uppercase tracking-widest active:scale-95 transition-all">MASUK</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} activeMenu={activeMenu} setActiveMenu={setActiveMenu}>
      {currentUser.role === UserRole.EMPLOYEE ? (
        <EmployeeDashboard user={currentUser} outletConfig={outletConfig} attendance={attendance} leaveRequests={leaveRequests} onClockIn={handleClockIn} onClockOut={handleClockOut} onSubmitLeave={handleSubmitLeave} payrollAdjustments={payrollAdjustments[currentUser.id] || { bonus: 0, deduction: 0 }} />
      ) : (
        <OwnerDashboard 
          activeMenu={activeMenu as any} 
          employees={users} 
          attendance={attendance} 
          leaveRequests={leaveRequests} 
          outletConfig={outletConfig} 
          onApproveLeave={handleApproveLeave} 
          onUpdateConfig={handleUpdateConfig} 
          onAddEmployee={handleAddEmployee} 
          onEditEmployee={handleEditEmployee} 
          onDeleteEmployee={handleDeleteEmployee} 
          payrollAdjustments={payrollAdjustments} 
          onUpdateAdjustment={handleUpdateAdjustment}
          onUpdateKasbon={handleUpdateKasbon} // Implementasi prop baru
          onRefreshData={() => fetchData(false)} 
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig } from '../types';
import { getCurrentPosition, calculateDistance } from '../services/locationService';
import { FREE_LEAVE_QUOTA } from '../constants';
import { calculateWeeklyPayroll } from '../services/payrollService';

interface EmployeeDashboardProps {
  user: User;
  outletConfig: OutletConfig;
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onClockIn: (lat: number, lng: number) => void;
  onClockOut: () => void;
  onSubmitLeave: (date: string, reason: string, photo?: string) => void;
  payrollAdjustments: { bonus: number, deduction: number };
}

const EmployeeDashboard: React.FC<EmployeeDashboardProps> = ({
  user,
  outletConfig,
  attendance,
  leaveRequests,
  onClockIn,
  onClockOut,
  onSubmitLeave,
  payrollAdjustments
}) => {
  const [loadingLoc, setLoadingLoc] = useState(false);
  const [errorLoc, setErrorLoc] = useState<string | null>(null);
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveReason, setLeaveReason] = useState('');
  const [evidencePhoto, setEvidencePhoto] = useState<string | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [slipStartDate, setSlipStartDate] = useState('');
  const [slipEndDate, setSlipEndDate] = useState('');

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setSlipStartDate(start.toISOString().split('T')[0]);
    setSlipEndDate(end.toISOString().split('T')[0]);
  }, []);

  const todayStr = new Date().toISOString().split('T')[0];
  const todayRecord = attendance.find(r => r.date === todayStr && r.userId === user.id);

  const now = new Date();
  const currentMonth = now.getMonth();
  const currentYear = now.getFullYear();

  const monthRecords = attendance.filter(a => 
    a.userId === user.id && 
    new Date(a.date).getMonth() === currentMonth &&
    new Date(a.date).getFullYear() === currentYear
  );

  const usedQuota = monthRecords.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT').length;
  const sisaLibur = Math.max(0, FREE_LEAVE_QUOTA - usedQuota);
  const onTimeCount = monthRecords.filter(a => a.status === 'PRESENT' && !a.isLate).length;
  const lateCount = monthRecords.filter(a => a.status === 'PRESENT' && a.isLate).length;

  const weekStart = new Date(slipStartDate || new Date());
  const weekEnd = new Date(slipEndDate || new Date());
  const payrollSummary = calculateWeeklyPayroll(
    user, 
    attendance.filter(a => a.userId === user.id), 
    monthRecords, 
    weekStart, 
    weekEnd, 
    payrollAdjustments.bonus, 
    payrollAdjustments.deduction
  );

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setEvidencePhoto(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleClockInAction = async () => {
    setLoadingLoc(true);
    setErrorLoc(null);
    try {
      const pos = await getCurrentPosition();
      const dist = calculateDistance(
        pos.coords.latitude,
        pos.coords.longitude,
        outletConfig.latitude,
        outletConfig.longitude
      );
      const allowedRadius = outletConfig.radius || 100;
      if (dist <= allowedRadius) {
        onClockIn(pos.coords.latitude, pos.coords.longitude);
      } else {
        setErrorLoc(`Lokasi Terlalu Jauh: Anda berjarak ${Math.round(dist)}m. Batas radius: ${allowedRadius}m.`);
      }
    } catch (err) {
      setErrorLoc("GPS Error: Gagal mendapatkan lokasi.");
    } finally {
      setLoadingLoc(false);
    }
  };

  const handleDownloadSlip = () => {
    if (!slipStartDate || !slipEndDate) return alert("Pilih tanggal!");
    const { jsPDF } = (window as any).jspdf;
    const weekStart = new Date(slipStartDate);
    const weekEnd = new Date(slipEndDate);
    const monthStart = new Date(weekEnd.getFullYear(), weekEnd.getMonth(), 1);

    const mRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart && new Date(a.date) <= weekEnd);
    const report = calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), mRecords, weekStart, weekEnd, payrollAdjustments.bonus, payrollAdjustments.deduction);

    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`SLIP GAJI MINGGUAN`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);

    doc.setTextColor(50);
    doc.setFontSize(11);
    doc.text(`Nama Karyawan: ${user.name}`, 14, 45);
    doc.text(`Periode Kerja: ${report.weekStartDate} s/d ${report.weekEndDate}`, 14, 52);
    doc.setFont("helvetica", "bold");
    doc.text(`Total Izin Bulan Ini: ${report.monthlyLeaveCount} kali`, 14, 59);
    doc.text(`Sisa Kasbon: Rp ${report.totalKasbon.toLocaleString('id-ID')}`, 14, 66);
    doc.setFont("helvetica", "normal");

    const deductionLabel = user.uangMakan > 0 ? 'Potongan Kehadiran' : 'Potongan Gaji';
    (doc as any).autoTable({
      startY: 75,
      head: [['DESKRIPSI', 'KETERANGAN', 'JUMLAH']],
      body: [
        ['Gaji Kotor Mingguan', report.methodLabel, `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus Mingguan', 'Diberikan Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        [deductionLabel, `${report.totalLeave} Izin Minggu Ini`, `Rp ${(report.deductions - report.manualDeduction).toLocaleString('id-ID')}`],
        ['Potongan Kasbon/Lainnya', 'Manual/Cicilan', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      styles: { fontSize: 9 }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text("TOTAL DITERIMA: Rp " + report.netSalary.toLocaleString('id-ID'), 14, finalY);

    doc.save(`slip_damdam_${user.username}_${report.weekEndDate}.pdf`);
  };

  const history = attendance.filter(a => a.userId === user.id).sort((a,b) => b.date.localeCompare(a.date));

  return (
    <div className="space-y-6 md:space-y-8">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-lg">📅</div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Jatah Izin</p>
            <p className={`text-lg font-black ${sisaLibur > 0 ? 'text-green-600' : 'text-red-500'}`}>{sisaLibur} / {FREE_LEAVE_QUOTA}x</p>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-10 h-10 bg-green-50 text-green-600 rounded-xl flex items-center justify-center text-lg">✅</div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Tepat Waktu</p>
            <p className="text-lg font-black text-slate-900">{onTimeCount} Hari</p>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-10 h-10 bg-amber-50 text-amber-600 rounded-xl flex items-center justify-center text-lg">⚠️</div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Terlambat</p>
            <p className="text-lg font-black text-slate-900">{lateCount} Hari</p>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 shadow-sm flex items-center space-x-4">
          <div className="w-10 h-10 bg-red-50 text-red-600 rounded-xl flex items-center justify-center text-lg">💸</div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Sisa Kasbon</p>
            <p className="text-lg font-black text-red-600">Rp {user.totalKasbon.toLocaleString('id-ID')}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8 items-start">
        <div className="lg:col-span-5 space-y-6 md:space-y-8">
          <div className="bg-white p-8 md:p-10 rounded-[32px] md:rounded-[48px] border border-slate-100 shadow-sm text-center">
            <h2 className="text-xl md:text-2xl font-black text-slate-900 mb-6 tracking-tight">Halo, {user.name}</h2>
            <div className="mb-8">
              {!todayRecord?.clockIn && todayRecord?.status !== 'LEAVE' && todayRecord?.status !== 'LEAVE_PENDING' ? (
                <button onClick={handleClockInAction} disabled={loadingLoc} className="w-full py-5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-[20px] font-black text-lg shadow-xl shadow-indigo-100 active:scale-95 transition-all">
                  {loadingLoc ? 'MENGECEK...' : 'ABSEN MASUK'}
                </button>
              ) : todayRecord?.status === 'LEAVE_PENDING' ? (
                <div className="p-6 bg-amber-50 text-amber-700 rounded-2xl font-black border border-amber-100 text-sm">MENUNGGU ACC ⏳</div>
              ) : todayRecord?.status === 'LEAVE' ? (
                <div className="p-6 bg-green-50 text-green-700 rounded-2xl font-black border border-green-100 text-sm">IZIN DISETUJUI ✅</div>
              ) : !todayRecord?.clockOut ? (
                <button onClick={onClockOut} className="w-full py-5 bg-orange-500 hover:bg-orange-600 text-white rounded-[20px] font-black text-lg shadow-xl shadow-orange-100 active:scale-95 transition-all">ABSEN PULANG</button>
              ) : (
                <div className="p-6 bg-indigo-50 text-indigo-700 rounded-2xl font-black border border-indigo-100 text-sm">SELESAI HARI INI ✅</div>
              )}
              {errorLoc && <p className="mt-4 text-[10px] font-black text-red-500 uppercase px-4 leading-relaxed">{errorLoc}</p>}
            </div>

            <div className="bg-indigo-900 text-white p-6 rounded-[24px] text-left mb-6 shadow-xl shadow-indigo-100">
               <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-1">Gaji Bersih Minggu Ini</p>
               <h3 className="text-2xl font-black mb-4">Rp {payrollSummary.netSalary.toLocaleString('id-ID')}</h3>
               <div className="grid grid-cols-2 gap-2 text-[9px] font-black uppercase tracking-widest">
                  <div className="bg-white/10 p-2 rounded-lg">
                    <p className="opacity-60">Bonus</p>
                    <p className="text-green-400">Rp {payrollSummary.bonus.toLocaleString('id-ID')}</p>
                  </div>
                  <div className="bg-white/10 p-2 rounded-lg">
                    <p className="opacity-60">Potongan</p>
                    <p className="text-red-400">Rp {payrollSummary.deductions.toLocaleString('id-ID')}</p>
                  </div>
               </div>
            </div>

            <div className="bg-slate-50 p-6 rounded-[24px] space-y-4">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest text-left">Download Slip Gaji</p>
              <div className="grid grid-cols-2 gap-2">
                <input type="date" value={slipStartDate} onChange={e => setSlipStartDate(e.target.value)} className="p-3 bg-white border border-slate-200 rounded-xl text-[10px] font-bold outline-none" />
                <input type="date" value={slipEndDate} onChange={e => setSlipEndDate(e.target.value)} className="p-3 bg-white border border-slate-200 rounded-xl text-[10px] font-bold outline-none" />
              </div>
              <button onClick={handleDownloadSlip} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg active:scale-95 transition-all">Download Slip PDF</button>
            </div>
          </div>

          <div className="bg-white p-8 md:p-10 rounded-[32px] md:rounded-[48px] border border-slate-100 shadow-sm">
            <h3 className="font-black text-lg text-slate-900 mb-6 uppercase tracking-tight">Ajukan Izin</h3>
            <div className="space-y-4">
              <input 
                type="date" 
                value={leaveDate} 
                onChange={e => setLeaveDate(e.target.value)} 
                className="w-full p-4 bg-white border border-slate-200 rounded-xl font-bold outline-none text-sm" 
              />
              <textarea value={leaveReason} onChange={e => setLeaveReason(e.target.value)} placeholder="Alasan ketidakhadiran..." className="w-full p-4 bg-white border border-slate-200 rounded-xl font-medium min-h-[100px] outline-none text-sm" />
              <div onClick={() => fileInputRef.current?.click()} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:bg-slate-50 transition-all bg-white">
                {evidencePhoto ? <img src={evidencePhoto} className="h-20 object-contain rounded-lg shadow-sm" /> : <div className="text-center text-slate-400 text-[10px] font-black uppercase tracking-widest">📸 Foto Bukti</div>}
              </div>
              <input type="file" ref={fileInputRef} onChange={handlePhotoChange} accept="image/*" className="hidden" />
              <button onClick={() => { if(leaveDate && leaveReason) { onSubmitLeave(leaveDate, leaveReason, evidencePhoto); setLeaveDate(''); setLeaveReason(''); setEvidencePhoto(undefined); } }} className="w-full bg-indigo-600 text-white py-5 rounded-xl font-black shadow-lg uppercase tracking-widest text-[10px]">Kirim Pengajuan</button>
            </div>
          </div>
        </div>

        <div className="lg:col-span-7 bg-white p-6 md:p-10 rounded-[32px] md:rounded-[48px] border border-slate-100 shadow-sm min-h-[400px]">
          <h2 className="text-xl font-black text-slate-900 mb-8 tracking-tight uppercase tracking-tight">Riwayat Absensi</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-left min-w-[350px]">
              <thead>
                <tr className="text-[9px] font-black uppercase text-slate-400 tracking-widest border-b pb-4">
                  <th className="pb-4 px-2">Tanggal</th>
                  <th className="pb-4 px-2">Jam</th>
                  <th className="pb-4 px-2 text-right">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {history.map((item, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/50">
                    <td className="py-4 px-2 font-black text-slate-800 text-sm">{item.date}</td>
                    <td className="py-4 px-2 font-bold text-slate-400 text-xs">{item.clockIn || '--:--'}</td>
                    <td className="py-4 px-2 text-right">
                      <span className={`px-3 py-1.5 rounded-full text-[8px] font-black uppercase ${
                        item.status === 'PRESENT' ? (item.isLate ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700') : 
                        item.status === 'LEAVE_PENDING' ? 'bg-slate-100 text-slate-500' : 
                        item.status === 'LEAVE' ? 'bg-indigo-100 text-indigo-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {item.status === 'PRESENT' ? (item.isLate ? 'Telat' : 'Hadir') : 
                         item.status === 'LEAVE_PENDING' ? 'Menunggu' : 
                         item.status === 'LEAVE' ? 'Izin' : 'Absen'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeDashboard;

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollMethod } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA } from '../constants';

interface OwnerDashboardProps {
  activeMenu: 'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings' | 'kasbon';
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
  payrollAdjustments: Record<string, { bonus: number, deduction: number }>;
  onUpdateAdjustment: (userId: string, field: 'bonus' | 'deduction', value: number) => void;
  onUpdateKasbon: (userId: string, amount: number) => void; // Prop baru
  onRefreshData?: () => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  activeMenu,
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee,
  payrollAdjustments,
  onUpdateAdjustment,
  onUpdateKasbon,
  onRefreshData
}) => {
  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ 
    name: '', username: '', password: '', gapok: 0, uangMakan: 0, deductionRate: 0, payrollMethod: PayrollMethod.DAILY_30, totalKasbon: 0
  });
  const [tempConfig, setTempConfig] = useState<OutletConfig>(outletConfig);
  const [selectedPhoto, setSelectedPhoto] = useState<string | null>(null);

  // State untuk tambah kasbon
  const [kasbonInputs, setKasbonInputs] = useState<Record<string, number>>({});

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  useEffect(() => {
    setTempConfig(outletConfig);
  }, [outletConfig]);

  const getStatsForEmployee = (userId: string) => {
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const monthRecs = attendance.filter(a => 
      a.userId === userId && 
      new Date(a.date).getMonth() === currentMonth &&
      new Date(a.date).getFullYear() === currentYear
    );
    const onTime = monthRecs.filter(a => a.status === 'PRESENT' && !a.isLate).length;
    const late = monthRecs.filter(a => a.status === 'PRESENT' && a.isLate).length;
    const leaves = monthRecs.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT').length;
    const remaining = Math.max(0, FREE_LEAVE_QUOTA - leaves);
    return { onTime, late, leaves, remaining };
  };

  const downloadIndividualSlip = (emp: User) => {
    if (!payStartDate || !payEndDate) return alert("Pilih tanggal!");
    const report = getPayrollForUser(emp);
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();

    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`SLIP GAJI KARYAWAN`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);

    doc.setTextColor(50);
    doc.setFontSize(11);
    doc.text(`Nama: ${emp.name}`, 14, 45);
    doc.text(`Periode: ${report.weekStartDate} s/d ${report.weekEndDate}`, 14, 52);
    doc.setFont("helvetica", "bold");
    doc.text(`Total Izin Bulan Ini: ${report.monthlyLeaveCount} kali`, 14, 59);
    doc.text(`Sisa Kasbon: Rp ${report.totalKasbon.toLocaleString('id-ID')}`, 14, 66);
    doc.setFont("helvetica", "normal");

    const deductionLabel = emp.uangMakan > 0 ? 'Potongan Kehadiran' : 'Potongan Gaji';
    (doc as any).autoTable({
      startY: 75,
      head: [['DESKRIPSI', 'DETAIL', 'JUMLAH']],
      body: [
        ['Gaji Kotor Mingguan', report.methodLabel, `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus Mingguan', 'Ditambahkan Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        [deductionLabel, `${report.totalLeave} Izin Minggu Ini`, `Rp ${(report.deductions - report.manualDeduction).toLocaleString('id-ID')}`],
        ['Potongan Kasbon/Lainnya', 'Sesuai Cicilan', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text("TOTAL DITERIMA: Rp " + report.netSalary.toLocaleString('id-ID'), 14, finalY);

    doc.save(`slip_${emp.username}_${report.weekEndDate}.pdf`);
  };

  const getMergedAttendance = () => {
    const start = new Date(attStartDate);
    const end = new Date(attEndDate);
    const dailyAtt = attendance.filter(a => {
      const d = new Date(a.date);
      return d >= start && d <= end;
    });
    const combined: any[] = [];
    dailyAtt.forEach(a => {
      let statusText = a.status === 'PRESENT' ? (a.isLate ? 'TERLAMBAT' : 'HADIR') : 
                      a.status === 'LEAVE_PENDING' ? 'MENUNGGU' : 
                      a.status === 'LEAVE' ? 'IZIN' : 'ABSEN';
      combined.push({ ...a, statusText });
    });
    return combined.sort((a, b) => b.date.localeCompare(a.date));
  };

  const getPayrollForUser = (user: User) => {
    const start = new Date(payStartDate || new Date());
    const end = new Date(payEndDate || new Date());
    const monthStart = new Date(end.getFullYear(), end.getMonth(), 1);
    const monthRecords = attendance.filter(a => a.userId === user.id && new Date(a.date) >= monthStart && new Date(a.date) <= end);
    const adj = payrollAdjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, attendance.filter(a => a.userId === user.id), monthRecords, start, end, adj.bonus, adj.deduction);
  };

  const handlePayKasbon = (userId: string) => {
    const adj = payrollAdjustments[userId];
    if (adj && adj.deduction > 0) {
      if (confirm(`Potong saldo kasbon karyawan sebesar Rp ${adj.deduction.toLocaleString('id-ID')}?`)) {
        onUpdateKasbon(userId, -adj.deduction);
        // Reset manual deduction after payment if desired, or leave it to show in slip
        alert('Kasbon berhasil dibayarkan dari gaji!');
      }
    } else {
      alert('Masukkan nominal potongan kasbon terlebih dahulu di kolom Potongan Lainnya.');
    }
  };

  // Add missing exportAttendanceToPDF function to fix line 333 error
  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const data = getMergedAttendance();

    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry - Laporan Absensi", 105, 20, { align: 'center' });

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`Periode: ${attStartDate} s/d ${attEndDate}`, 105, 28, { align: 'center' });

    (doc as any).autoTable({
      startY: 35,
      head: [['KARYAWAN', 'TANGGAL', 'STATUS']],
      body: data.map(item => [
        employees.find(e => e.id === item.userId)?.name || 'Unknown',
        item.date,
        item.statusText
      ]),
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] }
    });

    doc.save(`laporan_absensi_${attStartDate}_${attEndDate}.pdf`);
  };

  // Add missing handleSaveConfig function to fix line 478 error
  const handleSaveConfig = () => {
    onUpdateConfig(tempConfig);
    alert('Konfigurasi berhasil disimpan!');
  };

  const pendingLeaves = leaveRequests.filter(l => l.status === 'PENDING');

  return (
    <div className="bg-white rounded-[40px] lg:rounded-[56px] border border-slate-100 shadow-sm p-8 lg:p-14 min-h-[600px]">
      {activeMenu === 'dashboard' && (
        <div className="space-y-10">
          <div className="flex justify-between items-center">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Persetujuan Izin</h2>
            <button 
              onClick={onRefreshData}
              className="px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2"
            >
              🔄 Segarkan Data
            </button>
          </div>

          <div className="grid gap-6">
            {pendingLeaves.map(l => {
                const stats = getStatsForEmployee(l.userId);
                return (
                  <div key={l.id} className="p-8 bg-slate-50 rounded-[32px] border border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 group hover:bg-white hover:shadow-xl hover:shadow-slate-100 transition-all duration-300">
                    <div className="flex-1">
                      <div className="flex items-center space-x-3 mb-3">
                        <p className="font-black text-slate-900 text-xl">{employees.find(e => e.id === l.userId)?.name}</p>
                        <span className={`text-[9px] px-3 py-1.5 rounded-full font-black uppercase ${stats.remaining > 0 ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                            Sisa Izin: {stats.remaining}x
                        </span>
                      </div>
                      <p className="text-sm text-slate-500 font-medium mb-5">{l.date} — "{l.reason}"</p>
                      {l.evidencePhoto && (
                        <button onClick={() => setSelectedPhoto(l.evidencePhoto!)} className="text-[10px] font-black text-indigo-600 uppercase tracking-widest hover:text-indigo-800 flex items-center gap-2">
                          📸 Lihat Lampiran Foto
                        </button>
                      )}
                    </div>
                    <div className="flex w-full sm:w-auto gap-3">
                      <button onClick={() => onApproveLeave(l.id, 'APPROVED')} className="flex-1 sm:flex-none bg-indigo-600 text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">Setuju</button>
                      <button onClick={() => onApproveLeave(l.id, 'REJECTED')} className="flex-1 sm:flex-none bg-red-50 text-red-500 px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest border border-red-100 hover:bg-red-500 hover:text-white transition-all">Tolak</button>
                    </div>
                  </div>
                );
            })}
            {pendingLeaves.length === 0 && (
              <div className="text-center py-32 space-y-4">
                <div className="text-4xl opacity-20">📭</div>
                <p className="text-slate-400 font-bold text-sm">Tidak ada antrean pengajuan izin saat ini.</p>
                <button onClick={onRefreshData} className="text-[10px] font-black text-indigo-600 uppercase underline">Coba Cek Lagi</button>
              </div>
            )}
          </div>
        </div>
      )}

      {activeMenu === 'employees' && (
        <div className="space-y-10">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Manajemen Staf</h2>
            <button onClick={() => { setEditingEmp(null); setEmpForm({ name: '', username: '', password: '', gapok: 0, uangMakan: 0, deductionRate: 0, payrollMethod: PayrollMethod.DAILY_30, totalKasbon: 0 }); setShowEmpModal(true); }} className="w-full sm:w-auto bg-slate-900 text-white px-10 py-5 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl hover:bg-indigo-600 active:scale-95 transition-all">+ Tambah Staf Baru</button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
            {employees.filter(e => e.role === UserRole.EMPLOYEE).map(e => {
              const stats = getStatsForEmployee(e.id);
              return (
                <div key={e.id} className="p-8 bg-white border border-slate-100 rounded-[32px] shadow-sm hover:shadow-xl hover:shadow-slate-100 transition-all duration-300 space-y-6">
                  <div className="flex justify-between items-start">
                    <h4 className="text-xl font-black text-slate-900">{e.name}</h4>
                    <div className="flex space-x-3">
                      <button onClick={() => { setEditingEmp(e); setEmpForm(e); setShowEmpModal(true); }} className="text-indigo-600 font-black text-[10px] uppercase tracking-widest hover:underline">Edit</button>
                      <button onClick={() => onDeleteEmployee(e.id)} className="text-red-500 font-black text-[10px] uppercase tracking-widest hover:underline">Hapus</button>
                    </div>
                  </div>
                  <div className="grid grid-cols-3 gap-3 text-center">
                    <div className="bg-green-50 p-4 rounded-2xl">
                      <p className="text-[9px] font-black text-green-600 uppercase mb-1">Hadir</p>
                      <p className="text-lg font-black text-slate-900">{stats.onTime}</p>
                    </div>
                    <div className="bg-amber-50 p-4 rounded-2xl">
                      <p className="text-[9px] font-black text-amber-600 uppercase mb-1">Telat</p>
                      <p className="text-lg font-black text-slate-900">{stats.late}</p>
                    </div>
                    <div className="bg-indigo-50 p-4 rounded-2xl">
                      <p className="text-[9px] font-black text-indigo-600 uppercase mb-1">Izin</p>
                      <p className="text-lg font-black text-slate-900">{stats.leaves}</p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {activeMenu === 'kasbon' && (
        <div className="space-y-10">
          <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Manajemen Kasbon</h2>
          <div className="grid gap-6">
            {employees.filter(e => e.role === UserRole.EMPLOYEE).map(emp => (
              <div key={emp.id} className="p-8 bg-slate-50 rounded-[32px] border border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-8">
                <div className="flex-1">
                  <h4 className="text-xl font-black text-slate-900 mb-1">{emp.name}</h4>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Saldo Kasbon Saat Ini</p>
                  <p className="text-2xl font-black text-red-600 mt-2">Rp {emp.totalKasbon.toLocaleString('id-ID')}</p>
                </div>
                <div className="flex flex-col sm:flex-row items-center gap-4 w-full sm:w-auto">
                  <div className="relative w-full sm:w-48">
                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-xs">Rp</span>
                    <input 
                      type="number" 
                      placeholder="Nominal..." 
                      value={kasbonInputs[emp.id] || ''} 
                      onChange={e => setKasbonInputs({...kasbonInputs, [emp.id]: parseFloat(e.target.value) || 0})}
                      className="w-full pl-10 pr-4 py-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none focus:border-indigo-600" 
                    />
                  </div>
                  <button 
                    onClick={() => {
                      const amt = kasbonInputs[emp.id] || 0;
                      if(amt > 0) {
                        onUpdateKasbon(emp.id, amt);
