import { User, AttendanceRecord, PayrollReport, PayrollMethod } from '../types';
import { FREE_LEAVE_QUOTA, DAYS_IN_MONTH } from '../constants';

/**
 * Helper to format date as YYYY-MM-DD in local time
 */
const toLocalDateString = (date: Date): string => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

/**
 * Menghitung payroll mingguan dengan mempertimbangkan:
 * 1. Kebijakan khusus Mba Dwi & Bu Mega.
 * 2. Kuota izin bulanan (reset setiap tanggal 1).
 * 3. Potongan kasbon & bonus manual.
 */
export const calculateWeeklyPayroll = (
  user: User,
  allUserRecords: AttendanceRecord[], 
  recordsInPayrollMonth: AttendanceRecord[], 
  weekStart: Date,
  weekEnd: Date,
  bonus: number = 0,
  manualDeduction: number = 0
): PayrollReport => {
  const usernameLower = user.username.toLowerCase();
  const isDwi = usernameLower.includes('dwi');
  const isMega = usernameLower.includes('mega');
  const isDaily30 = user.payrollMethod === PayrollMethod.DAILY_30;

  let weeklyBase = 0;
  let methodLabel = isDaily30 ? 'Harian (Bagi 30)' : 'Mingguan (Bagi 4)';
  let dailyRateForDeduction = 0;

  if (isDwi) {
    weeklyBase = 515000;
    dailyRateForDeduction = 20000; 
  } else if (isMega) {
    weeklyBase = user.gapok / 4;
    dailyRateForDeduction = 55000;
  } else {
    const dailyGapok = user.gapok / DAYS_IN_MONTH;
    const dailyUangMakan = user.uangMakan / DAYS_IN_MONTH;
    dailyRateForDeduction = user.deductionRate || (dailyGapok + dailyUangMakan);

    if (isDaily30) {
      weeklyBase = (dailyGapok + dailyUangMakan) * 7;
    } else {
      weeklyBase = (user.gapok + user.uangMakan) / 4;
    }
  }

  const weekStartStr = toLocalDateString(weekStart);
  const weekEndStr = toLocalDateString(weekEnd);

  // Deduplicate records by date to ensure one day = one calculation
  // Gabungkan semua records yang relevan (semua records user) untuk menghitung kuota bulanan dengan benar
  const dailyRecordsMap = new Map<string, AttendanceRecord>();
  allUserRecords.forEach(record => {
    const existing = dailyRecordsMap.get(record.date);
    if (!existing) {
      dailyRecordsMap.set(record.date, record);
    } else {
      if (record.status === 'LEAVE' || record.status === 'LEAVE_PENDING') {
        dailyRecordsMap.set(record.date, record);
      } else if (record.status === 'PRESENT' && existing.status === 'ABSENT') {
        dailyRecordsMap.set(record.date, record);
      }
    }
  });

  let monthlyAbsentCounter = 0;
  let totalDeductionsThisWeek = 0;
  let excessLeaveCountThisWeek = 0;
  let weekPresent = 0;
  let weekOnTime = 0;
  let weekLate = 0;
  let weekLeave = 0;

  // Jalankan perhitungan mulai dari weekStart agar "kemarin" yang berada di beda bulan tetap terhitung
  const tempDate = new Date(weekStart);
  while (tempDate <= weekEnd) {
    const dateStr = toLocalDateString(tempDate);

    // Untuk akumulasi kuota bulanan, kita harus hitung mulai dari tanggal 1 di bulan tempDate
    const startOfMonth = new Date(tempDate.getFullYear(), tempDate.getMonth(), 1);
    let currentMonthQuotaCounter = 0;

    // Sub-loop untuk menghitung jatah izin bulanan hingga tanggal berjalan (dateStr)
    const quotaPtr = new Date(startOfMonth);
    while (quotaPtr <= tempDate) {
      const qDateStr = toLocalDateString(quotaPtr);
      const qRec = dailyRecordsMap.get(qDateStr);
      if (qRec?.status === 'LEAVE' || qRec?.status === 'ABSENT' || qRec?.status === 'LEAVE_PENDING') {
        currentMonthQuotaCounter++;
      }
      quotaPtr.setDate(quotaPtr.getDate() + 1);
    }

    const record = dailyRecordsMap.get(dateStr);
    const isInCurrentWeek = dateStr >= weekStartStr && dateStr <= weekEndStr;

    const isActuallyAbsent = record?.status === 'ABSENT';
    const isApprovedLeave = record?.status === 'LEAVE';
    const isPendingLeave = record?.status === 'LEAVE_PENDING';

    if (isActuallyAbsent || isApprovedLeave || isPendingLeave) {
      // monthlyAbsentCounter di laporan mingguan biasanya menunjukkan akumulasi bulan berjalan saat weekEnd
      // Tapi kita gunakan currentMonthQuotaCounter untuk logika potongan per hari

      if (isInCurrentWeek) {
        weekLeave++;

        // Deduction logic only for finalized statuses
        if (isActuallyAbsent || isApprovedLeave) {
          if (isDwi) {
            if (currentMonthQuotaCounter <= 3) {
              totalDeductionsThisWeek += 20000;
            } else {
              totalDeductionsThisWeek += 70000;
              excessLeaveCountThisWeek++;
            }
          } else if (isMega) {
            if (currentMonthQuotaCounter > 3) {
              totalDeductionsThisWeek += 55000;
              excessLeaveCountThisWeek++;
            }
          } else {
            if (currentMonthQuotaCounter > FREE_LEAVE_QUOTA) {
              totalDeductionsThisWeek += dailyRateForDeduction;
              excessLeaveCountThisWeek++;
            }
          }
        }
      }

      // Update monthly counter untuk report (berdasarkan bulan akhir minggu ini)
      if (tempDate.getMonth() === weekEnd.getMonth()) {
        monthlyAbsentCounter = currentMonthQuotaCounter;
      }
    } else if (record?.status === 'PRESENT' && isInCurrentWeek) {
      weekPresent++;
      if (record.isLate) weekLate++;
      else weekOnTime++;
    }

    tempDate.setDate(tempDate.getDate() + 1);
  }

  const totalDeductions = totalDeductionsThisWeek + manualDeduction;
  const netSalary = Math.max(0, weeklyBase + bonus - totalDeductions);

  return {
    userId: user.id,
    userName: user.name,
    weekStartDate: weekStartStr,
    weekEndDate: weekEndStr,
    totalPresent: weekPresent,
    totalOnTime: weekOnTime,
    totalLate: weekLate,
    totalLeave: weekLeave,
    monthlyLeaveCount: monthlyAbsentCounter,
    excessLeaveCount: excessLeaveCountThisWeek,
    grossSalary: weeklyBase,
    bonus,
    manualDeduction,
    deductions: totalDeductions,
    netSalary: netSalary,
    dailyRate: dailyRateForDeduction,
    methodLabel,
    totalKasbon: user.totalKasbon
  };
};

import React, { useState, useEffect } from 'react';
import { User, AttendanceRecord, LeaveRequest, OutletConfig, UserRole, PayrollMethod } from '../types';
import { calculateWeeklyPayroll } from '../services/payrollService';
import { FREE_LEAVE_QUOTA } from '../constants';
import { getCurrentPosition } from '../services/locationService';

interface OwnerDashboardProps {
  activeMenu: 'dashboard' | 'employees' | 'attendance' | 'payroll' | 'settings' | 'kasbon';
  employees: User[];
  attendance: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  outletConfig: OutletConfig;
  onUpdateConfig: (config: OutletConfig) => void;
  onApproveLeave: (leaveId: string, status: 'APPROVED' | 'REJECTED') => void;
  onAddEmployee: (user: Partial<User>) => void;
  onEditEmployee: (user: User) => void;
  onDeleteEmployee: (userId: string) => void;
  payrollAdjustments: Record<string, { bonus: number, deduction: number }>;
  onUpdateAdjustment: (userId: string, field: 'bonus' | 'deduction', value: number) => void;
  onUpdateKasbon: (userId: string, amount: number) => void;
  onRefreshData?: () => void;
}

const OwnerDashboard: React.FC<OwnerDashboardProps> = ({
  activeMenu,
  employees,
  attendance,
  leaveRequests,
  outletConfig,
  onUpdateConfig,
  onApproveLeave,
  onAddEmployee,
  onEditEmployee,
  onDeleteEmployee,
  payrollAdjustments,
  onUpdateAdjustment,
  onUpdateKasbon,
  onRefreshData
}) => {
  const [attStartDate, setAttStartDate] = useState(new Date().toISOString().split('T')[0]);
  const [attEndDate, setAttEndDate] = useState(new Date().toISOString().split('T')[0]);
  const [payStartDate, setPayStartDate] = useState('');
  const [payEndDate, setPayEndDate] = useState('');
  const [showEmpModal, setShowEmpModal] = useState(false);
  const [editingEmp, setEditingEmp] = useState<User | null>(null);
  const [empForm, setEmpForm] = useState<Partial<User>>({ 
    name: '', username: '', password: '', gapok: 0, uangMakan: 0, deductionRate: 0, payrollMethod: PayrollMethod.DAILY_30, totalKasbon: 0
  });
  const [tempConfig, setTempConfig] = useState<OutletConfig>(outletConfig);
  const [selectedPhoto, setSelectedPhoto] = useState<string | null>(null);
  const [kasbonInputs, setKasbonInputs] = useState<Record<string, number>>({});
  const [isGettingLocation, setIsGettingLocation] = useState(false);

  useEffect(() => {
    const today = new Date();
    const day = today.getDay(); 
    const diffToThursday = (day <= 4) ? (4 - day) : (4 - day + 7);
    const end = new Date(today);
    end.setDate(today.getDate() + diffToThursday);
    const start = new Date(end);
    start.setDate(end.getDate() - 6);
    setPayStartDate(start.toISOString().split('T')[0]);
    setPayEndDate(end.toISOString().split('T')[0]);
  }, []);

  useEffect(() => {
    setTempConfig(outletConfig);
  }, [outletConfig]);

  const handleGetCurrentLocation = async () => {
    setIsGettingLocation(true);
    try {
      const pos = await getCurrentPosition();
      setTempConfig({
        ...tempConfig,
        latitude: pos.coords.latitude,
        longitude: pos.coords.longitude
      });
      alert('Koordinat berhasil diambil dari lokasi Anda saat ini!');
    } catch (err) {
      alert('Gagal mengambil lokasi. Pastikan GPS aktif.');
    } finally {
      setIsGettingLocation(false);
    }
  };

  const getStatsForEmployee = (userId: string) => {
    const now = new Date();
    const currentMonthStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
    const monthRecs = attendance.filter(a => 
      a.userId === userId && 
      a.date.startsWith(currentMonthStr)
    );

    // Use unique dates to avoid overcounting if duplicates exist in state
    const presentDates = new Set(monthRecs.filter(a => a.status === 'PRESENT' && !a.isLate).map(a => a.date));
    const lateDates = new Set(monthRecs.filter(a => a.status === 'PRESENT' && a.isLate).map(a => a.date));
    const leaveDates = new Set(monthRecs.filter(a => a.status === 'LEAVE' || a.status === 'ABSENT' || a.status === 'LEAVE_PENDING').map(a => a.date));

    const onTime = presentDates.size;
    const late = lateDates.size;
    const leaves = leaveDates.size;
    const remaining = Math.max(0, FREE_LEAVE_QUOTA - leaves);

    return { onTime, late, leaves, remaining };
  };

  const getPayrollForUser = (user: User) => {
    if (!payStartDate || !payEndDate) return null;

    const start = new Date(payStartDate);
    const end = new Date(payEndDate);

    // Kirim seluruh records user agar service bisa menghitung kuota bulanan dengan akurat
    const userAllRecords = attendance.filter(a => a.userId === user.id);

    const adj = payrollAdjustments[user.id] || { bonus: 0, deduction: 0 };
    return calculateWeeklyPayroll(user, userAllRecords, userAllRecords, start, end, adj.bonus, adj.deduction);
  };

  const downloadIndividualSlip = (emp: User) => {
    const report = getPayrollForUser(emp);
    if (!report) return alert("Pilih tanggal periode terlebih dahulu!");

    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();

    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry", 105, 20, { align: 'center' });

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text(`SLIP GAJI KARYAWAN`, 105, 28, { align: 'center' });
    doc.line(14, 35, 196, 35);

    doc.setTextColor(50);
    doc.setFontSize(11);
    doc.text(`Nama: ${emp.name}`, 14, 45);
    doc.text(`Periode: ${report.weekStartDate} s/d ${report.weekEndDate}`, 14, 52);
    doc.setFont("helvetica", "bold");
    doc.text(`Akumulasi Izin Bulan Ini: ${report.monthlyLeaveCount} kali`, 14, 59);
    doc.text(`Sisa Kasbon: Rp ${report.totalKasbon.toLocaleString('id-ID')}`, 14, 66);
    doc.setFont("helvetica", "normal");

    const deductionLabel = emp.uangMakan > 0 ? 'Potongan Kehadiran' : 'Potongan Gaji';
    (doc as any).autoTable({
      startY: 75,
      head: [['DESKRIPSI', 'DETAIL', 'JUMLAH']],
      body: [
        ['Gaji Kotor Mingguan', report.methodLabel, `Rp ${report.grossSalary.toLocaleString('id-ID')}`],
        ['Bonus Mingguan', 'Ditambahkan Owner', `Rp ${report.bonus.toLocaleString('id-ID')}`],
        [deductionLabel, `${report.totalLeave} Izin Minggu Ini`, `Rp ${(report.deductions - report.manualDeduction).toLocaleString('id-ID')}`],
        ['Potongan Kasbon / Lainnya', 'Dipotong dari Gaji', `Rp ${report.manualDeduction.toLocaleString('id-ID')}`],
      ],
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text("TOTAL DITERIMA: Rp " + report.netSalary.toLocaleString('id-ID'), 14, finalY);

    doc.save(`slip_${emp.username}_${report.weekEndDate}.pdf`);
  };

  const getMergedAttendance = () => {
    const dailyAtt = attendance.filter(a => a.date >= attStartDate && a.date <= attEndDate);
    const combinedMap = new Map<string, any>();

    dailyAtt.forEach(a => {
      const key = `${a.userId}-${a.date}`;
      let statusText = a.status === 'PRESENT' ? (a.isLate ? 'TERLAMBAT' : 'HADIR') : 
                      a.status === 'LEAVE_PENDING' ? 'MENUNGGU' : 
                      a.status === 'LEAVE' ? 'IZIN' : 'ABSEN';

      // If duplicate records exist for the same user and date, prioritize leave/present over absent
      const existing = combinedMap.get(key);
      if (!existing || a.status !== 'ABSENT') {
        combinedMap.set(key, { ...a, statusText });
      }
    });

    return Array.from(combinedMap.values()).sort((a, b) => b.date.localeCompare(a.date));
  };

  const exportAttendanceToPDF = () => {
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF();
    const data = getMergedAttendance();
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text("DamDam Laundry - Laporan Absensi", 105, 20, { align: 'center' });
    (doc as any).autoTable({
      startY: 35,
      head: [['KARYAWAN', 'TANGGAL', 'STATUS', 'KOORDINAT']],
      body: data.map(item => [
        employees.find(e => e.id === item.userId)?.name || 'Unknown',
        item.date,
        item.statusText,
        item.latitude && item.longitude ? `${item.latitude.toFixed(4)}, ${item.longitude.toFixed(4)}` : '-'
      ]),
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] }
    });
    doc.save(`absensi_${attStartDate}.pdf`);
  };

  const handleSaveConfig = () => {
    onUpdateConfig(tempConfig);
    alert('Konfigurasi berhasil disimpan!');
  };

